export const QUICK_START_DATA: CourseData = {"product_id": "quick-start", "title": "AI Quick Start", "subtitle": "10 Free Prompts That Will Change How You Work", "source": "ai-quick-start-free.pdf", "version": "2.0 — March 2026", "pages": 9, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini", "ChatGPT"], "sections": [{"title": "Welcome", "type": "intro", "content": "These 10 prompts are hand-picked from our full AI Starter Kit (50+ prompts). But they're not just prompts — each one is a mini-system designed to produce results you'd normally pay a consultant for. They cover the areas where AI makes the biggest immediate impact on your work.", "items": []}, {"title": "How to Use", "type": "instructions", "content": "Step-by-step guide for using the prompts.", "items": [{"step": 1, "instruction": "Copy the full prompt — every word matters for the output quality"}, {"step": 2, "instruction": "Replace [bracketed text] with your real, specific details (the more detail, the better the result)"}, {"step": 3, "instruction": "Paste into Claude, Gemini, or ChatGPT"}, {"step": 4, "instruction": "Use the follow-up prompts included with each to go deeper"}]}, {"title": "Pro Tip — Getting Better Results", "type": "tips", "content": "The #1 mistake people make with AI is being vague. Instead of [topic], write the exact topic. Instead of [audience], describe your actual target reader — their age, role, frustration, goal. Think of every [bracket] as a blank on a form: the more precisely you fill it in, the more precisely the AI delivers. Each prompt below includes a 'Why This Works' note explaining the technique behind it, so you learn the skill — not just the prompt.", "items": []}, {"title": "What's Inside", "type": "overview", "content": "10 prompts across 7 categories — each with a follow-up prompt and explanation of why it works.", "items": [{"category": "Productivity", "count": 1}, {"category": "Writing", "count": 2}, {"category": "Business", "count": 2}, {"category": "Marketing", "count": 2}, {"category": "Research", "count": 1}, {"category": "Personal Growth", "count": 1}, {"category": "Advanced", "count": 1}]}, {"title": "The 10 Prompts", "type": "prompts", "content": "10 hand-picked prompts from the full AI Starter Kit — enhanced with follow-ups, technique breakdowns, and real examples.", "items": [{"number": "01", "name": "The Daily Prioritizer", "category": "PRODUCTIVITY", "prompt": "You are my executive productivity coach. I have [X hours] available today and here are all my tasks:\n\n[List every task, including rough time estimates if you have them]\n\nDo the following:\n1. Classify each task using the Eisenhower Matrix (Urgent+Important, Important Not Urgent, Urgent Not Important, Neither)\n2. Build a time-blocked schedule for my day with 15-minute buffer periods between deep work blocks\n3. For each task, note if it can be partially delegated to AI (and suggest the specific AI approach)\n4. Flag my #1 highest-leverage task — the one that moves the needle most — and put it in my peak energy slot\n5. Add a 'parking lot' section for tasks I should defer to tomorrow with reasoning\n\nFormat the schedule as a clean table with columns: Time | Task | Category | Energy Level | AI-Assistable?", "best_on": ["Claude", "ChatGPT"], "tip": "Run this every morning. After a week, ask the AI to analyze your patterns: 'Based on the 5 daily schedules I've given you, what are my recurring time-wasters and how should I restructure my default week?'", "why_it_works": "This prompt uses role assignment ('executive productivity coach'), structured output (Eisenhower Matrix + table format), and constraint-setting (buffer periods, peak energy) — three techniques that force AI out of generic advice mode.", "follow_up": "Now review my completed day: [paste what you actually did]. Compare it to the plan. Where did I lose time? What pattern do you see? Give me one rule I should follow tomorrow."}, {"number": "02", "name": "The Email Rewriter", "category": "WRITING", "prompt": "You are a communications expert who has written for CEOs and diplomats. I need to send an email to [recipient's role] at [company/context] about [specific situation].\n\nHere's my rough draft or key points:\n[Paste your draft OR bullet points of what you want to say]\n\nRewrite this email following these rules:\n- Maximum 120 words (people skim — every word must earn its place)\n- Opening line: reference something specific to the recipient (no 'I hope this finds you well')\n- Body: one clear paragraph with the key point\n- Close: one single, specific ask with a deadline or next step\n- Tone: [direct but warm / authoritative but friendly / casual but professional]\n\nThen provide:\n- Version A: Your best rewrite\n- Version B: A shorter, bolder alternative (under 80 words)\n- Subject line: 3 options ranked by open-rate likelihood", "best_on": ["Claude", "ChatGPT"], "tip": "Always provide your rough draft or bullet points, even if messy. AI rewrites are 10x better than AI writes-from-scratch because it has your real intent and details to work with.", "why_it_works": "Giving the AI two versions to produce (A and B) triggers comparative reasoning — it actively thinks about what to cut and what to keep, producing tighter writing than a single draft would.", "follow_up": "The recipient might push back on [likely objection]. Write a follow-up email for that scenario — same tone, same brevity, but address the objection head-on in the opening line."}, {"number": "03", "name": "The Business Idea Stress Test", "category": "BUSINESS", "prompt": "You are a seasoned venture strategist who has evaluated 500+ business ideas. You are brutally honest but constructive.\n\nMy business idea: [Describe in 2-3 sentences — what it is, who it's for, how it makes money]\n\nConduct a full stress test:\n\n1. VIABILITY SCORE: Rate 1-10 with specific reasoning\n2. TOP 5 RISKS: Ranked by likelihood × impact. For each risk, include one specific way to mitigate it\n3. IDEAL CUSTOMER: Describe them in detail — demographics, psychographics, where they hang out online, what they currently pay for alternatives\n4. COMPETITIVE LANDSCAPE: Name 3 real competitors (or closest alternatives) with their pricing, strengths, and weaknesses\n5. MOAT ANALYSIS: What would make this hard to copy? Rate the defensibility 1-10\n6. THE $100 TEST: Design a specific validation experiment I can run THIS WEEK for under $100 to test demand\n7. VERDICT: One paragraph — would you invest? Why or why not?\n\nDo NOT sugarcoat. I need the truth, not encouragement.", "best_on": ["Claude", "Gemini"], "tip": "After the initial analysis, challenge it: 'Now argue the opposite — why WOULD this succeed despite the risks you identified? What am I not seeing?' This forces balanced analysis.", "why_it_works": "The 'Do NOT sugarcoat' instruction + the specific expert role prevents AI's natural tendency to be encouraging. The numbered structure ensures nothing gets skipped.", "follow_up": "Based on your analysis, if I had to pivot this idea to reduce the top 2 risks while keeping the core value proposition, what would the pivoted version look like? Describe it as a one-paragraph pitch."}, {"number": "04", "name": "The Blog Post Architect", "category": "WRITING", "prompt": "You are a content strategist who has written viral articles for top publications. Your specialty is making complex topics feel simple and actionable.\n\nWrite a 1,000-word blog post:\n- Topic: [your topic]\n- Target reader: [describe them — role, experience level, what they're struggling with]\n- Goal: [what should the reader be able to DO after reading this?]\n\nStructure requirements:\n1. HOOK (first 2 sentences): Start with a surprising stat, a contrarian take, or a relatable frustration. No 'In today's fast-paced world' or 'Have you ever wondered'\n2. THE PROBLEM: One paragraph that makes the reader think 'this person gets me'\n3. 3-5 SUBHEADINGS: Each with a specific, actionable technique (not vague advice). Include at least one real example or mini case study per section\n4. THE SHORTCUT: One section that gives the reader an unexpected quick win they can use immediately\n5. CLOSE: A CTA that connects to [your goal — newsletter signup / product / consultation]\n\nTone: [conversational and confident / authoritative and data-driven / witty and relatable]\n\nBanned phrases: 'game-changer', 'dive in', 'at the end of the day', 'it's important to note', 'in conclusion'", "best_on": ["Claude", "ChatGPT"], "tip": "After getting the draft, use this power move: 'Now read this as a skeptical [target reader]. Highlight every sentence where they'd think \"so what?\" or \"I already knew that\" and replace it with something specific and surprising.'", "why_it_works": "Banning cliches and requiring specific examples forces AI to produce genuinely original content. The 'banned phrases' technique is one of the most underused prompt tricks.", "follow_up": "Extract 5 social media posts from this article — each should stand alone as valuable content. Format: Hook line (under 10 words), 3-4 sentence body, CTA back to the full post."}, {"number": "05", "name": "The Revenue Content Calendar", "category": "MARKETING", "prompt": "You are a social media strategist who has managed accounts that generate 6-figure revenue from organic content alone.\n\nCreate a 30-day content calendar for:\n- Business: [your business and what you sell]\n- Platform: [Instagram / LinkedIn / TikTok / Twitter]\n- Goal: [grow followers / drive sales / build authority / generate leads]\n- Audience: [who they are and what they care about]\n\nFor each day, provide:\n1. Content pillar (from: Educational 40% | Entertaining 30% | Promotional 20% | Community 10%)\n2. Content type (carousel, single image, video, story, text post, reel)\n3. Topic + angle (be specific — not just 'talk about product')\n4. Hook: The exact first line (this determines if people stop scrolling)\n5. CTA: What the viewer should do\n6. Best posting time for [platform]\n\nAlso include:\n- 4 'engagement bait' posts designed to get comments and shares\n- 2 'authority builder' posts that position me as the expert\n- 2 'soft sell' posts that drive purchases without feeling pushy\n- Week-over-week strategy notes: what to analyze and adjust\n\nFormat as a table grouped by week.", "best_on": ["ChatGPT", "Gemini"], "tip": "The most important part is the hooks. After getting the calendar, ask: 'Now rewrite every hook to be more provocative. Use pattern interrupts, curiosity gaps, or contrarian takes. Boring hooks = invisible posts.'", "why_it_works": "Specifying exact percentages for content types (40/30/20/10) gives the AI a framework instead of random content. Adding 'engagement bait' and 'soft sell' categories ensures strategic variety.", "follow_up": "Analyze this calendar. Which 5 posts are most likely to go viral and why? Which 3 are weakest? Replace the weak ones with stronger alternatives."}, {"number": "06", "name": "The Instant Expert Briefing", "category": "RESEARCH", "prompt": "You are a research analyst who briefs executives. Your job is to make me sound like I've been studying [topic] for months — in under 5 minutes of reading.\n\nCreate an executive briefing on: [topic]\n\nStructure:\n1. THE 30-SECOND VERSION: 3 sentences that capture the essence (if I only read this, I'd still sound smart in a meeting)\n2. 5 KEY FACTS: The numbers, dates, and data points that matter most — with context for why each matters\n3. THE KEY PLAYERS: Who are the 3-5 most important people/companies in this space and what are they doing?\n4. CURRENT STATE: What's happening right now (2024-2026) that's changing things?\n5. THE DEBATE: What do experts disagree about? Give both sides in 2-3 sentences each\n6. COMMON MISCONCEPTIONS: 3 things most people get wrong about this topic\n7. CONVERSATION STARTERS: 3 impressive things I could say in a meeting about this topic that would make me sound deeply informed\n8. DEEPER READING: 3 specific, real sources (articles, books, reports) for going deeper\n\nKeep everything concise. I'm prepping fast, not writing a thesis.", "best_on": ["Gemini", "Claude"], "tip": "Use Gemini for this prompt — it has access to current information and can provide more up-to-date facts and sources. Claude is better for the analysis sections.", "why_it_works": "The 'Conversation Starters' section is the secret weapon — it transforms passive knowledge into active talking points. The 'Common Misconceptions' section gives you contrarian edge.", "follow_up": "I'm meeting with [person/audience] about this topic. They likely know [their expertise level]. What are the 3 questions they'll probably ask me, and how should I answer each one?"}, {"number": "07", "name": "The Strategic SWOT System", "category": "BUSINESS", "prompt": "You are a McKinsey-level strategy consultant. Conduct a comprehensive SWOT analysis for:\n\nBusiness/Project: [describe it]\nIndustry: [your industry]\nStage: [startup / growing / established / pivoting]\nTop competitor: [name one if you know one]\n\nFor EACH quadrant, provide:\n- 5+ specific, actionable items (not generic phrases like 'strong brand' — be precise about WHAT is strong and WHY it matters)\n- A confidence rating (High/Medium/Low) for each item\n- One data point or evidence that supports it\n\nThen create:\n1. ATTACK MATRIX: A 2x2 table — rows are Strengths and Weaknesses, columns are Opportunities and Threats. Each cell answers: 'How do I use [row] to address [column]?'\n2. TOP 3 PRIORITIES: Based on this analysis, what are the 3 most important strategic moves in the next 90 days?\n3. EARLY WARNING SIGNALS: 3 things to monitor that would indicate a threat is becoming real\n\nBe specific to MY business — generic strategy advice is worthless.", "best_on": ["Claude", "Gemini"], "tip": "After the initial SWOT, ask: 'Now do a reverse SWOT — analyze my top competitor using the same framework. Where are they weak where I'm strong?' This reveals your competitive advantage.", "why_it_works": "The Attack Matrix is what separates this from basic SWOT — it forces AI to create actionable strategies from the intersection of factors, not just list items in four boxes.", "follow_up": "Turn my top 3 priorities into a 90-day action plan. Break each priority into specific weekly milestones with measurable outcomes."}, {"number": "08", "name": "The Rapid Skill Accelerator", "category": "PERSONAL GROWTH", "prompt": "You are a world-class learning coach who designs accelerated skill acquisition programs. Your philosophy: learn by doing, not by watching.\n\nDesign a 30-day plan to take me from [current level] to [target level] in [skill].\n\nAbout me:\n- Available time: [X minutes per day]\n- Learning style: [hands-on / reading / video / mixed]\n- Why I'm learning this: [your goal — job, project, personal interest]\n\nFor each day, provide:\n1. FOCUS (one specific sub-skill to practice)\n2. DO THIS (a concrete exercise — not 'practice X', but the exact exercise with parameters)\n3. TIME (realistic time estimate)\n4. SUCCESS METRIC (how do I know I did it right?)\n\nAlso include:\n- WEEK 1-4 MILESTONES: What I should be able to demonstrate at each week's end\n- THE 3 PLATEAUS: Where most people get stuck and how to break through\n- TOOLS & RESOURCES: Only free ones. Max 3 — fewer is better\n- THE SHORTCUT: One technique that most tutorials skip that dramatically accelerates learning\n- COMMON MISTAKES: Top 5 mistakes beginners make and how to avoid each one", "best_on": ["Claude", "ChatGPT"], "tip": "At the end of each week, paste your progress back and ask: 'Based on my Week [X] progress, am I on track? Adjust the remaining weeks to address my specific weak spots.'", "why_it_works": "The 'Success Metric' for each day prevents the #1 problem with learning plans: doing the activity without knowing if you're actually improving. Measurable daily feedback accelerates learning 3x.", "follow_up": "I just completed Week 1. Here's what went well: [X]. Here's what I struggled with: [Y]. Adjust Weeks 2-4 to focus more on my weak areas while maintaining momentum on my strengths."}, {"number": "09", "name": "The High-Converting Landing Page", "category": "MARKETING", "prompt": "You are a conversion copywriter who has written landing pages generating $10M+ in revenue. You understand both the psychology of buying and the mechanics of web copy.\n\nWrite complete landing page copy for:\n- Product/Service: [what you're selling]\n- Price: [price point]\n- Target buyer: [who they are, what they're feeling, what they've already tried]\n- Key differentiator: [what makes this different from alternatives]\n\nProvide every section in order:\n1. HERO: Headline (under 10 words, benefit-focused), subheadline (1 sentence that adds specificity), CTA button text (not 'Submit' — something that completes 'I want to...')\n2. PAIN POINTS: 3 frustrations written in the customer's exact words (as if overheard at a coffee shop)\n3. SOLUTION BRIDGE: One paragraph that transitions from pain to your offer\n4. FEATURES → BENEFITS: A table with 5 features, each translated into a specific benefit and the emotional result\n5. SOCIAL PROOF SECTION: Write 3 realistic testimonial templates I can adapt (name, role, specific result, before/after)\n6. OBJECTION HANDLER: FAQ with the 5 most common objections as questions, each answered in 2-3 sentences\n7. URGENCY + FINAL CTA: Closing section with scarcity or urgency element and a CTA that removes risk\n\nWrite for a [sophisticated / general / skeptical] audience. No hype. No 'revolutionary'. Just clear, benefit-driven copy.", "best_on": ["Claude", "ChatGPT"], "tip": "After getting the copy, ask: 'Now read this as a skeptical buyer who has been burned before. Which sections would make them close the tab? Rewrite those sections to address their skepticism directly.'", "why_it_works": "The Features → Benefits → Emotional Result chain is a professional copywriting framework (Feature: what it does → Benefit: why it matters → Emotion: how it feels). Most people only do the first one.", "follow_up": "Write 3 variations of the hero section for A/B testing. Variation A: lead with the biggest pain point. Variation B: lead with the most impressive result. Variation C: lead with social proof."}, {"number": "10", "name": "The MEGA Prompt Framework", "category": "ADVANCED", "prompt": "This isn't a prompt to copy — it's a framework to build ANY prompt. Use these 7 building blocks every time you talk to AI:\n\n[ROLE]: 'You are [specific expert with years of experience and specialty]'\n→ Example: 'You are a SaaS pricing strategist with 15 years of experience in B2B subscription models'\n\n[CONTEXT]: 'Here is the background: [your situation, constraints, what you've already tried]'\n→ Example: 'I run a 10-person design agency. We currently charge hourly but want to switch to project-based pricing'\n\n[TASK]: 'Do the following: [numbered list of specific deliverables]'\n→ Example: '1. Analyze our current pricing model 2. Propose 3 pricing tiers 3. Write the pricing page copy'\n\n[FORMAT]: 'Output as: [table / bullet points / step-by-step / email / report]'\n→ Example: 'Present the 3 tiers as a comparison table with columns for each tier'\n\n[CONSTRAINTS]: 'Rules: [word limits, things to avoid, must-includes]'\n→ Example: 'Keep each tier description under 50 words. Do not use the word \"cheap\" for the lowest tier'\n\n[TONE]: 'Write in a [adjective] voice'\n→ Example: 'Write in a confident, no-nonsense voice — like talking to a smart colleague'\n\n[EXAMPLE]: 'Here's a sample of what good output looks like: [paste an example]'\n→ This is the single most powerful element. Even a rough example dramatically improves output quality.\n\nPRO MOVE: Stack all 7 into one prompt. The more blocks you use, the better your results. Even using just ROLE + TASK + FORMAT puts you ahead of 90% of AI users.", "best_on": ["Claude", "Gemini", "ChatGPT"], "tip": "Build a personal 'prompt template' with your ROLE and CONTEXT pre-filled. Save it in Claude's Projects or Gemini Gems so you never start from scratch. (Our AI Skills Builder course teaches exactly how to set this up.)", "why_it_works": "Each block constrains the AI's output space. Without constraints, AI gives you 'average internet content.' With all 7 blocks, it gives you custom expert output. This is the same framework professional prompt engineers use.", "follow_up": "Take this topic: [your topic]. Build a MEGA prompt using all 7 blocks, then execute it. Show me the prompt you'd build AND the output it produces."}]}, {"title": "Upsell / CTA", "type": "cta", "content": "Loved These Prompts? You've only scratched the surface. The full AI Starter Kit has 50+ prompts across 8 categories — each with the same depth you've seen here, plus 'Best On' tags showing which AI tool works best for each task.", "items": [{"offer": "Get the Complete AI Starter Kit", "price": "$19", "description": "50+ expert prompts | 8 categories | Pro Tips for each | Copy-paste ready", "url": "https://www.kh-academy.com"}, {"offer": "Save 40% with the Ultimate AI Bundle", "price": "$97 for all 4 products", "description": "AI Starter Kit + AI Skills Builder + AI for Small Business + AI Automation Mastery — the complete path from beginner to automated business", "url": "https://www.kh-academy.com"}]}]};

export const STARTER_KIT_DATA: CourseData = {"product_id": "starter-kit", "title": "AI Starter Kit", "subtitle": "50+ Essential Prompts for ChatGPT, Claude & Gemini", "source": "ai-starter-kit.pdf", "version": "2.0 — March 2026", "pages": 25, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["ChatGPT", "Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "Welcome to the AI Starter Kit — your shortcut to getting real results from AI tools. These aren't random prompts copied from the internet. Every prompt in this kit has been tested across ChatGPT, Claude, and Gemini to ensure it actually works.", "items": []}, {"title": "How to Use This Kit", "type": "instructions", "content": "This kit uses a layered prompting methodology: each prompt combines role assignment, structured output formatting, and explicit constraints to produce results that generic AI requests simply cannot match. What makes these prompts different is that they encode expert-level workflows — the kind of structured thinking that consultants, copywriters, and strategists use daily — into repeatable templates you can customize in seconds. Think of each prompt as a mini-framework: swap in your details, follow the pro tips to iterate, and you will consistently get outputs that feel like they came from a specialist, not a chatbot.", "items": [{"step": 1, "title": "Copy & Customize", "instruction": "Copy any prompt exactly as written, then replace the [bracketed text] with your specific details. The brackets show you exactly what to personalize."}, {"step": 2, "title": "Check the 'Best On' Tag", "instruction": "Each prompt includes a 'Best On' tag showing which AI tool gives the best results for that specific task. Start with the recommended tool for optimal output."}, {"step": 3, "title": "Use the Pro Tips", "instruction": "Try the 'Pro Tip' beneath each prompt to get even better outputs. These are power-user techniques that take your results from good to exceptional."}]}, {"title": "What's Inside", "type": "overview", "content": "50+ battle-tested prompts organized into 8 categories. 'Best On' recommendations for ChatGPT, Claude & Gemini. Pro Tips to maximize every prompt's effectiveness. 4 advanced frameworks for power users.", "items": [{"category": "Productivity & Time Management", "count": 8, "pages": "4–6"}, {"category": "Business & Strategy", "count": 8, "pages": "7–9"}, {"category": "Writing & Communication", "count": 8, "pages": "10–12"}, {"category": "Marketing & Social Media", "count": 8, "pages": "13–15"}, {"category": "Research & Analysis", "count": 6, "pages": "16–17"}, {"category": "Learning & Personal Growth", "count": 6, "pages": "18–19"}, {"category": "Coding & Technical", "count": 6, "pages": "20–21"}, {"category": "Bonus: Advanced Frameworks", "count": 4, "pages": "22–23"}]}, {"title": "Category 01: Productivity & Time Management", "type": "prompts", "content": "8 prompts to manage your time, schedule, and decisions.", "items": [{"number": "01", "name": "The Daily Prioritizer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as my personal productivity coach with expertise in time-management frameworks. I have [X hours] available today. Here are my tasks: [list your tasks]. Prioritize them using the Eisenhower Matrix (Urgent/Important quadrants). For each task, estimate the time required and the cognitive load (high-focus vs. low-focus). Flag anything I should delegate or drop entirely, and explain why. Then build me a time-blocked schedule with 15-minute buffer periods between deep work sessions. Place high-focus tasks during my peak energy window at [morning/afternoon]. Do NOT schedule more than 3 deep work blocks in a single day. Output the schedule as a table with columns: Time, Task, Duration, Quadrant, and Energy Level.", "best_on": ["Claude", "Gemini"], "tip": "Run this every morning. Save your task list in a note app so you can paste it instantly.", "why_it_works": "The Eisenhower Matrix forces a binary classification that eliminates the 'everything feels urgent' trap. By combining it with energy-level mapping and buffer periods, this prompt mirrors how executive coaches actually structure client days — matching task difficulty to cognitive capacity rather than just time availability.", "follow_up": "Now review this schedule. Which tasks could be batched together to reduce context-switching? If something unexpected takes an extra 30 minutes, which task gets moved to tomorrow and why?", "pro_tip": "Add your energy profile: 'I'm sharpest from 9-11am and hit a slump at 2pm.' The AI will slot your hardest tasks into peak windows."}, {"number": "02", "name": "The Meeting Summarizer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as an executive assistant who has summarized thousands of meetings. Summarize the following meeting notes into: (1) Key decisions made — list each with who made it and any conditions attached, (2) Action items — format as a table with columns: Action, Owner, Deadline, Priority, (3) Open questions that need follow-up — note who should answer each, (4) Unresolved disagreements or tensions that need attention, (5) A 2-sentence executive summary I can share with stakeholders who were not there. Do NOT add any information that was not in the original notes. If a deadline or owner is unclear, flag it explicitly as 'TBD — needs clarification.' Here are the notes: [paste meeting notes]", "best_on": ["Claude", "Gemini"], "tip": "Record meetings with Otter.ai or your phone, transcribe, then paste here.", "why_it_works": "Structured extraction with explicit field requirements forces the model to parse raw text into discrete, actionable categories rather than producing a vague narrative summary. The 'do not add information' constraint prevents hallucination of details that were never discussed.", "follow_up": "Based on the action items above, draft a brief follow-up email I can send to all attendees within 10 minutes of the meeting ending. Keep it under 150 words.", "pro_tip": "Paste the previous meeting's summary along with the new notes and ask 'What action items from last time are still unresolved?' to create accountability chains."}, {"number": "03", "name": "The Email Drafter", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a professional communications specialist. Write a professional email to [recipient's role] at [company type] requesting [specific outcome]. Tone: direct but warm. Length: under 120 words. Structure: (1) One sentence of relevant context or connection, (2) The core request stated clearly, (3) One sentence addressing why this benefits them, (4) A single, specific call-to-action with a proposed next step (date/time if applicable). End with a single, clear ask — not multiple options. Do NOT use the phrases 'I hope this email finds you well,' 'Just wanted to follow up,' or 'Please do not hesitate to.' Avoid any sentence that starts with 'I just.'", "best_on": ["Claude", "Gemini"], "tip": "Add 'Match this writing style: [paste a previous email you have sent]' for personalization.", "why_it_works": "The word-count constraint and banned-phrase list force concise, original writing. Specifying a single CTA prevents the common AI failure mode of offering multiple options, which paradoxically reduces response rates by creating decision fatigue for the recipient.", "follow_up": "Now write two variations: one if I do not hear back in 3 days (polite nudge), and one if I still do not hear back after 7 days (final follow-up with a deadline).", "pro_tip": "Paste 3-5 of your own sent emails and ask the AI to create a 'personal email style guide' first. Then reference that guide in every future email prompt for consistency."}, {"number": "04", "name": "The Decision Matrix", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a decision-analysis consultant. I need to decide between [Option A] and [Option B]. For each option, analyze: (1) Pros and cons — minimum 5 each, ranked by importance, (2) Short-term impact (next 30 days) vs. long-term impact (next 12 months), (3) Financial implications with estimated costs and potential returns, (4) Risk level (low/medium/high) with a one-sentence justification, (5) Reversibility — how hard is it to undo this choice, (6) What I would regret more if I did not choose it. Present the comparison as a clear table. Then give me your recommendation with three reasons. Finally, tell me the one question I should answer myself before deciding — the question only I can answer. Do NOT hedge with 'it depends' — commit to a recommendation.", "best_on": ["Claude", "Gemini"], "tip": "Add your personal constraints like budget, timeline, or values for a more tailored answer.", "why_it_works": "Forcing the AI to commit to a recommendation (rather than hedging) activates more decisive analytical reasoning. Adding the reversibility dimension and the 'regret test' mirrors how behavioral economists frame decisions, surfacing emotional factors that pure logic misses.", "follow_up": "Now steelman the option you did NOT recommend. What scenario would make it the better choice? What am I missing?", "pro_tip": "For major decisions, run this prompt three times with different 'personas': a risk-averse advisor, an aggressive growth advisor, and a mentor who knows you well. Compare the three outputs."}, {"number": "05", "name": "The Weekly Review", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a personal performance coach. Help me conduct a weekly review using an interactive format. Ask me these questions one at a time, wait for my response, then ask the next: (1) What were my top 3 accomplishments this week — and which one am I proudest of? (2) What did not go as planned, and what was the root cause? (3) What did I learn that I will apply going forward? (4) What are my top 3 priorities for next week, and what does 'done' look like for each? (5) What is one thing I should stop doing or say no to? After all answers, create a structured weekly report with sections: Wins, Lessons, Next Week Priorities (with success criteria), and One Thing to Stop. Format it so I can paste it into a journal or notes app.", "best_on": ["Claude", "Gemini"], "tip": "Schedule this for Friday afternoon. It takes 10 minutes and transforms your planning.", "why_it_works": "The interactive one-at-a-time format prevents surface-level answers by giving each question dedicated attention. Requiring 'root cause' for failures and 'success criteria' for priorities converts vague reflection into specific, actionable self-coaching.", "follow_up": "Compare this week's review to last week's. What patterns do you notice? Am I making progress on the things I said mattered, or am I drifting?", "pro_tip": "Keep a running document of all weekly reviews. After a month, paste all four into the AI and ask for a 'monthly pattern analysis' — you will see trends invisible in any single week."}, {"number": "06", "name": "The SOP Generator", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as an operations manager who specializes in process documentation. Create a detailed Standard Operating Procedure (SOP) for [task/process]. Include: (1) Purpose — why this SOP exists and what outcome it ensures, (2) Scope — who should use it and when, (3) Prerequisites — tools, access, or knowledge needed before starting, (4) Step-by-step instructions with numbered steps — each step should be a single action, not multiple actions combined, (5) Decision points — if/then branches where the process might vary, (6) Common mistakes to avoid with a brief explanation of why each is a problem, (7) Quality checklist to verify completion — 5-8 checkboxes, (8) Estimated total time. Format it so someone with no prior experience could follow it perfectly on their first attempt. Use clear, direct language — no jargon without a definition.", "best_on": ["Claude", "Gemini"], "tip": "Use this to document everything you do repeatedly — then delegate or automate it.", "why_it_works": "Single-action steps and explicit decision branches eliminate ambiguity, the main reason SOPs fail. Adding a purpose section gives context that helps the reader make judgment calls in edge cases the SOP does not cover.", "follow_up": "Now identify which steps in this SOP could be automated or semi-automated with existing tools. For each automatable step, suggest a specific tool and describe the setup.", "pro_tip": "Have someone unfamiliar with the task follow the SOP while you watch. Every place they hesitate reveals a gap in the documentation. Paste their feedback back into the AI for a revision."}, {"number": "07", "name": "The Automation Finder", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a workflow automation specialist who has helped hundreds of small businesses reduce manual work. I spend my work time on these tasks: [list 5-10 regular tasks with approximate weekly time for each]. For each task, tell me: (1) Automation potential — fully automatable, partially automatable, or not automatable, with a one-sentence explanation, (2) Recommended tool — name a specific tool (Zapier, Make, n8n, Apple Shortcuts, scripting, etc.) and describe the exact automation, (3) Estimated setup time vs. ongoing time saved per week, (4) Difficulty to set up (easy/medium/hard) and whether it needs technical skill, (5) Dependencies — what breaks if this automation fails, and how to build in a safety check. Rank all tasks by ROI ratio (weekly time saved divided by setup effort). Do NOT recommend tools that require enterprise pricing — I am a solo operator or small team.", "best_on": ["Gemini", "Claude"], "tip": "Start with the highest-ratio task. One automation can save you 5+ hours per week.", "why_it_works": "Specifying the ROI ratio forces a quantitative comparison rather than vague 'this could help' suggestions. The dependency analysis prevents the common failure of automating something without considering what happens when the automation breaks.", "follow_up": "For the top-ranked automation, give me a step-by-step implementation guide I can follow this afternoon. Include the exact trigger, actions, and a test scenario to verify it works.", "pro_tip": "Once you automate your top 3, paste the remaining manual tasks back and ask 'Now that I have freed up X hours, which of these remaining tasks should I eliminate entirely rather than automate?'"}, {"number": "08", "name": "The Focus Session Designer", "category": "PRODUCTIVITY & TIME MANAGEMENT", "prompt": "Act as a cognitive performance coach who specializes in deep work and flow states. Design a [X]-hour deep work session for me. I need to accomplish: [describe task]. My biggest distraction is [describe]. Create: (1) A 2-minute pre-session ritual to prime my brain for focus — include specific actions, not vague advice, (2) Time blocks within the session with specific micro-goals for each block (what exactly should be completed, not just 'work on X'), (3) Strategic break intervals — specify what to do during breaks (movement, hydration, etc.) and what NOT to do (no phone, no email), (4) An 'if I get stuck' protocol with three escalating strategies, (5) A 3-minute closing ritual to capture progress and set up the next session. Structure this as a timeline I can print or keep on my screen. Assume I work best when [describe your focus style — music/silence, time pressure, etc.].", "best_on": ["Claude", "Gemini"], "tip": "Put your phone in another room and use this plan. You will be amazed at the output.", "why_it_works": "Micro-goals for each block create the 'small wins' dopamine loop that sustains focus. The stuck protocol prevents the most common deep-work failure: hitting a wall and defaulting to distraction instead of using a structured workaround.", "follow_up": "I completed the session. Here is what I accomplished: [describe]. Adjust the plan for tomorrow based on what worked and what did not.", "pro_tip": "Create a 'focus session library' — save your best session designs for different task types (writing, coding, planning) and reuse the structure that consistently produces your best output."}]}, {"title": "Category 02: Business & Strategy", "type": "prompts", "content": "8 prompts for business analysis, strategy, and planning.", "items": [{"number": "09", "name": "The Business Idea Validator", "category": "BUSINESS & STRATEGY", "prompt": "I have a business idea: [describe idea in 2-3 sentences]. Act as a brutally honest venture capitalist who has reviewed over 1,000 pitches. Analyze: (1) The 5 biggest risks of failure — ranked from most to least likely, with a probability estimate for each, (2) The ideal customer avatar — demographics, psychographics, and where to find them, (3) Market size — estimate the TAM, SAM, and SOM with your reasoning, (4) Competitive landscape — name 3 existing competitors, their strengths, and how this idea specifically differs, (5) Critical assumptions — what needs to be true for this to succeed, (6) A minimum viable test I could run this week for under $100 to validate demand — be extremely specific about steps. Do NOT sugarcoat. I need honest, direct feedback. End with a final verdict: invest, pass, or conditional invest (and what condition must be met).", "best_on": ["Claude", "Gemini"], "tip": "Do not defend your idea — let the AI poke holes. Better to find problems now than after investing.", "why_it_works": "The VC persona activates pattern-matching against common startup failure modes. Requiring probability estimates and a final verdict forces the model beyond generic 'pros and cons' into concrete risk assessment, which is more useful for actual decision-making.", "follow_up": "Assume I ran the validation test and got [describe result]. Does this change your assessment? What should my next move be — and what is the one metric I should obsess over for the next 30 days?", "pro_tip": "Run this prompt three times with different VC personas: a conservative investor, an aggressive growth investor, and a domain expert in your industry. The overlap in their concerns reveals your true risks."}, {"number": "10", "name": "The Elevator Pitch Crafter", "category": "BUSINESS & STRATEGY", "prompt": "Act as a pitch coach who has helped founders raise over $50M in funding. Help me create a 30-second elevator pitch for my [business/product/service]. It must cover: what it does, who it is for, why it is different, and a memorable hook. My audience is [describe who you are pitching to]. Create 3 versions: (1) Formal — investor meeting, structured around problem-solution-traction, (2) Casual — networking event, conversational and story-driven, (3) One-liner — when someone asks 'what do you do?' (under 15 words). For each version, highlight the single most compelling data point or proof of traction. Do NOT use buzzwords like 'disruptive,' 'revolutionary,' or 'game-changing.' End each pitch with a question or hook that invites follow-up conversation.", "best_on": ["Claude", "Gemini"], "tip": "Practice the one-liner version until it feels natural. That is your most-used version.", "why_it_works": "Creating three versions at different formality levels forces the model to distill the core value proposition from multiple angles. Banning buzzwords eliminates the generic filler that makes pitches forgettable, while ending with a hook ensures the conversation continues.", "follow_up": "Now act as a skeptical investor hearing each pitch. What is the first question or objection you would have for each version? Write a prepared response for each objection.", "pro_tip": "Record yourself delivering all three versions. The one you stumble on least is the one closest to how you naturally talk — lead with that version and refine the others to match its energy."}, {"number": "11", "name": "The SWOT Analyzer", "category": "BUSINESS & STRATEGY", "prompt": "Act as a senior strategy consultant at a top-tier firm. Conduct a comprehensive SWOT analysis for [business/product/project]. Context about my business: [2-3 sentences about current state, size, market]. For each quadrant (Strengths, Weaknesses, Opportunities, Threats), provide at least 5 specific, actionable items — not vague generalities. Each item must include: the factor itself, why it matters, and one concrete action to take. Then create a 2x2 action matrix: (1) Leverage — use Strengths to capture Opportunities, (2) Defend — use Strengths to counter Threats, (3) Improve — fix Weaknesses to capture Opportunities, (4) Mitigate — fix Weaknesses to avoid Threats. For the action matrix, provide specific next steps with a priority ranking (high/medium/low) and a time horizon (this week, this month, this quarter). Do NOT include generic items like 'strong brand' or 'market competition' unless you explain specifically why they apply here.", "best_on": ["Claude", "Gemini"], "tip": "Share this with your team and ask what they would add. AI gives you 80% — your team adds the nuance.", "why_it_works": "Requiring a concrete action for each SWOT item transforms the analysis from a static assessment into a dynamic action plan. The 2x2 matrix forces cross-referencing that reveals non-obvious strategic moves most people miss when they treat each quadrant in isolation.", "follow_up": "Based on this analysis, what are the top 3 strategic moves I should make in the next 90 days? For each, outline the resources needed, the expected outcome, and how I will measure success.", "pro_tip": "Run this analysis quarterly and compare results side by side. The items that persist across quarters without being resolved are your structural issues — they need a fundamentally different approach, not just more effort."}, {"number": "12", "name": "The Customer Persona Builder", "category": "BUSINESS & STRATEGY", "prompt": "Act as a market research specialist with deep expertise in consumer psychology. Build a detailed customer persona for my [product/service] which solves [problem] for [broad audience description]. Include: (1) Demographics — age range, income bracket, location type, job title or industry, education level, (2) Psychographics — core values (top 3), deepest fears related to this problem, aspirations, how they define success, (3) Daily routine — specifically the moments where my product would fit in, (4) Current solution — what they do now to solve this problem and why it falls short, (5) Information diet — where they consume content, who they trust, what podcasts or accounts they follow, (6) Purchase triggers — what would make them say 'I need this right now,' (7) Purchase blockers — what would make them say 'not for me,' (8) Exact language — 5 sentences they would use to describe their problem to a friend, written in first person. Give this persona a name and make it feel like a real person. Do NOT make it an idealized customer — include at least one frustrating trait or objection.", "best_on": ["Claude", "Gemini"], "tip": "Item 8 is gold — use those exact words in your marketing copy.", "why_it_works": "Including a frustrating trait or objection prevents the common 'ideal customer' fantasy that leads to messaging no real person resonates with. The 'exact language' requirement forces the model to generate authentic, colloquial phrasing that you can use directly in ads and copy.", "follow_up": "Now build a second persona that represents a buyer who looks different on the surface but has the same core problem. How should my messaging shift to reach both personas without alienating either?", "pro_tip": "Validate the persona by searching social media, forums, and review sites for people who match this profile. Paste real quotes you find back into the AI and ask 'How should I update this persona based on what real people are actually saying?'"}, {"number": "13", "name": "The Pricing Strategist", "category": "BUSINESS & STRATEGY", "prompt": "Act as a pricing strategy consultant who has worked with both startups and established businesses. Help me price my [product/service]. Here is what I know: it costs me [cost] to deliver, competitors charge [range], my target customer is [description], and the main value I provide is [value]. Analyze three pricing strategies: (1) Cost-plus pricing — show the math, typical markup percentages for my industry, and the resulting price, (2) Value-based pricing — estimate the monetary value of the outcome I deliver, then price at 10-20% of that value, (3) Competitor-based pricing — position relative to the market with a specific rationale. For each strategy, give me a specific price point and explain the psychological anchoring behind it. Then recommend which strategy fits my situation and why. Include a pricing page structure: what tiers to offer, what to name them, what to include in each, and which tier to make the 'default' choice. Do NOT recommend 'free tier' unless I specifically have a freemium model.", "best_on": ["Claude", "Gemini"], "tip": "Most people underprice. Ask the AI 'what would a premium version look like at 3x this price?'", "why_it_works": "Analyzing three strategies side-by-side with specific numbers prevents the common mistake of defaulting to competitor-based pricing. The psychological anchoring explanation helps you understand why certain price points feel right to buyers, which is critical for premium positioning.", "follow_up": "A potential customer says 'That is too expensive.' Write me three different responses based on different objection-handling frameworks: value reframing, comparison anchoring, and risk reversal.", "pro_tip": "Create a 'pricing experiment plan' — test two price points with equal traffic for 2 weeks. Ask the AI to design a statistically valid A/B test for your pricing page, including sample size needed for significance."}, {"number": "14", "name": "The 90-Day Action Plan", "category": "BUSINESS & STRATEGY", "prompt": "Act as a business strategist who specializes in rapid execution planning. Create a 90-day action plan for [business goal]. My current situation: [describe where you are now]. My resources: [time/money/team available]. Break the plan into three 30-day sprints, each building on the previous one. For each sprint, provide: (1) The theme — one sentence describing the focus of this sprint, (2) The one key metric to track with a specific target number, (3) Weekly action items — 3-5 specific tasks per week with clear deliverables (not just 'work on marketing'), (4) Resources or tools needed with estimated costs, (5) A milestone that proves progress — something tangible I can point to, (6) Risk assessment — what could go wrong and a specific course-correction plan. End with a 'pre-mortem': assume the plan failed at Day 90. What were the three most likely causes of failure? What can I do now to prevent each one? Do NOT include any action item that takes more than 4 hours of focused work.", "best_on": ["Claude", "Gemini"], "tip": "Print this out and put it on your wall. Review weekly. Adjust monthly.", "why_it_works": "The sprint structure with escalating themes prevents the 'everything at once' paralysis that kills most 90-day plans. Capping individual tasks at 4 hours ensures every item is actually doable by one person. The pre-mortem technique is borrowed from military planning and dramatically improves plan survival rates.", "follow_up": "It is Day 30. I completed [describe what you actually did]. Update the remaining 60 days based on what I learned. What should I double down on, and what should I drop?", "pro_tip": "At the start of each sprint, paste the plan back to the AI with your progress notes and ask for a 'sprint retrospective and adjustment.' This creates an adaptive plan that improves as you learn."}, {"number": "15", "name": "The Revenue Model Calculator", "category": "BUSINESS & STRATEGY", "prompt": "Act as a financial analyst building a revenue model for an early-stage business. Help me build a revenue model for [business]. My current revenue (if any): [amount]. My main offering: [describe]. Price point: [current or planned]. For each revenue stream, model: (1) All possible revenue streams including primary, secondary, and passive income, (2) For each stream, project monthly revenue at months 1, 3, 6, and 12, (3) Key assumptions behind each projection — stated explicitly so I can challenge them, (4) Customer acquisition cost estimate and customer lifetime value for each stream, (5) Fixed costs vs. variable costs breakdown, (6) Break-even analysis — units sold and months to break-even. Present the core model as a table. Then run three scenarios: conservative (50% of projections), realistic (your projections), and optimistic (150% of projections). For each scenario, state when I break even. Do NOT inflate projections — be skeptical of hockey-stick growth. Assume organic growth unless I specify a paid acquisition budget.", "best_on": ["Claude", "Gemini"], "tip": "Run this with optimistic, realistic, and pessimistic scenarios separately to see the full range.", "why_it_works": "Forcing explicit assumptions and three scenarios prevents the optimism bias that kills most financial projections. The CAC and LTV requirements introduce unit economics thinking early, which many founders skip until it is too late.", "follow_up": "Based on the realistic scenario, what is the single highest-leverage action I can take to accelerate the timeline to break-even? Model what happens if I increase [price/volume/retention] by 20%.", "pro_tip": "Update this model monthly with real numbers. Paste the updated actuals back and ask 'Which assumptions were wrong? Recalculate the projections based on what actually happened.' Your model gets smarter every month."}, {"number": "16", "name": "The Competitor Spy", "category": "BUSINESS & STRATEGY", "prompt": "Act as a competitive intelligence analyst. Analyze [competitor name/URL] in the context of my business: [brief description of your business]. Tell me: (1) Their apparent target audience — who are they really selling to, based on their messaging, pricing, and content, (2) Their pricing strategy and positioning on the value-to-price spectrum, (3) Their content and marketing strategy — what channels they invest in and what messaging angles they use, (4) Their top 3 strengths I should respect and not try to compete on directly, (5) Their top 3 weaknesses I can exploit — be specific about how, (6) Customer sentiment — what patterns appear in their reviews, testimonials, and social mentions (both positive and negative), (7) 3 specific tactical moves I can make to differentiate from them. Do NOT give me generic competitive analysis. Every point must be specific to this competitor and actionable for my business.", "best_on": ["Gemini", "Claude"], "tip": "Do this for your top 3 competitors. The patterns you will see across all three are invaluable.", "why_it_works": "Requiring specificity at every level prevents the generic SWOT-style analysis that adds no strategic value. The 'do not compete on their strengths' instruction embodies the military principle of asymmetric advantage — winning by changing the game rather than playing the same one better.", "follow_up": "Now analyze what this competitor will likely do in the next 6-12 months based on their current trajectory. How should I position myself now to be ahead of their next move?", "pro_tip": "Use Gemini for this prompt since it can access current web data. Then paste Gemini's output into Claude and ask 'What strategic implications does this competitive analysis have for my business? What is the one move that would hurt this competitor the most?'"}]}, {"title": "Category 03: Writing & Communication", "type": "prompts", "content": "8 prompts for writing, editing, and communication tasks.", "items": [{"number": "17", "name": "The Blog Post Generator", "category": "WRITING & COMMUNICATION", "prompt": "Act as a senior content strategist who writes for top-tier publications. Write a 1,000-word blog post about [topic]. Target audience: [who]. Goal: [inform/persuade/entertain]. Structure requirements: (1) Hook opening — the first two sentences must create curiosity or challenge a common belief, no generic introductions, (2) 3-5 subheadings organized as a logical progression, not random sections, (3) Each section must include at least one specific example, data point, or mini-story, (4) Include a 'contrarian take' or surprising perspective somewhere in the piece, (5) Conclusion with a clear call-to-action that connects back to the hook. Tone: [conversational/professional/authoritative]. Do NOT use these phrases: 'In today's fast-paced world,' 'It's no secret that,' 'At the end of the day,' 'game-changer,' 'dive deep,' 'leverage,' or 'landscape.' Avoid starting more than one paragraph with 'The.' Write for scanning — use short paragraphs (2-3 sentences max) and bold key phrases.", "best_on": ["Claude", "Gemini"], "tip": "Always add 'Do NOT use' instructions. It prevents the AI-sounding cliches that readers immediately recognize.", "why_it_works": "The banned-phrase list and structural constraints (hook-first, contrarian take, scan-friendly formatting) force the AI out of its default template mode and into genuinely structured writing. Requiring specific examples in every section prevents the vague generalities that make AI-written content feel hollow.", "follow_up": "Now review this post as a strict editor. Cut any section that does not earn its place. Flag any claim that needs a source. Tighten the prose by 15% without losing substance.", "pro_tip": "Generate the blog post, then paste it back and ask: 'Rewrite the opening three different ways: start with a question, start with a surprising statistic, and start with a micro-story.' Pick the strongest hook."}, {"number": "18", "name": "The Rewriter", "category": "WRITING & COMMUNICATION", "prompt": "Act as a professional editor with 15 years of experience at a major publication. Rewrite the following text to be [shorter/more engaging/simpler/more professional]. Rules: (1) Keep the core meaning and key arguments intact, (2) Make it sound like a human expert wrote it — not AI, (3) Remove all filler words, passive voice, and unnecessary qualifiers ('very,' 'really,' 'just,' 'quite,' 'basically'), (4) If the original is over 200 words, cut it by at least 30%, (5) Improve sentence variety — mix short punchy sentences with longer ones, (6) Replace any cliche with a specific, concrete phrase. Show me the rewritten version, then list the 3 most impactful changes you made and why each improves the text. Here is the text: [paste text]", "best_on": ["Claude"], "tip": "Claude is the best rewriter. It preserves your voice while tightening the prose.", "why_it_works": "The explicit editing checklist mirrors what professional editors actually do: remove filler first, fix voice and structure second, then polish. Requiring the AI to explain its changes teaches you editing skills you can apply to all future writing.", "follow_up": "Now take this rewritten version and create three variations: one for a LinkedIn audience, one for an email, and one for a presentation slide. Same content, different format and density.", "pro_tip": "Keep a personal 'banned words' list — words you overuse or that sound like AI. Add it to every rewriting prompt to make the output increasingly personalized over time."}, {"number": "19", "name": "The LinkedIn Post Creator", "category": "WRITING & COMMUNICATION", "prompt": "Act as a LinkedIn content creator with a track record of high-engagement posts. Write a LinkedIn post about [topic/experience/insight]. Structure: (1) Hook line — must be a pattern interrupt, bold statement, or counterintuitive claim that stops the scroll. No questions as hooks (they underperform), (2) Short paragraphs of 1-2 sentences each with line breaks between them, (3) Include a personal story, specific example, or real data — no abstract advice, (4) Build to one clear, memorable insight or takeaway, (5) End with an open-ended question that invites genuine discussion (not 'agree or disagree?'). Length: 150-200 words. Tone: confident but not preachy — write as someone sharing hard-won experience, not lecturing. Do NOT use hashtags in the body — add 3-5 relevant ones at the very end. Do NOT use emojis as bullet points. Do NOT start with 'I'm excited to share' or 'I recently learned.'", "best_on": ["Claude", "Gemini"], "tip": "The hook line determines 80% of your engagement. Ask for 5 hook variations and pick the best.", "why_it_works": "The formatting rules (short paragraphs, line breaks, no emoji bullets) are reverse-engineered from LinkedIn's algorithm and reading patterns on mobile, where most LinkedIn consumption happens. Banning common openers forces originality in the most important real estate of the post.", "follow_up": "Generate 5 alternative hook lines for this post, each using a different technique: surprising statistic, contrarian opinion, personal failure, bold prediction, and 'I was wrong about' confession. Which would perform best and why?", "pro_tip": "Write 5 posts in a batch using this prompt. Schedule them across the week. Consistent posting matters more than any single viral post — the algorithm rewards reliability."}, {"number": "20", "name": "The Tone Matcher", "category": "WRITING & COMMUNICATION", "prompt": "Act as a linguistic analyst who specializes in personal writing styles. Analyze my writing style from these samples: [paste 2-3 paragraphs you have written]. Produce a detailed 'Writing Style Guide' that includes: (1) Average sentence length and range, (2) Vocabulary level (simple/moderate/advanced) with examples of my characteristic word choices, (3) Tone profile — formality level, warmth, humor, directness (rate each on a 1-10 scale), (4) Structural patterns — how I open paragraphs, how I transition between ideas, how I close, (5) Signature phrases or verbal tics I use frequently, (6) What I never do — patterns that are absent from my writing, (7) A one-paragraph 'writing persona summary' I can paste into any prompt. Format this as a reference document I can reuse. Test your analysis by writing a new paragraph about a random topic in my voice, then explain which specific style elements you applied.", "best_on": ["Claude"], "tip": "Save the output and paste it at the start of any writing prompt: 'Match this writing style: [paste guide]'", "why_it_works": "Quantifying style elements (sentence length, formality scores) gives the AI concrete parameters to match, rather than vague instructions like 'write in my voice.' The test paragraph proves the analysis works and lets you calibrate before using it for real content.", "follow_up": "Now write three short pieces in my voice: a product announcement, a response to a negative review, and a thank-you note to a customer. Each should sound unmistakably like me.", "pro_tip": "Update your style guide every few months as your writing evolves. Paste your latest writing alongside the old guide and ask 'How has my writing style changed? Update the guide to match my current voice.'"}, {"number": "21", "name": "The Email Sequence Builder", "category": "WRITING & COMMUNICATION", "prompt": "Act as an email marketing strategist who has built sequences with 40%+ open rates. Create a [3/5/7]-email sequence for [purpose: welcome series, product launch, re-engagement, etc.]. Target audience: [describe]. The sequence should build progressively toward [goal]. For each email, provide: (1) Subject line — under 50 characters, tested psychological trigger identified (curiosity, urgency, benefit, social proof), (2) Preview text — the hidden second line that appears in inbox, (3) Full email body — conversational, scannable, one core idea per email, (4) Specific call-to-action — only ONE per email, phrased as a button, (5) Send timing — days between emails with rationale, (6) Segmentation trigger — what the reader must have done (or not done) to receive this email. The sequence must tell a story across all emails — not feel like disconnected messages. Each email should deliver standalone value even if the reader does not click. Do NOT use more than one exclamation mark per email.", "best_on": ["Claude", "Gemini"], "tip": "Email subject lines make or break open rates. Ask for 5 subject line options per email.", "why_it_works": "The segmentation triggers transform a generic blast sequence into a behavior-responsive flow. Requiring standalone value in each email follows the principle of reciprocity — the reader gets something before being asked to do something, which dramatically improves conversion.", "follow_up": "Now write the 'did not open' branch: for each email, create a follow-up with a different subject line and angle that goes to anyone who did not open the original within 48 hours.", "pro_tip": "After sending the sequence, paste your open rates and click rates back into the AI. Ask 'Based on these metrics, which emails are underperforming? Rewrite only the underperforming subject lines and CTAs.'"}, {"number": "22", "name": "The Press Release Writer", "category": "WRITING & COMMUNICATION", "prompt": "Act as a PR specialist who has placed stories in major media outlets. Write a press release for [announcement]. Follow AP style guidelines. Structure: (1) Compelling headline — not your company name, but the story (what makes this newsworthy?), (2) Subheadline with the key data point or hook, (3) Dateline and strong opening paragraph covering who/what/when/where/why in the first three sentences, (4) Second paragraph with the most compelling quote from a company leader — make it sound human, not corporate, (5) 2-3 supporting paragraphs with context, data, and a customer or partner quote, (6) Boilerplate 'About [Company]' paragraph (placeholder), (7) Media contact info placeholder. Length: 400-500 words. The release must answer the journalist's question: 'Why should my readers care about this?' within the first 50 words. Do NOT use the words 'excited,' 'thrilled,' 'pleased to announce,' or 'industry-leading.'", "best_on": ["Claude", "Gemini"], "tip": "The headline and first paragraph are all most journalists read. Make them count.", "why_it_works": "Banning corporate cliches and requiring the 'why should readers care' answer upfront forces a newsworthy framing rather than a company announcement framing. Journalists discard 95% of press releases — the ones that survive lead with the story, not the company.", "follow_up": "Now write a media pitch email to accompany this press release — the email a PR person would send to a specific journalist. Under 100 words, personalized angle, explain why their specific audience would care.", "pro_tip": "Write the press release, then ask 'What is the real story here that a journalist would actually want to cover? Reframe the entire release around that angle.' Often the real story is not what you think it is."}, {"number": "23", "name": "The Script Writer", "category": "WRITING & COMMUNICATION", "prompt": "Act as a professional video scriptwriter who creates content for [platform: YouTube, TikTok, Instagram Reel, etc.]. Write a [length]-minute script about [topic]. My audience is [describe]. The goal is [educate/entertain/sell]. Script requirements: (1) Hook in the first 3 seconds — must create a 'pattern interrupt' that stops the scroll. Write three hook options, (2) Visual and action cues in [brackets] throughout — every 15-30 seconds should have a visual change, (3) Conversational tone — write for speaking, not reading. Use contractions. Short sentences. Fragments are fine, (4) 'Open loop' at the 30% mark — tease something coming later to prevent drop-off, (5) Clear CTA at the end — specific and single action, (6) Retention markers — note where viewers are most likely to drop off and include a re-engagement technique at each point. Include estimated timestamps. The script should feel like talking to a smart friend, not presenting to an audience.", "best_on": ["Claude", "Gemini"], "tip": "Read the script aloud. If you stumble on any phrase, it is not natural enough — ask AI to simplify.", "why_it_works": "The retention markers and open loops are techniques used by top content creators to maintain watch time, which is the primary signal every platform algorithm uses for distribution. Visual change cues every 15-30 seconds match the average attention span data from platform analytics.", "follow_up": "Now create a thumbnail concept and title for this video. Give me 5 title options using different psychological triggers and describe what the thumbnail should show, including text overlay and color palette.", "pro_tip": "Record yourself delivering the script 'off-book' — just from memory of the key points. Your natural delivery is always better than reading. Then transcribe your natural version and use that as the final script."}, {"number": "24", "name": "The Proposal Template", "category": "WRITING & COMMUNICATION", "prompt": "Act as a business development consultant who has helped close deals worth over $1M. Create a professional [business/project/freelance] proposal for [client/project description]. My qualifications: [brief background]. Structure: (1) Executive summary — 3 sentences max, leading with the client's problem and desired outcome, (2) Problem statement — describe what the client is facing using THEIR language, showing you deeply understand their situation, (3) Proposed solution with specific deliverables — each deliverable includes what it is, why it matters, and the timeline, (4) Process and timeline with milestones — a clear visual timeline the client can scan in 10 seconds, (5) Investment section — frame pricing around value/ROI, not cost. Include payment terms, (6) Why choose us — 3 proof points (results, testimonials, relevant experience), not a generic company bio, (7) Risk mitigation — address the client's unspoken fear of 'what if this does not work,' (8) Next steps — exactly one action for the client to take. Tone: professional and confident, never desperate. Length: 2-3 pages. Do NOT include generic phrases like 'we are passionate about' or 'our team of dedicated professionals.'", "best_on": ["Claude", "Gemini"], "tip": "Customize the problem statement with specific details about the client. Generic proposals lose deals.", "why_it_works": "Starting with the client's problem instead of your company's story flips the standard proposal structure. The risk mitigation section addresses the buyer's deepest unspoken objection — 'what if I waste my money' — which most proposals ignore entirely, leaving it as an invisible deal-killer.", "follow_up": "Now create a one-page 'proposal summary' version I can send as an email. It should hit the same key points but be scannable in under 60 seconds. Include a subject line.", "pro_tip": "Before writing the proposal, ask the AI: 'What are the top 5 concerns a [client type] would have about hiring someone for [project type]?' Then make sure your proposal addresses every single one — explicitly or implicitly."}]}, {"title": "Category 04: Marketing & Social Media", "type": "prompts", "content": "8 prompts for marketing, social media, and content creation.", "items": [{"number": "25", "name": "The Content Calendar Generator", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a social media strategist managing accounts with 50K+ followers. Create a 30-day social media content calendar for [business/brand] on [platforms]. My content pillars are: [list 3-4 topics]. For each day, provide: (1) Post topic/theme with a specific angle — not just 'post about X' but the exact angle and hook, (2) Content type (carousel, video, story, reel, text post) with rationale for why this type fits this topic, (3) Caption with a scroll-stopping hook and clear CTA, (4) Best posting time based on platform best practices for [my audience's timezone], (5) 5-10 relevant hashtags per post mixing high-volume and niche. Content mix: 40% educational (teach something valuable), 30% engaging (spark conversation or emotion), 20% promotional (sell or convert), 10% behind-the-scenes (build trust and relatability). Include 2 'tentpole' posts per week designed for maximum shareability. Do NOT repeat the same content type more than twice consecutively.", "best_on": ["Gemini", "Claude"], "tip": "Batch-create a month's content in one sitting using this calendar as your roadmap.", "why_it_works": "The 40/30/20/10 content mix ratio is based on engagement data from high-performing social accounts. Preventing consecutive repeat content types ensures visual variety in the feed, which is critical for both algorithm performance and follower retention.", "follow_up": "Now pick the 5 strongest posts from this calendar and expand each into a full content brief: the complete caption, visual description for the designer, any text overlays, and 3 comment responses I should have ready for likely reactions.", "pro_tip": "At the end of each month, paste your top 5 and bottom 5 performing posts from this calendar back into the AI. Ask 'What patterns separate the winners from the losers? Adjust next month's calendar based on these insights.'"}, {"number": "26", "name": "The Ad Copy Writer", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a direct-response copywriter who has managed ad campaigns with 3x+ ROAS. Write [Facebook/Google/Instagram] ad copy for [product/service]. Target audience: [describe — demographics, pain points, current situation]. Pain point this ad addresses: [describe specifically]. Create a complete ad set: (1) 3 headline variations — under 30 characters each, each using a different psychological trigger (curiosity, benefit, social proof), (2) 3 primary text variations — Version A: emotional/story-driven appeal, Version B: logical/data-driven appeal, Version C: curiosity-driven/open-loop appeal. Each under 125 words, (3) Description text for the link preview, (4) Call-to-action button recommendation with rationale, (5) Audience targeting suggestions — 3 interest-based targeting ideas. For all copy: lead with the transformation, not the product. Use 'you' more than 'we.' Do NOT use false scarcity or misleading claims. Do NOT use all-caps words.", "best_on": ["Claude", "Gemini"], "tip": "Always test at least 3 variations. The AI can generate them — let your audience pick the winner.", "why_it_works": "Creating three distinct psychological angles (emotional, logical, curiosity) lets you test which resonance pattern works best for your specific audience. Leading with transformation instead of product features activates the buyer's imagination, which is the first step in any purchase decision.", "follow_up": "Now write the landing page headline and first paragraph that each ad variation should link to. The message match between ad and landing page is the single biggest factor in conversion rate.", "pro_tip": "Write the ad copy, then ask: 'Now write the negative version — an ad targeting people who FAILED at solving this problem with a competitor's solution. Use their frustration as the hook.' Negative framing often outperforms positive framing in paid ads."}, {"number": "27", "name": "The SEO Article Planner", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as an SEO content strategist who has ranked articles on the first page for competitive keywords. Create an SEO content plan for the keyword [target keyword]. My website is about [topic/niche]. Current domain authority: [if known, or 'new site']. Provide: (1) Search intent analysis — is the searcher looking to learn, compare, buy, or solve a problem? Support your answer with evidence, (2) Suggested article title — include the keyword naturally, under 60 characters, compelling enough to click over the 9 other results on page one, (3) Meta description — exactly 155 characters, includes keyword and a reason to click, (4) Complete heading structure — H1, H2s, and H3s that cover the topic thoroughly and target related keywords, (5) 10 semantically related keywords to include naturally throughout the content, (6) Content gap analysis — what are the top 3 ranking articles missing that mine should include, (7) Recommended content length based on what currently ranks, (8) 3 internal linking opportunities and 3 authoritative external link suggestions. Do NOT keyword-stuff. The content plan should prioritize genuine usefulness over SEO tricks.", "best_on": ["Gemini", "Claude"], "tip": "Gemini has the most current web data. Use it for keyword research, then write the actual article with Claude.", "why_it_works": "The content gap analysis — identifying what top-ranking articles miss — is how experienced SEOs find opportunities in competitive niches. Prioritizing usefulness over SEO tricks aligns with modern search algorithms that reward user satisfaction signals.", "follow_up": "Now write the introduction and first H2 section of this article. Make the intro hook strong enough that a reader who landed from Google would not hit the back button within 5 seconds.", "pro_tip": "Use Gemini to find 'People Also Ask' questions for your keyword. Paste those questions back and ask 'Add an FAQ section to the content plan that directly answers each of these questions.' Google frequently pulls FAQ answers into featured snippets."}, {"number": "28", "name": "The Landing Page Copy", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a conversion rate optimization specialist who has written landing pages with 10%+ conversion rates. Write landing page copy for [product/service]. Conversion goal: [purchase/signup/book a call]. Target audience: [describe — who they are, what they have tried before, what they fear]. Structure: (1) Hero section — headline (under 10 words, benefit-driven), subheadline (one sentence expanding the promise), CTA button text, (2) Problem section — describe 3 specific pain points using the customer's own language, not clinical descriptions, (3) Solution section — how the product solves each pain point, mapped one-to-one, (4) Features-to-benefits translation — 3-5 features, each with 'So that you can...' benefit statement, (5) Social proof section — structure for testimonials (what format, what they should emphasize), (6) Objection handling — FAQ with the 5 questions buyers silently ask before purchasing, (7) Final CTA section with urgency element and risk reversal (guarantee or safety net). Every section should have a micro-CTA or visual cue pointing toward the main action. Do NOT use 'Welcome to our website' or feature-only descriptions without benefits.", "best_on": ["Claude", "Gemini"], "tip": "The best landing pages follow the formula: Problem, Agitate, Solution, Proof, CTA.", "why_it_works": "The one-to-one mapping between pain points and solutions creates a logical inevitability in the reader's mind. Addressing silent objections in the FAQ preempts the buyer's internal resistance, which is the primary reason visitors leave without converting.", "follow_up": "Now write the above-the-fold A/B test variant: same page, but with a completely different headline angle. Version A leads with the benefit. Version B leads with the pain. Explain which you would test first and why.", "pro_tip": "After writing the copy, ask: 'Read this landing page as a skeptical visitor who has been burned before. What would still make you hesitate? Add a section that addresses that final objection.' This usually reveals the one thing keeping your conversion rate from doubling."}, {"number": "29", "name": "The Hashtag Strategist", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a social media growth strategist who specializes in organic reach optimization. Generate a comprehensive hashtag strategy for my [niche/industry] content on [Instagram/TikTok/LinkedIn]. My content is about [describe your content topics]. My current follower count: [approximate]. Provide: (1) 10 high-volume hashtags (1M+ posts) — use these sparingly for visibility, (2) 10 medium-volume hashtags (100K-1M posts) — your bread and butter for discoverability, (3) 10 niche/low-competition hashtags (under 100K posts) — where you can actually rank on the hashtag page, (4) 5 branded hashtag suggestions — short, memorable, ownable, and not already in heavy use, (5) Recommended hashtag sets — 3 pre-built combinations of 10 hashtags each (one for each content pillar). For each set, explain the strategy: are you going for reach, community, or discoverability? Include which hashtags to put in the caption vs. in comments (platform-specific). Do NOT suggest banned, shadow-banned, or spam-associated hashtags.", "best_on": ["Gemini", "Claude"], "tip": "Use 3 large + 4 medium + 3 niche hashtags per post. This balances reach with discoverability.", "why_it_works": "The tiered volume approach matches how platform algorithms categorize content — niche hashtags give you quick ranking wins that signal relevance to the algorithm, which then serves your content to broader audiences through the medium and high-volume tags.", "follow_up": "Now audit my current hashtag usage: [paste your last 5 post hashtags]. Which ones are helping, which are wasted, and what should I replace them with?", "pro_tip": "Create a rotating hashtag library — 5 sets of 10 hashtags each. Rotate them across posts to avoid the 'same hashtags every time' penalty that Instagram's algorithm now detects. Use a spreadsheet or notes app to track which set is next."}, {"number": "30", "name": "The Product Description Writer", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a senior e-commerce copywriter who has written for brands with 7-figure revenue. Write 3 product descriptions for [product name]. Target customer: [describe their situation and desire]. Key differentiator: [what makes this unique]. Price point: [price]. Description 1: Benefit-focused — lead with the transformation or outcome, paint a picture of life after purchase, 80-150 words. Description 2: Feature-focused — specs, details, and materials translated into 'this means you get...' benefit statements, 80-150 words. Description 3: Story-driven — open with a mini-scenario the reader recognizes, introduce the product as the solution, 80-150 words. Each description must: use sensory language, include a strong CTA, address one common objection, and end with a reason to buy now (not fake urgency). Do NOT use superlatives like 'best,' 'perfect,' or 'ultimate' without a specific supporting claim.", "best_on": ["Claude", "Gemini"], "tip": "A/B test all three on your product page. Story-driven descriptions often convert 20-30% better.", "why_it_works": "Three distinct approaches let you test which communication style resonates with your specific buyer. Banning unsupported superlatives forces specificity, which builds more trust than generic enthusiasm. Addressing an objection within the description preempts the hesitation that causes cart abandonment.", "follow_up": "Now write the complete product page copy: combine the strongest elements from all three descriptions into one cohesive product page with headline, subheadline, bullet points, and CTA. Add a 'who this is for' and 'who this is NOT for' section.", "pro_tip": "Ask the AI to write the description from the perspective of a happy customer writing a 5-star review. Often the most persuasive product copy reads like a testimonial, not like marketing."}, {"number": "31", "name": "The Audience Pain Point Finder", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as a consumer psychologist who specializes in buyer motivation research. My product/service helps with [problem/category]. My target audience is [describe]. List the top 15 pain points this audience experiences related to this problem. For each pain point: (1) Describe it in the exact words the customer would use — first-person, colloquial, emotionally honest, (2) Rate its emotional intensity (1-10) and explain why it scores that high, (3) Identify the deeper fear or desire underneath the surface pain, (4) Suggest a specific content piece (blog post, video, social post) that addresses it, with a title, (5) Write a one-sentence ad hook that targets this pain point. Rank from most to least emotionally intense. Do NOT list generic problems like 'time management' — every pain point must be specific enough that the reader thinks 'that is exactly my problem.'", "best_on": ["Claude", "Gemini"], "tip": "The top 3 pain points equal your marketing headlines. Use the customer's exact words, not corporate language.", "why_it_works": "Requiring first-person customer language forces the model to think from the buyer's perspective rather than the seller's. Identifying the deeper fear underneath the surface pain reveals the emotional motivators that drive purchasing decisions — people buy to escape pain more than to gain pleasure.", "follow_up": "Now take the top 5 pain points and build a complete messaging framework: for each, write the headline, the supporting paragraph, and the specific product feature or benefit that resolves it. This becomes the foundation of all your marketing.", "pro_tip": "Validate these pain points by searching Reddit, online forums, and Amazon reviews for your product category. Paste real customer complaints back into the AI and ask 'How should I update my pain point list based on what real people are actually saying?'"}, {"number": "32", "name": "The Email Subject Line Generator", "category": "MARKETING & SOCIAL MEDIA", "prompt": "Act as an email marketing specialist with deep expertise in open-rate optimization. Generate 20 email subject lines for [purpose: newsletter, product launch, abandoned cart, re-engagement, etc.]. Target audience: [describe — their situation, what they care about, their sophistication level]. Requirements: (1) All under 50 characters — shorter performs better on mobile, (2) Categorize each by psychological trigger used: curiosity, urgency, benefit, personalization, social proof, or fear of missing out, (3) No ALL CAPS or excessive punctuation (maximum one question mark or exclamation per line), (4) At least 4 should use specific numbers or data, (5) At least 4 should ask a question, (6) At least 3 should use the word 'you' or 'your,' (7) Include 3 'negative' subject lines (addressing a fear or mistake). Rate each on estimated open-rate potential (1-10) and explain your top 3 picks with reasoning. Do NOT use spam trigger words like 'free,' 'act now,' 'limited time,' or 'congratulations.'", "best_on": ["Claude", "Gemini"], "tip": "Subject lines with numbers outperform those without by 15-20%. Always test 2 subject lines per send.", "why_it_works": "Categorizing by psychological trigger creates a diverse set that tests multiple mental entry points. Including 'negative' subject lines is counter-intuitive but backed by data — emails addressing fears or mistakes consistently achieve higher open rates than purely positive framing.", "follow_up": "Now write the preview text (the first line visible in the inbox) for your top 5 subject lines. The preview text should complement the subject line, not repeat it — together they should tell a mini-story that makes opening irresistible.", "pro_tip": "Build a 'subject line swipe file' — save every subject line that makes YOU open an email. Paste your collection into the AI periodically and ask 'What patterns do I respond to? Generate 10 subject lines that use those same patterns for my business.'"}]}, {"title": "Category 05: Research & Analysis", "type": "prompts", "content": "6 prompts for research, data analysis, and trend spotting.", "items": [{"number": "33", "name": "The Research Synthesizer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a senior research analyst at a leading consultancy. I need to quickly understand [topic/industry/trend]. Provide a structured briefing: (1) A 3-sentence summary so clear that a 10-year-old could understand the basics, (2) The 5 most important facts or statistics — cite specific numbers where possible and note your confidence level in each (high/medium/low), (3) Key players and companies in this space with a one-sentence description of each player's position, (4) Current state and trajectory — where things are now, where they are heading, and the 2-3 forces driving the change, (5) The 3 most common misconceptions about this topic and why each is wrong, (6) Contrarian view — one credible perspective that goes against the mainstream narrative, (7) 5 specific sources I should read for deeper knowledge (publications, reports, or authors, not generic 'Google it' advice). Do NOT give me a textbook overview — give me the briefing I would want before walking into a meeting with experts on this topic.", "best_on": ["Gemini", "Claude"], "tip": "Gemini has the most current data. Use it for trends and stats, then deep-dive with Claude for nuanced analysis.", "why_it_works": "The 'explain it to a 10-year-old' constraint forces simplification that reveals whether you truly understand something. The contrarian view section prevents echo-chamber thinking and prepares you for pushback from well-informed skeptics.", "follow_up": "Based on this briefing, what are the 3 smartest questions I could ask an expert on this topic to signal that I have done my homework and to learn something I cannot find in public sources?", "pro_tip": "Use Gemini for the initial research (current data), then paste the output into Claude and ask 'What is this briefing missing? What nuances would a true expert add?' The combination of breadth and depth is unbeatable."}, {"number": "34", "name": "The Data Interpreter", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a data analyst presenting findings to a non-technical executive. Analyze this data and tell me what it means in plain English: [paste data/numbers/results]. Context: this data is from [describe the source and what it measures]. My goal is to [what you want to decide or understand]. Specifically provide: (1) The headline takeaway — one sentence a CEO would want to hear first, (2) 3-5 patterns or trends — what the data shows when you look beyond the surface numbers, (3) The most surprising or counterintuitive finding and why it matters, (4) Anomalies or red flags — anything that looks off or needs investigation, (5) Recommended actions — 3 specific things I should do based on this data, prioritized by impact, (6) What additional data I would need to make a more confident decision — be specific about what to collect and why. Present this as a brief executive summary with bullet points. Do NOT use statistical jargon without a plain-English translation. If the data is insufficient to draw a conclusion, say so explicitly rather than speculating.", "best_on": ["Claude", "Gemini"], "tip": "Always ask 'What additional data would I need?' — it reveals blind spots in your analysis.", "why_it_works": "Starting with the headline takeaway forces the AI to prioritize signal over noise. Requiring anomaly detection and explicit uncertainty acknowledgment prevents the common AI failure mode of generating confident-sounding analysis from insufficient data.", "follow_up": "Now create a simple visualization recommendation — what type of chart or graph would best communicate the headline takeaway to my team? Describe the chart, what goes on each axis, and the key data points to highlight.", "pro_tip": "Paste the same data set with a different framing question and compare the analyses. Data tells different stories depending on what question you ask. The AI will surface different patterns based on different objectives."}, {"number": "35", "name": "The Book Summarizer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a well-read intellectual who specializes in extracting actionable knowledge from books. Summarize the book [title] by [author]. Provide a structured briefing: (1) The core thesis in one sentence — not the topic, but the argument, (2) The 5 key ideas with a 2-3 sentence explanation of each — focus on what is original or counterintuitive, not what is obvious, (3) The most actionable advice — the specific thing a reader could implement today, (4) The strongest evidence or example the author uses — the one that makes the argument most convincing, (5) Who should read this book and who should skip it — be specific about the reader profile, (6) The best critique of the book's argument — what would a thoughtful skeptic say is wrong, (7) 3 quotes that capture the book's essence, (8) How this book connects to or contradicts other well-known works in the same field. Do NOT just list chapter summaries — synthesize the ideas into a coherent briefing that is more useful than the table of contents.", "best_on": ["Claude", "Gemini"], "tip": "After the summary, ask 'What would a critic say is wrong with this book's argument?' to get a balanced view.", "why_it_works": "Requiring the thesis (not just the topic) forces genuine comprehension. The critique section applies steel-man thinking to prevent uncritical acceptance of the author's ideas. Connecting to other works places the book in an intellectual context that deepens understanding.", "follow_up": "Based on the key ideas, create a one-page 'implementation plan' — how would I apply the three most relevant ideas from this book to my situation: [describe your context]? Be specific about daily or weekly actions.", "pro_tip": "After getting summaries of 3-5 books on the same topic, paste all summaries together and ask 'What do these books agree on? Where do they contradict each other? What is the synthesized wisdom if you combine the best of each?' This gives you a meta-understanding that surpasses any single book."}, {"number": "36", "name": "The Industry Report Generator", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a management consultant preparing a client briefing on a market opportunity. Create a mini industry report on [industry/market]. Context: I am considering [entering this market / investing / partnering / building a product for this space]. Provide: (1) Market size — estimated total addressable market with a note on data freshness and confidence level, (2) Growth trajectory — historical growth rate and projected growth, with the key drivers behind each, (3) Competitive landscape — top 5 companies with their estimated market share, positioning strategy, and recent strategic moves, (4) Value chain — how money flows from customer to provider, where the margins are, and where the bottlenecks exist, (5) Key trends shaping the industry in 2026 — 3-5 trends with evidence for each, (6) Major challenges and disruptions — what could upend the current order, (7) Opportunities for new entrants — specific niches or underserved segments, (8) 3 predictions for the next 2-3 years with confidence ratings. Format as a professional brief with clear section headings. Do NOT present estimates as facts — always indicate when you are approximating.", "best_on": ["Gemini", "Claude"], "tip": "Cross-reference the numbers with a quick web search. AI estimates are directionally correct but not always precise.", "why_it_works": "The value chain analysis is what separates a useful industry report from a Wikipedia summary — understanding where money and margins flow reveals the real opportunities. Requiring confidence levels on estimates prevents false precision that leads to bad decisions.", "follow_up": "Based on this report, if I were entering this market with [describe your resources and strengths], what is the highest-probability path to capturing $100K in annual revenue within 12 months? Be specific about the niche, the offering, and the go-to-market approach.", "pro_tip": "Run this report using Gemini for current market data, then paste the output into Claude and ask 'As a strategy consultant, what is the non-obvious insight in this data? What opportunity is hiding in plain sight that most people would miss?'"}, {"number": "37", "name": "The Survey Designer", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a market research methodologist who designs surveys for Fortune 500 companies. Design a [5/10/15]-question survey to understand [research goal]. Target respondents: [describe who will take this survey]. For each question: (1) The question itself — clear, unambiguous, no leading language, (2) Question type — multiple choice, Likert scale (1-5 or 1-7), open-ended, ranking, or matrix, (3) Answer options if applicable — mutually exclusive and collectively exhaustive, (4) Why this question is included — what specific insight it reveals, (5) How I will use the answer — the decision it informs. Survey architecture: start with easy, non-threatening questions to build momentum. Place sensitive or complex questions in the middle. End with demographics and a thank-you. Include one open-ended question that captures insights I might not have thought to ask about. Estimated completion time must be under [X] minutes. Do NOT use double-barreled questions (asking two things at once) or agree/disagree scales (they introduce acquiescence bias).", "best_on": ["Claude", "Gemini"], "tip": "Keep it under 10 questions for 80%+ completion rates. Every additional question drops completion by 5-10%.", "why_it_works": "Requiring a 'how I will use the answer' explanation for each question eliminates the 'nice to know' questions that bloat surveys and reduce completion rates. Banning agree/disagree scales follows survey methodology best practice — they systematically bias toward agreement.", "follow_up": "Now write the survey introduction — the brief paragraph respondents see before starting. It should explain why their response matters, how long it takes, and how their data will be used. Also write a follow-up email template thanking them for completing the survey and sharing one key finding.", "pro_tip": "Before sending the survey, have 3 people from your target audience take it while you watch. Note every point of confusion or hesitation. Paste their feedback back into the AI and ask for a revision. This pilot test catches 80% of survey design problems."}, {"number": "38", "name": "The Trend Spotter", "category": "RESEARCH & ANALYSIS", "prompt": "Act as a futurist and trend analyst who advises businesses on emerging opportunities. Identify 10 emerging trends in [industry/niche] for 2026-2027. For each trend: (1) What it is in one sentence — clear and jargon-free, (2) Why it is happening now — the underlying forces driving this trend (technology, behavior shift, regulation, economics), (3) Evidence — one specific data point, company, or event that proves this trend is real and not just hype, (4) Who is already doing it well — a specific company or person to watch, (5) How a [small business/freelancer/startup] could capitalize on it — a concrete, low-cost action step, not just 'be aware of it,' (6) Timeline — is this a 6-month, 1-year, or 3-year opportunity window? (7) Confidence level (high/medium/low) that this trend will grow. Rank from most to least impactful for someone in my position: [describe your business or role]. Do NOT include trends that have been mainstream for more than 2 years — I want emerging, not established.", "best_on": ["Gemini", "Claude"], "tip": "Focus on the 2-3 trends with high confidence that align with your skills. Ignore the rest.", "why_it_works": "Requiring evidence and a timeline separates genuine emerging trends from speculative hype. The 'how to capitalize' constraint forces practical relevance — most trend reports describe what is happening without telling you what to do about it, which is the only part that matters.", "follow_up": "For the top 3 trends most relevant to my business, create a 30-day action plan to position myself as an early mover. What should I build, publish, or learn this month to be ahead of the curve?", "pro_tip": "Run this prompt quarterly using Gemini (for current data) and compare the outputs over time. Trends that appear consistently and move up in ranking are the real ones to bet on. Trends that appear once and vanish were just hype."}]}, {"title": "Category 06: Learning & Personal Growth", "type": "prompts", "content": "6 prompts for learning, interviews, negotiation, and personal development.", "items": [{"number": "39", "name": "The Skill Learning Plan", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a learning design specialist who builds curricula for accelerated skill acquisition. Create a 30-day learning plan to go from beginner to competent in [skill]. My learning style: [visual/reading/hands-on/auditory]. Time available: [30-60 minutes per day]. Include: (1) Daily tasks — each day should have one focused learning activity and one practice exercise, clearly separated, (2) Free resources for each day — specific YouTube videos, articles, tools, or tutorials (not just 'search for X'), (3) A weekly mini-project that applies that week's learning to a real scenario, (4) Progress checkpoints — at days 7, 14, 21, and 30, specific tests or demonstrations that prove competency at each level, (5) Common beginner mistakes with an explanation of why they happen and how to avoid each, (6) A 'plateau buster' for each week — what to do when progress feels stuck. Structure each week with a theme that builds on the previous week. Do NOT front-load theory — interleave learning and doing from Day 1.", "best_on": ["Gemini", "Claude"], "tip": "The mini-projects are the most important part. You do not learn by consuming — you learn by doing.", "why_it_works": "Interleaving theory and practice from Day 1 follows the 'desirable difficulty' principle from learning science — struggling with application while learning concepts creates deeper neural pathways than mastering theory before attempting practice.", "follow_up": "I have completed Week 1. Here is what I found easy and what I struggled with: [describe]. Adjust the remaining 3 weeks based on my actual progress, spending more time on my weak areas and accelerating through my strengths.", "pro_tip": "At the end of 30 days, ask the AI: 'Test me. Ask me 10 questions that a competent practitioner of [skill] should be able to answer. Then grade my answers and tell me exactly what I still need to work on.' This final assessment reveals gaps you might not notice on your own."}, {"number": "40", "name": "The Interview Prep Coach", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a career coach who has helped hundreds of candidates land offers at competitive companies. I am interviewing for a [job title] position at [company type/name]. My background: [brief summary of experience and strengths]. Help me prepare: (1) The 10 most likely interview questions for this specific role — not generic questions, but ones tailored to this industry and level, (2) For each question, a strong answer framework using the STAR method (Situation, Task, Action, Result) with notes on what the interviewer is actually evaluating, (3) 5 thoughtful questions I should ask the interviewer — questions that demonstrate strategic thinking and genuine interest, not questions I could answer by reading the company website, (4) Company research checklist — exactly what to look up and how to reference it naturally in conversation, (5) Red flags to watch for about the company during the interview, (6) A 90-second 'Tell me about yourself' script that positions my experience as a narrative building toward this exact role. Do NOT give me generic advice like 'be confident' or 'dress professionally.' Every piece of guidance should be specific and actionable.", "best_on": ["Claude", "Gemini"], "tip": "Practice answers out loud, not just in your head. Record yourself on your phone and review.", "why_it_works": "Explaining what the interviewer is actually evaluating with each question transforms preparation from memorizing answers to understanding the underlying assessment. The 'Tell me about yourself' narrative structure ensures your response has a logical arc rather than being a chronological resume recitation.", "follow_up": "Now simulate a 15-minute interview. Ask me the 5 hardest questions one at a time. After each of my answers, tell me what was strong, what was weak, and how to improve it. Be direct — I want to improve, not feel good.", "pro_tip": "Ask the AI: 'What is the one answer that could single-handedly lose me this job? What mistake do candidates for [role] make most often?' Knowing what NOT to say is often more valuable than knowing what to say."}, {"number": "41", "name": "The Negotiation Prep", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a negotiation strategist who has coached executives through high-stakes negotiations. Help me prepare to negotiate [salary/contract/deal/price]. My current situation: [describe what you have now]. What I want: [describe your ideal outcome]. What I think the other side wants: [describe their priorities]. My leverage: [describe any advantages you have]. Provide: (1) 3 strong opening positions — aggressive, moderate, and conservative — with exact numbers or terms for each and the logic behind them, (2) My BATNA (best alternative to a negotiated agreement) — help me identify and strengthen it, (3) Their likely BATNA — what happens if they say no, (4) Key leverage points I might not have considered, (5) Likely objections from the other side and a specific counter for each — including the exact words to use, (6) My walk-away point and how to communicate it without making an ultimatum, (7) Word-for-word scripts for the 3 hardest moments: the opening ask, responding to their first 'no,' and closing the deal. End with a negotiation preparation checklist of things to know before I walk in. Do NOT give me generic negotiation theory — give me a specific game plan for THIS negotiation.", "best_on": ["Claude"], "tip": "Claude excels at nuanced negotiation scenarios. It will give you scripts you can actually use.", "why_it_works": "Analyzing both sides' BATNAs creates a realistic power map rather than the one-sided preparation most people do. Word-for-word scripts for high-stress moments prevent the common failure of knowing what to say in theory but freezing in practice.", "follow_up": "The negotiation happened. Here is what they said and what I agreed to: [describe]. Did I leave money on the table? What should I negotiate in the follow-up or next renewal based on what I learned about their priorities?", "pro_tip": "Before the negotiation, ask the AI to role-play as the other side. Say 'You are [the other party]. I am going to make my opening ask. Respond as they would, then break character and tell me how I did.' Practice the full conversation 2-3 times."}, {"number": "42", "name": "The Feedback Translator", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as an executive coach who specializes in processing professional feedback constructively. I received this feedback: [paste feedback]. Context: this came from [who — manager, client, peer, report] about [what situation]. Help me process it productively: (1) Emotional content vs. factual content — separate the feelings, tone, and subjective opinions from the specific, observable behaviors mentioned, (2) Pattern check — what are the 2-3 core messages underneath the surface words? What is this person really trying to tell me? (3) Validity assessment — for each core message, rate it as likely accurate, partially accurate, or more about the giver than about me. Explain your reasoning, (4) Action items — 3 concrete, measurable things I should change in the next 30 days, with specific milestones, (5) What to intentionally ignore — which parts are opinion, projection, or style preference rather than substantive feedback, (6) Professional response — draft a reply that shows I have listened and internalized without being defensive or over-apologetic. The response should be under 100 words. Do NOT dismiss the feedback or validate my ego — help me extract maximum value from it, even if it stings.", "best_on": ["Claude"], "tip": "This is incredibly useful for harsh performance reviews or critical client feedback.", "why_it_works": "The emotional/factual separation prevents the common reaction of either defensively rejecting all feedback or anxiously accepting everything as truth. Rating validity of each point creates the psychological distance needed to process difficult feedback rationally rather than emotionally.", "follow_up": "30 days from now, I want to proactively request follow-up feedback from this same person. Write me a short message that asks 'Have you noticed improvement in [specific areas]?' in a way that is confident and genuine, not needy.", "pro_tip": "Keep a 'feedback journal' — paste every significant piece of feedback into the AI over time. Quarterly, ask: 'What themes keep showing up across all this feedback? What is the one thing that, if I fixed it, would resolve most of the recurring issues?' This reveals your blind spot."}, {"number": "43", "name": "The Networking Message Crafter", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a relationship-building strategist who has helped professionals build networks that generate real opportunities. Write a [LinkedIn/email/Twitter DM] message to connect with [person's role/description]. My goal: [what I want from the connection — advice, collaboration, introduction, etc.]. My background: [brief description]. What I know about them: [something specific about their work]. Rules: (1) Under 75 words total — every word must earn its place, (2) Reference something specific about their work that shows genuine familiarity, not surface-level flattery, (3) Make the value proposition about them — what do they gain from responding, (4) Include a clear but low-pressure ask — something they can say yes to in under 2 minutes of effort, (5) No fake flattery, no 'I'd love to pick your brain,' no 'I'm a huge fan,' (6) Include an easy out — so they do not feel trapped if they are not interested. Provide 3 variations with different approaches: one leading with a shared connection or experience, one leading with a valuable insight, and one leading with a specific question.", "best_on": ["Claude", "Gemini"], "tip": "The shorter the message, the higher the response rate. 50-75 words is the sweet spot.", "why_it_works": "The 75-word limit forces ruthless prioritization of every sentence. Providing an easy out paradoxically increases response rates because it removes the feeling of social obligation. Three variations let you pick the approach that feels most authentic to your personality.", "follow_up": "They responded positively. Now write my reply that: (1) thanks them briefly, (2) provides the context they need, and (3) proposes a specific, low-friction next step. Keep it under 50 words.", "pro_tip": "Before sending, ask the AI: 'Read this message as [the recipient]. What is your honest reaction? Would you respond? If not, what would make you more likely to?' This perspective-flip catches tone-deaf messaging before it lands."}, {"number": "44", "name": "The Difficult Conversation Planner", "category": "LEARNING & PERSONAL GROWTH", "prompt": "Act as a conflict resolution specialist and executive coach. Help me plan a difficult conversation with [person/role] about [topic]. Context: [describe the situation, your relationship, and why this conversation is necessary]. Provide: (1) An opening statement that is honest but non-confrontational — lead with shared goals, not accusations. Write the exact words, (2) 3 key points I need to make — for each, provide the core message AND the way to phrase it that minimizes defensiveness (use 'I' statements and observed behavior, not interpretations), (3) Empathy bridges — 2-3 statements that acknowledge their perspective even when I disagree, (4) Likely defensive reactions and a calm, de-escalating response for each — including what to do if they get angry, shut down, or deflect, (5) What a successful outcome looks like — be specific about what changes and what does not, (6) A closing statement that preserves the relationship and confirms next steps, (7) A contingency plan — what to do if the conversation goes off the rails. Do NOT make this manipulative — the goal is honest, respectful communication that solves a real problem.", "best_on": ["Claude"], "tip": "Claude gives the most emotionally intelligent responses for interpersonal scenarios.", "why_it_works": "Scripting both your messages and their likely reactions creates a mental rehearsal that dramatically reduces anxiety and improves real-time performance. The empathy bridges prevent the conversation from becoming adversarial, which is the primary way difficult conversations fail.", "follow_up": "The conversation happened. Here is how it went: [describe what happened, their reactions, and the outcome]. What should I do as a follow-up? Draft a brief message or action that reinforces the positive outcome or addresses anything left unresolved.", "pro_tip": "Practice the conversation with the AI acting as the other person. Tell it: 'Respond as [person] would — including their defensiveness, excuses, or emotional reactions. Do not be nice about it.' The realistic simulation prepares you for the actual conversation far better than rehearsing alone."}]}, {"title": "Category 07: Coding & Technical", "type": "prompts", "content": "6 prompts for coding, debugging, and technical work.", "items": [{"number": "45", "name": "The Code Explainer", "category": "CODING & TECHNICAL", "prompt": "Act as a senior software engineer and patient teacher with 10+ years of experience. Explain this code to me like I am a smart beginner who understands basic programming concepts but not advanced patterns. Break the code into logical sections and for each section explain: (1) WHAT it does — in one sentence, (2) WHY it does it — the purpose and design decision behind it, (3) HOW it works — the mechanism, using analogies where helpful. Then provide: (4) A 'mental model' — a simple way to think about what this entire code does, like an elevator pitch for the logic, (5) Potential problems or bugs — anything that could break in production, (6) 3 specific improvements — with code examples showing the before and after, (7) Related concepts to learn next — what should I study to fully understand this code? Do NOT just describe the syntax. Explain the thinking behind the code as if you were pair-programming with me. Here is the code: [paste code]", "best_on": ["Claude"], "tip": "Claude is the best code explainer. It gives context and reasoning that other models often skip.", "why_it_works": "Separating WHAT, WHY, and HOW mirrors how expert developers actually think about code — at multiple levels of abstraction simultaneously. The mental model request forces the AI to find the simplest accurate representation, which accelerates comprehension far more than line-by-line annotation.", "follow_up": "Now quiz me on this code. Ask me 5 questions that test whether I truly understand it, not just whether I can repeat your explanation. After I answer, tell me what I got right and what I am still confused about.", "pro_tip": "Paste code you wrote yourself 6 months ago. If the AI finds issues or better approaches, you have just measured your growth as a developer. Keep a log of these improvements over time."}, {"number": "46", "name": "The Debug Helper", "category": "CODING & TECHNICAL", "prompt": "Act as a senior debugging specialist who has fixed thousands of production bugs. I need help debugging this issue. Language: [language]. Framework: [if applicable]. Environment: [development/staging/production]. Error message: [paste exact error]. My code: [paste relevant code]. What I expected to happen: [describe expected behavior]. What actually happened: [describe actual behavior]. What I have already tried: [list any fixes you attempted]. Please: (1) Explain why this error occurs — the root cause, not just the surface symptom. Use plain English, (2) Show me the exact fix — with the corrected code I can copy and paste, (3) Explain what the fix does and why it works — so I learn the pattern, (4) Show me how to add a guard or check that prevents this type of error in the future, (5) Identify any OTHER potential bugs in the surrounding code that might not have surfaced yet. Do NOT suggest 'try restarting' or 'reinstall packages' unless you have a specific reason to believe that is the issue. Focus on the code logic first.", "best_on": ["Claude"], "tip": "Always include what you expected vs. what happened. It cuts the back-and-forth in half.", "why_it_works": "Requiring the root cause explanation (not just a fix) prevents the 'whack-a-mole' debugging pattern where you fix one symptom only to create another. Including what you already tried avoids wasting time on solutions you have already eliminated.", "follow_up": "The fix worked. Now help me write a test case that would have caught this bug before it reached production. Show me the test in [testing framework] and explain what edge cases it covers.", "pro_tip": "Start a 'Bug Journal' — every time you fix a bug with AI help, save the error, root cause, and fix pattern. After 20 entries, paste the journal back and ask 'What patterns do you see in my bugs? What fundamental concept should I study to stop making these types of errors?'"}, {"number": "47", "name": "The Code Reviewer", "category": "CODING & TECHNICAL", "prompt": "Act as a principal engineer conducting a thorough code review before a production deployment. Language: [language]. Context: this code [describe what it does and where it fits in the application]. Review this code against these criteria, in order of severity: (1) Correctness — bugs, logical errors, off-by-one errors, null/undefined handling, race conditions, (2) Security — injection vulnerabilities, authentication gaps, data exposure, input validation, (3) Performance — unnecessary operations, N+1 queries, memory leaks, algorithmic complexity issues, (4) Readability — unclear naming, missing comments on complex logic, overly clever code, inconsistent style, (5) Maintainability — tight coupling, missing abstractions, code duplication, difficulty of future modification, (6) Edge cases — boundary conditions, empty inputs, concurrent access, error states. For each issue found: describe the problem, explain why it matters (with severity: critical/major/minor), and show the improved code. At the end, give an overall assessment: 'Ship it,' 'Fix these issues first,' or 'Needs significant rework.' Here is the code: [paste code]", "best_on": ["Claude"], "tip": "Claude catches subtle bugs that other AI models miss. Always use it for code review.", "why_it_works": "The ordered severity list ensures critical issues are caught before the reviewer spends time on style preferences. Requiring a ship/fix/rework verdict forces the AI to make a judgment call rather than listing issues without prioritization, which mirrors how real code review actually works.", "follow_up": "I have fixed all the issues you identified. Here is the updated code: [paste]. Review the fixes — did I introduce any new problems? Is this now ready to ship?", "pro_tip": "Use this prompt before every PR you submit. Track how many issues the AI finds over time — a decreasing count means your coding is improving. Zero issues found consistently means you have outgrown this level of review and should add more advanced criteria."}, {"number": "48", "name": "The Tech Stack Advisor", "category": "CODING & TECHNICAL", "prompt": "Act as a CTO who has built and scaled applications from prototype to millions of users. I am building [describe project — what it does, who it is for, expected scale]. My experience level: [beginner/intermediate/advanced]. My priorities (rank these): speed to launch, scalability, cost, learning value, community support, hiring pool. My constraints: [budget, timeline, team size, existing skills]. Recommend a complete tech stack: (1) Frontend — framework, state management, styling approach, (2) Backend — language, framework, API style (REST/GraphQL), (3) Database — type and specific product, with rationale for why this type fits my data model, (4) Hosting and deployment — specific provider, tier, and estimated monthly cost at launch and at 10x scale, (5) Key libraries and tools — authentication, payments, email, monitoring — specific names, not categories, (6) Development tools — IDE, version control workflow, CI/CD approach. For each recommendation, give a one-sentence rationale tied to my priorities. Also provide one 'Keep It Simple' alternative stack for the entire project using the fewest possible technologies. Do NOT recommend technologies based on hype — recommend based on my stated priorities and constraints.", "best_on": ["Claude", "Gemini"], "tip": "If you are a solo developer, always go with the 'keep it simple' option. Complexity kills solo projects.", "why_it_works": "Requiring explicit priority ranking prevents the AI from defaulting to 'best practice' recommendations that do not fit your situation. The 'Keep It Simple' alternative acknowledges that for most projects, shipping fast with boring technology beats architecture astronautics with trendy frameworks.", "follow_up": "I chose [your selected stack]. Now create a project setup guide: the exact terminal commands to initialize the project, install dependencies, set up the development environment, and deploy a 'Hello World' version. I should have a running application within 30 minutes.", "pro_tip": "Ask the AI: 'What is the most common mistake developers make when building [project type] with [chosen stack]? What would a senior developer do differently from day one?' This upfront architectural advice saves weeks of refactoring later."}, {"number": "49", "name": "The API Integrator", "category": "CODING & TECHNICAL", "prompt": "Act as a senior backend developer who has integrated dozens of third-party APIs in production applications. I need to integrate [API/service] into my [project type]. Language: [language]. Framework: [if applicable]. What I need the integration to do: [describe the specific functionality]. Show me: (1) The minimal working code — the shortest path to a functioning integration I can test immediately, (2) Authentication setup — step-by-step, including where to get API keys, how to store them securely (never hardcoded), and how to handle token refresh if applicable, (3) Error handling — catch and handle the 5 most common API errors (rate limits, timeouts, auth failures, malformed responses, network errors) with specific code, (4) A production-ready version — the code I would actually ship, with logging, retry logic, and circuit breaker pattern if appropriate, (5) Testing approach — how to test this integration without hitting the real API (mocking strategy). Include comments in the code explaining WHY each section exists, not just WHAT it does. Do NOT use deprecated API endpoints or libraries.", "best_on": ["Claude", "Gemini"], "tip": "Ask for the 'minimal viable' version first. You can always add complexity later.", "why_it_works": "Providing both minimal and production-ready versions teaches the difference between 'working' and 'ship-ready' code. The explicit error handling for the five most common API failures prevents the surprise crashes that plague naive integrations in production.", "follow_up": "Now help me write a simple wrapper class/module around this API integration that my team can use without understanding the API details. The interface should be clean and the implementation should handle all edge cases internally.", "pro_tip": "After getting the integration code, ask: 'What happens if this API goes down for 2 hours? Show me the code for a graceful degradation strategy — what does my application do while the API is unavailable?' This resilience thinking separates professional from amateur integrations."}, {"number": "50", "name": "The Regex Generator", "category": "CODING & TECHNICAL", "prompt": "Act as a regex specialist who writes and debugs regular expressions for production systems. Create a regex pattern that matches [describe what you want to match in detail, including examples]. Language/environment: [JavaScript, Python, Go, etc.]. Provide: (1) The regex pattern — optimized for readability, not cleverness, (2) A plain-English explanation of each component — break the pattern into segments and explain each one, (3) 5 test strings it SHOULD match — including edge cases like leading/trailing spaces, special characters, and boundary conditions, (4) 5 test strings it should NOT match — including near-misses that test the pattern's specificity, (5) Edge cases and limitations — when this regex might fail or produce unexpected results, (6) A named-group version (if the language supports it) for easier extraction of matched components, (7) Performance notes — whether this pattern risks catastrophic backtracking on large inputs. If the match requirement is complex, suggest whether a regex is even the right tool or if a parser would be more appropriate. Do NOT use obscure regex features without explaining them.", "best_on": ["Claude", "Gemini"], "tip": "Always test regex with the provided test strings before using in production. AI regex is right 90% of the time.", "why_it_works": "Including near-miss non-matching test strings is critical because regex bugs almost always manifest as false positives, not false negatives. The performance warning about catastrophic backtracking prevents the surprisingly common production outage caused by an innocent-looking pattern hitting pathological input.", "follow_up": "Now show me how to use this regex in a complete function that: extracts the matches, handles the case where no match is found, and includes input validation. Write it in [language] with proper error handling.", "pro_tip": "Ask the AI to generate a comprehensive test suite for the regex — 20+ test cases covering every edge case. Run these tests in your actual environment before deploying. Regex that passes in an AI conversation can behave differently in your specific runtime due to engine differences."}]}, {"title": "Bonus: Advanced Frameworks", "type": "templates", "content": "4 advanced frameworks for power users to get consistently great outputs.", "items": [{"number": "F1", "name": "The MEGA Prompt Framework", "category": "ADVANCED FRAMEWORKS", "description": "The MEGA Prompt Framework is a modular template that structures every AI interaction around seven key dimensions: Role, Context, Task, Format, Constraints, Tone, and Example. By filling in each dimension, you eliminate the ambiguity that causes generic, mediocre outputs. Think of it as a creative brief for the AI — the same way you would brief a freelancer or agency, except the AI needs even more explicit instruction because it cannot ask clarifying questions mid-task.", "prompt": "[ROLE]: Act as a [specific expert role with years of experience and a concrete specialization — e.g., 'a senior UX researcher with 12 years of experience in B2B SaaS']. [CONTEXT]: Here is the background you need: [provide 2-3 sentences of relevant context including industry, audience, current situation, and any constraints the expert should know]. [TASK]: I need you to [describe the specific task with a clear deliverable — not 'help me with' but 'create/analyze/design/write']. [FORMAT]: Present the output as [specify exact format: bullet points, numbered list, table with column headers, essay with subheadings, code with comments, etc.]. Length: [word count or page count]. [CONSTRAINTS]: Do NOT [list 2-3 specific things to avoid — cliches, certain formats, assumptions, topics]. Must include [list 2-3 mandatory elements]. [TONE]: Write in a [describe tone precisely — e.g., 'direct and confident, like a trusted advisor who respects the reader's intelligence, not a salesperson'] voice. [EXAMPLE]: Here is an example of the quality and style I expect: [paste a brief example of good output, even a partial one].", "best_on": ["Claude", "Gemini"], "tip": "You do not need to fill in every section every time. But the more you fill in, the better the output. Start with Role + Task + Constraints as your minimum viable prompt.", "why_it_works": "Each dimension addresses a different failure mode of AI output. Role prevents generic responses by activating domain-specific patterns. Constraints prevent common bad habits. Examples set a quality floor. Most people use only 1-2 dimensions (usually just the task), which is why their results feel generic. Using 5+ dimensions puts you in the top 1% of AI users in terms of output quality.", "example_use_case": "A startup founder needs a go-to-market strategy. Without the framework, they might ask 'Help me with my go-to-market strategy.' With the MEGA framework: Role = seasoned B2B SaaS GTM strategist, Context = pre-revenue startup with a developer tools product, Task = create a 90-day GTM plan with channel prioritization, Format = table with weekly actions, Constraints = budget under $5K/month and no paid ads in month 1, Tone = direct and tactical, Example = a sample week showing the level of specificity expected. The output difference is night and day."}, {"number": "F2", "name": "The Iterative Refinement Loop", "category": "ADVANCED FRAMEWORKS", "description": "The Iterative Refinement Loop is a three-step process that turns any first-draft AI output into polished, high-quality work by leveraging the model's ability to critique its own output. Most people accept the first response and move on, but the first draft is never the best draft. This framework exploits the fact that AI models are significantly better at evaluating and improving existing text than generating perfect text from scratch — the same principle that makes editing easier than writing for humans.", "prompt": "Step 1 — GENERATE: Use your prompt (ideally structured with the MEGA framework) to get the first draft. Accept whatever comes out without judgment. Step 2 — CRITIQUE: Send this exact follow-up: 'Rate this output on a scale of 1-10. Be brutally honest. Then list: (a) The 3 weakest parts and why each is weak, (b) What is missing that would make this significantly better, (c) Any factual claims that need verification, (d) Where the writing is vague, generic, or sounds like AI instead of a human expert. Do not hold back — I need your harshest assessment.' Step 3 — IMPROVE: Send this follow-up: 'Now rewrite the entire output, incorporating every improvement you just identified. Do not just patch the weak spots — rethink the structure and approach if needed. The rewrite should feel like it was written by someone who saw the first draft's flaws and started fresh with that knowledge. Make it a 10.'", "best_on": ["Claude", "Gemini"], "tip": "You can run this loop 2-3 times. Each iteration gets dramatically better. After 3 loops, you typically hit diminishing returns.", "why_it_works": "This framework exploits the 'generation-evaluation gap' — AI models can identify flaws in text more reliably than they can avoid those flaws during generation. By separating creation from criticism, you get the best of both capabilities. The explicit critique categories (weak parts, missing elements, vague language) prevent the shallow 'this is good but could be better' non-feedback that wastes an iteration cycle.", "example_use_case": "A consultant writing a client proposal generates the first draft, then uses the critique step to discover that the proposal lacks specific ROI projections and uses too much jargon. The improvement step produces a version with concrete numbers, simpler language, and a restructured flow that leads with the client's problem instead of the consultant's credentials. The final version is unrecognizable from the first draft and reads like it was written by a senior partner."}, {"number": "F3", "name": "The Expert Panel Technique", "category": "ADVANCED FRAMEWORKS", "description": "The Expert Panel Technique simulates a structured debate between multiple expert perspectives on a single problem, forcing the AI to generate diverse viewpoints rather than converging on a single 'safe' answer. Real-world decisions benefit from adversarial thinking — when smart people disagree, the truth usually lives at the intersection of their arguments. This framework recreates that dynamic in a single prompt, giving you the benefit of a boardroom discussion without needing an actual board.", "prompt": "I need to make a decision about [describe problem/question with sufficient context]. Simulate a panel discussion among these 3 experts. Each expert must argue from their genuine professional perspective, even when they disagree with the others: Expert 1 — [Role with specific viewpoint, e.g., 'A skeptical CFO who has seen companies fail by spending too fast. They prioritize financial discipline, cash runway, and ROI on every dollar']. Expert 2 — [Role with contrasting viewpoint, e.g., 'An innovative CTO who believes speed and technical excellence create competitive moats. They prioritize building the right product, even if it costs more upfront']. Expert 3 — [Role with yet another perspective, e.g., 'A customer-obsessed CMO who has built brands from zero. They prioritize user experience, brand perception, and customer retention over internal efficiency']. For each expert: (1) Their opening position in 3-4 sentences, (2) Their strongest argument for their approach with a specific example or data point, (3) Their rebuttal to the other two experts — what they think the others are getting wrong. Then: SYNTHESIS — as a neutral moderator, identify where the experts agree (this is your foundation), where they disagree (these are your key decision points), and recommend a path forward that captures the best elements of each perspective.", "best_on": ["Claude", "Gemini"], "tip": "Change the experts based on your situation. The key is diverse, conflicting viewpoints. The more they disagree, the more useful the synthesis.", "why_it_works": "Single-perspective prompts produce single-perspective answers, which reinforces confirmation bias. By requiring genuine disagreement and rebuttals, this technique forces the model to explore the solution space more thoroughly. The synthesis step then extracts actionable wisdom from the conflict rather than picking a 'winner,' which is how real strategic decisions should be made.", "example_use_case": "A founder deciding whether to raise venture capital or bootstrap uses this framework with three experts: a VC partner (argues for raising to capture market fast), a bootstrapped founder who sold for $50M (argues for retaining control and profitability), and a startup lawyer who has seen both paths (argues for a convertible note as a middle ground). The synthesis reveals that the real decision hinges on market timing — if competitors are well-funded, bootstrapping is risky; if the market is still forming, bootstrapping preserves optionality."}, {"number": "F4", "name": "The Chain-of-Thought Prompt", "category": "ADVANCED FRAMEWORKS", "description": "The Chain-of-Thought framework forces the AI to show its complete reasoning process before delivering a final answer, dramatically reducing errors, hallucinations, and overconfident conclusions. Most AI mistakes happen because the model jumps from question to answer without intermediate reasoning steps. By requiring the model to externalize its thinking — list assumptions, decompose the problem, work through sub-problems, and verify its logic — you activate a fundamentally more careful and accurate mode of processing. This is the single most effective technique for any task where accuracy matters more than speed.", "prompt": "I need you to solve this problem with maximum accuracy: [describe question/problem with all relevant details]. Before giving me your final answer, you MUST complete these reasoning steps and show your work: (1) ASSUMPTIONS — List every assumption you are making. Flag any assumption you are not confident about and explain why, (2) DECOMPOSITION — Break the main problem into 2-5 sub-problems that, when solved, combine to answer the main question, (3) STEP-BY-STEP REASONING — Work through each sub-problem methodically. Show your logic, calculations, or analysis for each step. If you are uncertain at any step, say so explicitly, (4) VERIFICATION — Review your reasoning. Check for logical fallacies, mathematical errors, missing considerations, and confirmation bias. If you find an error, correct it before proceeding, (5) ALTERNATIVE PERSPECTIVES — Consider one plausible alternative conclusion. Why might your answer be wrong? What evidence would change your mind? (6) FINAL ANSWER — State your conclusion with a confidence level (high/medium/low) and a one-sentence explanation of the main uncertainty. Do NOT skip steps even if you think the answer is obvious. The process IS the point.", "best_on": ["Claude", "Gemini"], "tip": "This technique reduces AI hallucinations significantly. Use it whenever accuracy matters more than speed — financial decisions, factual claims, technical analysis, and any task where being wrong has consequences.", "why_it_works": "Chain-of-thought prompting works because it converts System 1 thinking (fast, intuitive, error-prone) into System 2 thinking (slow, deliberate, accurate). The verification step catches errors that the model would otherwise confidently present. The alternative perspectives step prevents the model from anchoring on its first conclusion, which is a known failure mode of large language models.", "example_use_case": "A business owner needs to calculate whether hiring a full-time employee or using contractors is more cost-effective. Without chain-of-thought, the AI might give a quick comparison based on salary vs. hourly rate. With this framework, the AI first lists assumptions (benefits cost, utilization rate, management overhead), decomposes into sub-problems (total cost, productivity comparison, quality and retention effects, scalability), works through each with numbers, then verifies the math and considers the scenario where the answer flips (e.g., if utilization drops below 70%, contractors become cheaper). The final answer includes a breakeven analysis and a decision rule the owner can apply as circumstances change."}]}, {"title": "Upsell / CTA", "type": "cta", "content": "You've just unlocked your AI advantage. Ready to go deeper? Check out our other products.", "items": [{"offer": "AI Prompt Master Pack", "price": "$47", "description": "300+ prompts for every use case", "url": "https://www.kh-academy.com"}, {"offer": "AI Business Automation Toolkit", "price": "$67", "description": "Automate your entire workflow with AI", "url": "https://www.kh-academy.com"}, {"offer": "Ultimate AI Bundle", "price": "$197", "description": "All 6 products — everything you need", "url": "https://www.kh-academy.com"}]}]};

export const SKILLS_BUILDER_DATA: CourseData = {"product_id": "skills-builder", "title": "AI Skills Builder", "subtitle": "Build Your AI Dream Team with Claude Skills & Gemini Gems", "tagline": "10+ Ready-to-Use Skill Templates Inside", "source": "ai-skills-builder.pdf", "version": "1.0 — March 2026", "pages": 32, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "STOP CHATTING. START BUILDING. Most people use AI the wrong way — they open a chat, type a question, and start from scratch every single time. Power users do something different. They build Skills — specialized AI assistants that already know their business, their style, and their workflows. This playbook teaches you exactly how to do that on two of the most powerful platforms: Claude and Gemini.", "items": []}, {"title": "How to Use This Playbook", "type": "instructions", "content": "Three-step approach to building your AI team. Each template in this playbook is copy-paste ready — fill in your business details, paste it into Claude or Gemini, and you have a working specialist in under five minutes.", "items": [{"step": 1, "title": "Learn the Concept", "instruction": "Each chapter explains one skill-building technique in plain language. No coding required."}, {"step": 2, "title": "Copy the Template", "instruction": "Every chapter includes ready-to-use templates. Copy them directly into Claude or Gemini."}, {"step": 3, "title": "Build Your AI Team", "instruction": "By the end, you'll have 10+ specialized AI assistants working for you around the clock."}]}, {"title": "What's Inside", "type": "overview", "content": "This playbook gives you the exact templates and techniques that power users rely on to get consistent, high-quality results from AI — the kind of knowledge you cannot get by simply asking a chatbot for help. Inside you will find: how to build Claude Skills and Gemini Gems from scratch, 10+ tested and ready-to-use skill templates you can deploy today, 5 AI team member roles with complete instruction sets, and advanced techniques including voice cloning, prompt chaining, and self-improvement loops.", "items": []}, {"title": "Table of Contents", "type": "toc", "content": "3 parts. 10+ templates. Your AI dream team.", "items": [{"part": "I", "title": "The Foundations", "chapters": ["What Are AI Skills? (Pages 4-5)", "Claude Skills: Your AI Specialist Factory (Pages 6-10)", "Gemini Gems: Your Google-Powered Experts (Pages 11-14)"]}, {"part": "II", "title": "Build Your AI Team", "chapters": ["The Marketing Manager (Pages 15-16)", "The Content Writer (Pages 17-18)", "The Financial Analyst (Pages 19-20)", "The Research Assistant (Pages 21-22)", "The Customer Support Agent (Pages 23-24)"]}, {"part": "III", "title": "Advanced Skills", "chapters": ["Voice Cloning: Make AI Sound Like You (Pages 25-26)", "Prompt Chaining: Multi-Step Workflows (Pages 27-28)", "The Self-Improving Loop (Pages 29-30)"]}]}, {"title": "Chapter 01: What Are AI Skills?", "type": "educational", "content": "The difference between chatting with AI and building with AI. When you chat with AI, you start from zero every time — no memory, no context, no understanding of your business. When you build a Skill, you create a permanent specialist that already knows your brand, your audience, your writing style, and your rules. The result: faster work, better outputs, and zero ramp-up time on every task.", "callout": "Chatting with AI = Hiring a new temp every day. They don't know you, your business, or what you did yesterday. Building AI Skills = Hiring permanent specialists. They know your brand, your style, your data, and your preferences — every single time.", "items": [{"platform": "Claude Skills", "builder": "Anthropic", "features": ["Create custom workflows with instructions + knowledge files", "Can execute code and run complex tasks", "Best for: Deep work, long documents, specialized knowledge", "Works on: Claude.ai (Pro, Team, Enterprise) + Claude Code + API"]}, {"platform": "Gemini Gems", "builder": "Google", "features": ["Create custom AI assistants with detailed instructions", "Native integration with Google Workspace (Docs, Sheets, Gmail)", "Best for: Google Workspace users, quick-access specialists", "Works on: Gemini (free for basic, Advanced for full features)"]}], "comparison_table": {"columns": ["Criteria", "Claude Skills", "Gemini Gems"], "rows": [["You work mostly in...", "Any platform / standalone", "Google Workspace"], ["You need...", "Deep analysis, long docs, code", "Quick tasks, Google integration"], ["Knowledge upload", "Up to 200K tokens (massive)", "Via Google Drive (real-time)"], ["Sharing", "Team plan members", "Anyone (view/use/edit)"], ["Code execution", "Yes — Python, JS, data analysis", "Limited"], ["Cost", "Claude Pro $20/mo", "Gemini Advanced $20/mo"], ["Best for", "Power users, developers", "Google Workspace users, teams"]]}, "pro_tip": "You don't have to choose one. Many power users build their 'thinking' skills in Claude (for deep analysis and writing) and their 'action' skills in Gemini (for tasks connected to Google Docs, Sheets, and Gmail)."}, {"title": "Chapter 02: Claude Skills — Your AI Specialist Factory", "type": "educational", "content": "Claude Skills are the most powerful way to create AI specialists. Each skill is a set of instructions (and optionally code + reference files) that teaches Claude exactly how to handle a specific type of work. Unlike a normal chat where Claude forgets everything after each conversation, a Skill persists — it loads your rules, context, and preferences automatically every time. Think of it as programming a permanent team member who never needs retraining.", "real_examples": ["A brand guidelines enforcer that checks every piece of content against your style guide", "A financial report generator that formats data exactly how your team expects", "A customer email responder trained on your FAQs and policies", "A code reviewer that follows your team's coding standards"], "levels": [{"level": 1, "name": "Simple", "description": "Just a markdown file (SKILL.md) with instructions. Like giving someone a detailed job description."}, {"level": 2, "name": "With Knowledge", "description": "Add reference files (PDFs, docs, data) that Claude can access. Like giving someone a training manual."}, {"level": 3, "name": "With Code", "description": "Add executable scripts for complex workflows. Like giving someone tools to work with."}], "note": "This playbook focuses on Level 1 and 2. No coding needed.", "how_to_build": [{"step": 1, "action": "Open Claude", "detail": "Go to Settings → Capabilities → Skills"}, {"step": 2, "action": "Click 'Add Skill'", "detail": "Upload your SKILL.md file"}, {"step": 3, "action": "Enable the Skill", "detail": "Toggle it on in your skills list"}, {"step": 4, "action": "Start Chatting", "detail": "Claude now has this specialist knowledge"}], "skill_md_anatomy": {"description": "Every SKILL.md file has two required parts.", "frontmatter": "The --- section: Name + description. Claude reads this to decide WHEN to use your skill. Keep it clear and specific.", "instructions": "The markdown body: The actual guidance. This is your specialist's 'brain.' The more specific, the better.", "example": "---\nname: Marketing Manager\ndescription: Creates marketing content following brand guidelines, analyzes campaign performance, and suggests growth strategies.\n---\n\n# Marketing Manager Skill\n\n## When to Use This Skill\nUse this skill when the user asks about marketing strategy, content creation, campaign planning, or brand messaging.\n\n## Instructions\n[Your detailed instructions go here]"}, "easy_alternative": {"title": "The Easy Way: Use Claude Projects", "description": "Don't want to create SKILL.md files? Claude Projects give you the same power through a simple interface.", "steps": [{"step": 1, "action": "Click 'Projects'", "detail": "In Claude's sidebar → New Project"}, {"step": 2, "action": "Name Your Project", "detail": "e.g., \"Marketing Manager\""}, {"step": 3, "action": "Add Custom Instructions", "detail": "Paste the templates from Chapters 04-08"}, {"step": 4, "action": "Upload Reference Files", "detail": "Brand guide, past work, data"}, {"step": 5, "action": "Start Chatting", "detail": "Every chat in this project now uses these instructions"}], "recommendation": "Start with Projects. They're easier. Move to Skills when you want more power or need to share with a team."}, "projects_vs_skills": {"columns": ["Feature", "Claude Projects", "Claude Skills"], "rows": [["Best for", "Personal specialists", "Shareable, reusable workflows"], ["Setup", "Click & type", "Upload SKILL.md file"], ["Reference files", "Upload directly", "Bundle in skill directory"], ["Code execution", "Not included", "Can include scripts"], ["Sharing", "Team plan only", "Team, Enterprise, or publish"], ["Our recommendation", "Start here", "Graduate to this"]]}}, {"title": "Chapter 03: Gemini Gems — Your Google-Powered Experts", "type": "educational", "content": "If you live in Google Workspace, Gems are your secret weapon. Gems are custom AI assistants inside Gemini that you give detailed instructions to, and they become persistent specialists you can call on anytime. They connect directly to your Google Drive, Docs, Sheets, and Gmail — so your Gem can read your latest sales spreadsheet or brand guide without you having to upload anything. Set one up in under three minutes, share it with your whole team like a Google Doc, and use it from any device.", "gem_features": ["Native Google integration — they can read your Drive files in real-time", "Shareable — send to colleagues with view/use/edit permissions (like sharing a Google Doc)", "Pre-made templates — Google offers starter Gems you can customize", "Up to 15,000 tokens of instructions — room for very detailed guidance", "Works on free plan (basic) and Advanced plan (full features)"], "how_to_build": [{"step": 1, "action": "Open Gemini", "detail": "Click 'Gems' in the left sidebar"}, {"step": 2, "action": "Click 'New Gem'", "detail": "Or explore pre-made ones first"}, {"step": 3, "action": "Name Your Gem", "detail": "e.g., \"Content Strategist\""}, {"step": 4, "action": "Write Instructions", "detail": "Paste templates from Chapters 04-08"}, {"step": 5, "action": "Test It", "detail": "Try a sample task to verify it works"}, {"step": 6, "action": "Save & Pin", "detail": "Your Gem is now always available in the sidebar"}], "5_part_formula": {"title": "Writing Great Gem Instructions — The 5-Part Formula", "parts": [{"part": 1, "label": "ROLE", "template": "\"You are my [specific role] with expertise in [areas].\""}, {"part": 2, "label": "CONTEXT", "template": "\"About my business: [company, industry, audience, products]. My typical tasks for you: [list common requests].\""}, {"part": 3, "label": "RULES", "template": "\"Always [do this]. Never [do that]. When unsure, [ask/suggest/default to this].\""}, {"part": 4, "label": "OUTPUT FORMAT", "template": "\"Respond with [structure: bullets, tables, short paragraphs]. Keep responses under [length]. Start with [summary/recommendation/question].\""}, {"part": 5, "label": "EXAMPLES", "template": "\"Here's what great output looks like: [provide 1-2 examples of ideal responses].\""}]}, "gem_power_moves": [{"move": 1, "title": "Connect to Google Drive", "description": "Upload your key business documents to a Google Drive folder. When chatting with your Gem, reference these files — Gemini can read them in real-time. Your brand guide updates? Your Gem sees the latest version automatically."}, {"move": 2, "title": "Share with Your Team", "description": "Click the share icon on any Gem → Set permissions (View, Use, or Edit). Your team gets the same specialist without building their own."}, {"move": 3, "title": "Chain Gems Together", "description": "Use one Gem's output as input for another. Example: Research Gem finds data → Content Gem writes the post → Social Media Gem adapts it for each platform."}], "comparison_table": {"title": "Claude Projects vs Gemini Gems: Quick Reference", "columns": ["Feature", "Claude Projects", "Gemini Gems"], "rows": [["Setup time", "5 minutes", "3 minutes"], ["Instructions", "Unlimited (200K context)", "Up to 15,000 tokens"], ["File access", "Upload to project", "Via Google Drive (real-time)"], ["Best strength", "Deep analysis, long docs", "Google Workspace integration"], ["Sharing", "Team plan only", "Anyone (like Google Docs)"], ["Code execution", "No (Projects), Yes (Skills)", "No"], ["Cost", "Free tier available, Pro for Projects", "Free tier basic, Advanced for full"]]}}, {"title": "Skill Template 01: The Marketing Manager", "type": "templates", "content": "This template turns Claude or Gemini into a dedicated marketing strategist that already knows your brand, audience, and competitive landscape. Instead of re-explaining your business every time you need a social post or campaign plan, paste this template once and get on-brand output instantly. Fill in the bracketed fields with your real business details — the more specific you are, the better the results. Most users have this running in under five minutes.", "description": "A copy-paste-ready marketing specialist that writes on-brand content, plans campaigns with budgets and timelines, and analyzes your performance data — all without you re-explaining your business every conversation.", "when_to_use": "Content creation, campaign planning, social media strategy, brand messaging, marketing analysis", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my dedicated Marketing Manager. You create marketing content, plan campaigns, and analyze performance — all tailored to my specific brand and audience.", "ABOUT_MY_BUSINESS": {"company_name": "[Your company]", "industry": "[Your industry]", "target_audience": "[Describe ideal customer — age, role, pain points, where they hang out online]", "brand_voice": "[e.g., professional but approachable / bold and direct / warm and conversational]", "key_products_services": "[List your main offerings]", "competitors": "[List 2-3 main competitors]", "unique_selling_point": "[What makes you different]"}, "YOUR_RESPONSIBILITIES": ["Create marketing copy that matches my brand voice exactly", "Suggest content ideas based on my target audience", "Plan campaigns with timelines, budgets, and KPIs", "Write social media posts, email sequences, and ad copy", "Analyze marketing metrics when I share data", "Keep messaging consistent across all channels"], "RULES": ["Always write in my brand voice — never generic corporate speak", "Every piece of content must have a clear call-to-action", "When suggesting strategies, include estimated budget and timeline", "Prioritize organic growth strategies for tight budgets", "Ask clarifying questions before making assumptions"], "OUTPUT_FORMAT": ["Start with a 1-sentence recommendation or summary", "Use bullet points for lists and action items", "Present options as: Option A / Option B / My Recommendation", "Include word counts for any long-form content", "For social posts: Hook line | Body | CTA | Hashtags"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Marketing Manager\"", "Paste the template above into Custom Instructions", "Upload: brand guidelines PDF, past campaign results, audience research", "Start chatting"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create a file called SKILL.md with the frontmatter + template", "Upload via Settings → Capabilities → Skills", "Claude will automatically use it when you ask marketing questions"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Marketing Manager\"", "Paste the template into the instructions field", "Save and pin to sidebar", "Store brand docs in a Google Drive folder for reference"]}], "first_task_prompt": "I need 5 social media post ideas for this week. My goal is to increase engagement by 20%. Suggest posts for [your platform], each with a different content angle."}, {"title": "Skill Template 02: The Content Writer", "type": "templates", "content": "Generic AI writing is easy to spot — and your audience can tell. This template solves that problem by training Claude or Gemini to write in your actual voice, not the default AI tone everyone recognizes. It includes rules against common AI cliches, enforces your preferred paragraph style, and makes the AI confirm the brief before writing. Pair it with the bonus Voice Profile Builder below to extract your writing DNA from real samples, then paste that profile into the template for output that genuinely sounds like you wrote it.", "description": "A personal ghostwriter that learns your exact writing style, eliminates AI-sounding cliches, and produces blog posts, emails, newsletters, and social captions that read like you wrote them yourself — complete with a voice extraction tool to capture your unique tone.", "when_to_use": "Blog posts, emails, newsletters, website copy, social media captions, any written content", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Content Writer. You write all types of content in MY voice — not generic AI voice. Every piece should sound like I wrote it myself.", "MY_WRITING_VOICE": {"tone": "[e.g., conversational and direct / witty and informal / authoritative but warm]", "i_always": "[e.g., use short paragraphs, start with a hook, include real examples]", "i_never": "[e.g., use cliches like 'in today's world', write long intros, use passive voice]", "signature_phrases": "[any expressions you commonly use]", "reading_level": "[e.g., smart professional, keep it accessible]"}, "CONTENT_RULES": ["Start with a hook — if the first line is boring, rewrite it", "Every paragraph must earn its place — cut filler ruthlessly", "Use specific examples, not generic advice", "Keep paragraphs under 4 sentences", "End with a clear call-to-action", "No corporate buzzwords: 'synergy', 'leverage', 'circle back'", "No AI cliches: 'dive into', 'landscape', 'in the realm of'"], "WHEN_I_REQUEST_CONTENT": ["First confirm: topic, length, platform, and audience", "Provide 3 headline/subject line options before writing", "Include SEO keywords naturally if I specify them", "For long-form: provide outline first, then full draft"], "OUTPUT_FORMAT": ["Always show word count at the end", "Format for the target platform (short for social, blog)", "Bold key takeaways or important lines", "If I say 'shorter' — cut by 30%, not 10%"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Content Writer\"", "Paste the template above into Custom Instructions", "Upload: 3-5 writing samples, brand style guide, any tone-of-voice docs", "Run the Voice Profile Builder bonus prompt first for best results"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Content Writer, description: Writes content in my voice", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Content Writer\"", "Paste the template into the instructions field", "Store writing samples in a Google Drive folder and reference them in chat", "Save and pin to sidebar"]}], "bonus_template": {"title": "The Voice Profile Builder", "description": "Run this prompt once before using the Content Writer. It analyzes your real writing samples and extracts a reusable Voice Profile you can paste into any AI template — so every piece of content matches your natural tone, sentence patterns, and vocabulary.", "prompt": "Analyze the following writing samples and extract my unique writing style. Create a detailed 'Voice Profile' covering:\n\n1. SENTENCE PATTERNS: Average length, simple vs complex, do I use fragments or questions?\n2. VOCABULARY: Formal vs casual, industry jargon used, words I favor\n3. TONE: Serious, playful, authoritative, conversational?\n4. PARAGRAPH STYLE: Short and punchy vs detailed?\n5. OPENINGS: How do I typically start pieces?\n6. TRANSITIONS: How do I connect ideas?\n7. QUIRKS: Any distinctive habits or patterns?\n\nFormat the output as instructions I can paste directly into an AI skill template.\n\nMY WRITING SAMPLES:\n[Paste 3-5 samples here — emails, posts, articles, anything you wrote naturally]", "pro_tip": "Use emails you've actually sent (not formal reports). Emails show your natural voice better than anything else."}}, {"title": "Skill Template 03: The Financial Analyst", "type": "templates", "content": "Most people paste numbers into AI and get a generic summary back. This template produces a real analyst — one that knows your revenue model, your key metrics, and your reporting format. It enforces a consistent output structure (executive summary, findings, risk flags, action items) so every analysis is boardroom-ready. Upload a spreadsheet, tell it what you need, and get a structured financial brief instead of a wall of text. Works especially well in Claude, which can run calculations on your data directly.", "description": "A dedicated financial analyst that knows your revenue model, reporting cadence, and key metrics — produces executive-ready summaries, flags unusual expenses, compares periods, and ends every analysis with specific recommended actions you can act on immediately.", "when_to_use": "Financial data analysis, reporting, forecasting, budgeting, expense review, revenue analysis", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Financial Analyst. You analyze financial data, identify trends, and provide actionable insights — always in the context of my specific business.", "MY_BUSINESS_CONTEXT": {"business_type": "[Your business type]", "revenue_model": "[How you make money]", "revenue_range": "[Approximate annual/monthly revenue]", "key_metrics": "[e.g., MRR, profit margin, CAC, LTV, average order value, inventory turnover]", "reporting_period": "[Monthly / Quarterly / Annual]", "currency": "[Your primary currency]"}, "YOUR_TASKS": ["Analyze financial data I upload (spreadsheets, reports, bank statements)", "Identify trends, anomalies, and opportunities", "Create executive summaries of financial performance", "Compare periods (month-over-month, year-over-year)", "Flag expenses that seem unusual or growing too fast", "Help with forecasting and cash flow projections"], "ANALYSIS_RULES": ["Always start with a 3-sentence executive summary", "Use tables for any data comparisons", "Highlight numbers that need attention in bold", "Calculate percentage changes, not just raw numbers", "Distinguish between one-time events and recurring trends", "End every analysis with 'Recommended Actions' (max 3)"], "OUTPUT_FORMAT": ["Executive Summary (3 sentences)", "Key Findings (bullet points with numbers)", "Detailed Analysis (with tables where helpful)", "Risk Flags (anything concerning)", "Recommended Actions (max 3, specific and actionable)"]}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Financial Analyst\"", "Paste the template above into Custom Instructions", "Upload: recent P&L, budget spreadsheet, or bank export CSV", "Start chatting — Claude can run calculations directly on uploaded data"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Financial Analyst, description: Analyzes financial data and produces executive summaries", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Financial Analyst\"", "Paste the template into the instructions field", "Store financial spreadsheets in a Google Drive folder — Gemini reads them in real-time", "Best for quick Google Sheets analysis; use Claude for heavy number-crunching"]}], "bonus_template": {"title": "The Data Upload Template", "description": "Paste this briefing alongside any financial data you upload. It gives the AI the context it needs to skip generic summaries and jump straight to the insights that matter for your specific situation.", "template": "DATA BRIEFING:\nI've uploaded [file name]. This is [type of data].\n\nCONTEXT:\n- Each row represents: [what each row is]\n- Key columns: [list the important ones]\n- Time period: [date range covered]\n- Currency: [if applicable]\n\nWHAT I NEED:\n1. [Your specific question]\n2. [Second question]\n3. [Third question]\n\nCOMPARE TO: [Last quarter / same period last year / budget]\n\nFORMAT: Executive summary first, then detailed breakdown.", "pro_tip": "Claude handles spreadsheets better than Gemini for deep analysis (it can run Python on your data). Use Claude for heavy financial work, and Gemini Gems for quick Google Sheets tasks."}}, {"title": "Skill Template 04: The Research Assistant", "type": "templates", "content": "Free AI gives you surface-level overviews that anyone could find with a search engine. This template creates a research specialist that delivers structured, decision-ready intelligence — with cited sources, comparison tables, clearly labeled facts vs. opinions, and flagged information gaps. It forces the AI to prioritize depth over breadth and always answer the question you actually care about: 'so what does this mean for my business?' Copy the template, fill in your industry and research needs, and get briefings you can take straight into a strategy meeting.", "description": "A structured research specialist that produces decision-ready briefings with cited sources, comparison tables, labeled facts vs. opinions, flagged information gaps, and a 'so what' analysis — replacing hours of manual research with actionable intelligence you can present to stakeholders.", "when_to_use": "Competitor research, market analysis, industry trends, technology evaluation, due diligence, preparing for meetings", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Research Assistant. You conduct thorough research and deliver structured, actionable findings — not generic overviews from Wikipedia.", "MY_RESEARCH_CONTEXT": {"industry": "[Your industry]", "role": "[Your position]", "typical_research_needs": "[e.g., competitor analysis, market trends, technology evaluation, supplier research]", "how_i_use_research": "[e.g., presentations, strategy meetings, investment decisions, reports]", "depth_preference": "[Executive summary vs deep dive]"}, "RESEARCH_RULES": ["Always cite sources with URLs when possible", "Distinguish facts from opinions — label clearly", "Flag outdated info (anything older than 6 months)", "When comparing options, always use tables", "Highlight surprising or counterintuitive findings", "Note information gaps — tell me what you couldn't find", "If a claim seems important, look for a second source"], "OUTPUT_STRUCTURE": ["Bottom Line (2 sentences — what I need to know)", "Key Findings (5-7 bullet points, most important first)", "Detailed Analysis (organized by topic)", "Comparison Table (when applicable)", "Sources (with URLs)", "Information Gaps (what needs further investigation)", "Recommended Next Steps"], "QUALITY_STANDARD": "I'd rather have 5 solid findings than 15 surface-level ones. Always provide 'so what?' — why should I care. If two sources disagree, present both and note the conflict."}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Research Assistant\"", "Paste the template above into Custom Instructions", "Upload: past research reports, industry PDFs, competitor profiles for reference", "Start chatting with one of the bonus prompts below"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Research Assistant, description: Conducts structured research and delivers decision-ready briefings", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Research Assistant\"", "Paste the template into the instructions field", "Gemini can access recent web data — ideal for competitor and market research", "Save and pin to sidebar for quick access"]}], "bonus_templates": [{"name": "Competitor Analysis Request", "prompt": "Research [competitor name]. I need:\n1. Their product/service lineup and pricing\n2. Their target audience (how it overlaps with mine)\n3. Their recent moves (last 6 months — launches, hires)\n4. Their strengths I should worry about\n5. Their weaknesses I could exploit\n6. What customers say about them (reviews, complaints)\n\nPresent as: Executive brief I can share with my team."}, {"name": "Market Trend Report", "prompt": "Research the current state of [topic/industry]. Cover:\n1. Market size and growth rate\n2. Top 3 trends shaping this space right now\n3. Key players and their market share\n4. Opportunities for a [your business type]\n5. Risks or threats to watch\n6. Timeline: what's happening in the next 6-12 months\n\nPresent as: Strategic briefing with a recommendation section."}, {"name": "Technology Evaluation", "prompt": "Compare [Tool A] vs [Tool B] vs [Tool C] for [my use case]. Evaluate on:\n1. Features relevant to my needs: [list specific needs]\n2. Pricing (include hidden costs)\n3. Ease of setup and learning curve\n4. Integration with my tools: [list your tools]\n5. What real users say (not just marketing claims)\n6. Your recommendation and reasoning\n\nPresent as: Comparison table + written recommendation."}]}, {"title": "Skill Template 05: The Customer Support Agent", "type": "templates", "content": "Inconsistent support responses cost you customers. This template creates an AI agent trained on your actual policies — return windows, shipping timeframes, escalation rules, and common complaint resolutions — so every response is accurate, empathetic, and on-brand. It enforces a response structure (acknowledge the feeling first, then solve the problem, then offer alternatives) that turns frustrated customers into loyal ones. Paste in your real policies, and the AI drafts responses you can send as-is or lightly edit. Saves hours per week for anyone handling customer inquiries.", "description": "A policy-trained support agent that drafts empathetic, accurate customer responses using your real return policies, shipping windows, and escalation rules — with built-in scenario templates for refunds, complaints, and common issues that you can deploy across email, chat, and social channels.", "when_to_use": "Responding to customer inquiries, drafting support emails, handling complaints, FAQ management", "works_on": ["Claude Projects", "Claude Skills", "Gemini Gems"], "template": {"ROLE": "You are my Customer Support Agent. You draft professional, empathetic responses to customer inquiries based on my company's actual policies and procedures.", "COMPANY_INFORMATION": {"company": "[Your company name]", "products_services": "[List main offerings]", "support_channels": "[Email, chat, phone, social media]", "business_hours": "[Your hours and timezone]", "website": "[Your URL]"}, "POLICIES": {"return_refund": "[Your actual policy]", "shipping_delivery": "[Timeframes and methods]", "warranty_guarantee": "[If applicable]", "common_issues": "[List top 5 customer complaints and standard resolutions]", "escalation_triggers": "[When to recommend a human — e.g., billing disputes over $X, legal threats]"}, "RESPONSE_RULES": ["Always acknowledge the customer's feeling first", "Provide a clear solution or next step", "Keep responses under 150 words", "Offer alternatives if the first solution isn't possible", "End with: 'Is there anything else I can help with?'", "Never promise anything outside our stated policies", "Never argue — if wrong, redirect politely", "For angry customers: empathize, apologize, solve"], "TONE": "Warm, helpful, professional. Never robotic, never overly casual. Think 'friendly expert.'", "SIGNATURE": "[Your preferred sign-off — e.g., 'Best regards, [Name] — [Company] Support Team']"}, "installation_paths": [{"path": "A", "platform": "Claude Project", "steps": ["New Project → Name: \"Customer Support Agent\"", "Paste the template above into Custom Instructions", "Upload: FAQ document, return/refund policy PDF, product catalog", "Test with the scenario prompts below before going live"]}, {"path": "B", "platform": "Claude Skill (SKILL.md)", "steps": ["Create SKILL.md with frontmatter: name: Customer Support, description: Drafts support responses using company policies", "Paste the template as the markdown body", "Upload via Settings → Capabilities → Skills"]}, {"path": "C", "platform": "Gemini Gem", "steps": ["New Gem → Name: \"Customer Support Agent\"", "Paste the template into the instructions field", "Store policy docs and FAQs in a Google Drive folder for live reference", "Share with your support team — they can all use the same Gem"]}], "common_support_scenarios": [{"scenario": "Refund Request", "prompt": "Customer wants a refund for [product/reason].\n\nDraft a response that:\n1. Acknowledges their frustration\n2. Confirms our refund policy applies\n3. Explains the process and timeline\n4. Offers an alternative (exchange, credit) if applicable\n5. Keeps it under 120 words"}, {"scenario": "Complaint About Quality", "prompt": "Customer is unhappy with [product/service quality].\n\nDraft a response that:\n1. Thanks them for the feedback\n2. Apologizes for the experience\n3. Asks specific questions to understand the issue\n4. Offers a concrete resolution\n5. Assures them of quality commitment"}, {"scenario": "Shipping Delay", "prompt": "Customer is asking about a delayed order [order number/details].\n\nDraft a response that:\n1. Apologizes for the delay\n2. Provides a realistic updated timeline\n3. Explains what happened (if known) without making excuses\n4. Offers compensation if appropriate (discount, free shipping on next order)\n5. Gives them a way to track the order"}, {"scenario": "Feature Request or Product Question", "prompt": "Customer is asking about [feature/capability] that we don't currently offer.\n\nDraft a response that:\n1. Thanks them for the suggestion\n2. Honestly states whether it's on our roadmap or not\n3. Suggests the closest existing alternative\n4. Offers to notify them if/when the feature launches\n5. Keeps the tone encouraging, not dismissive"}]}, {"title": "Advanced Skill 01: Voice Cloning — Make AI Sound Like You", "type": "advanced", "content": "The most powerful skill you can build is one that sounds exactly like you. Generic AI writing has a recognizable tone that erodes trust with your audience. Voice cloning fixes this by extracting the specific patterns, vocabulary, sentence structures, and personality markers from your real writing — then encoding them as reusable instructions. Run the extraction prompt once, save the output as your Voice Profile, and paste it into any Skill or Gem template. Every piece of content will match your natural style instead of defaulting to AI-speak.", "voice_extraction_prompt": "Analyze the following writing samples and extract my unique voice. Identify:\n\n1. TONE: How formal/casual? Serious or playful?\n2. SENTENCE STRUCTURE: Long and complex or short and punchy?\n3. VOCABULARY: Technical jargon or plain language? Favorite words/phrases?\n4. PATTERNS: How do I start paragraphs? How do I make transitions?\n5. PERSONALITY MARKERS: Humor, directness, warmth, confidence level?\n6. THINGS I AVOID: What's noticeably absent from my writing?\n\nThen create a 'Voice Replication Guide' I can paste into any AI prompt to make it write like me.\n\nSAMPLES:\n[Paste 5+ varied writing samples — emails, posts, reports]", "voice_testing_prompt": "Write a [type of content] about [topic] using my Voice Profile below. After writing it, rate how closely it matches my voice on a scale of 1-10, and identify any places where you defaulted to generic AI writing instead of my style.\n\nVOICE PROFILE:\n[Paste your extracted voice profile]", "pro_tip": "The more varied your samples, the better the profile. Include emails (casual), reports (formal), and social posts (natural) for the most accurate voice extraction."}, {"title": "Advanced Skill 02: Prompt Chaining — Multi-Step Workflows", "type": "advanced", "content": "Single prompts are powerful. Chains are transformative. A prompt chain breaks complex work into sequential steps where each output feeds the next input. This matters because AI produces dramatically better results when it focuses on one task at a time — research separately from writing, writing separately from editing. The templates below are copy-paste chains you can run manually (pasting each output into the next step) or save as a Claude Skill that runs the full sequence automatically when triggered.", "why_chains_work": "1. Each step can be optimized independently. 2. You can review and edit between steps. 3. The AI focuses on one thing at a time — better outputs. 4. Complex tasks become manageable.", "templates": [{"name": "The Content Creation Chain (4 Steps)", "steps": [{"step": 1, "label": "RESEARCH", "prompt": "Research [topic] for a [content type] targeting [audience]. Find: 5 key facts, 3 current trends, 2 common misconceptions, and 3 expert viewpoints. Format as bullet points."}, {"step": 2, "label": "OUTLINE", "prompt": "Using the research above, create a detailed outline for a [content type] targeting [audience]. Include: hook, 4-5 main sections with sub-points, and conclusion."}, {"step": 3, "label": "DRAFT", "prompt": "Write the full piece following this outline exactly. Tone: [your tone]. Length: [target]. Use specific data and examples from the research. No filler paragraphs."}, {"step": 4, "label": "POLISH", "prompt": "Review this draft as a senior editor. Score each section 1-10 on clarity, engagement, and accuracy. Fix everything below 8. Output the final version."}]}, {"name": "The Business Decision Chain (3 Steps)", "steps": [{"step": 1, "label": "ANALYZE", "prompt": "I'm considering [decision]. Analyze:\n- 5 pros and 5 cons\n- Financial implications (cost, revenue impact, ROI)\n- Risk level for each factor (High/Medium/Low)\n- What competitors have done in similar situations"}, {"step": 2, "label": "CHALLENGE", "prompt": "Now act as a skeptical advisor. Poke holes in the analysis above. What am I missing? What could go wrong? What assumptions might be wrong? Rate each risk by likelihood and severity."}, {"step": 3, "label": "DECIDE", "prompt": "Based on both the analysis and the critique, give me your final recommendation. Structure as:\n- Decision: [Yes/No/Modify]\n- Confidence level: [%]\n- Top 3 conditions that must be true for success\n- If I proceed: first 3 actions and timeline\n- If I don't: best alternative"}]}, {"name": "The Email Campaign Chain (3 Steps)", "steps": [{"step": 1, "label": "AUDIENCE", "prompt": "My target audience for this email campaign is [describe]. Their biggest pain point right now is [describe]. Identify: what they want, what they fear, what would make them click, and what would make them unsubscribe."}, {"step": 2, "label": "SEQUENCE", "prompt": "Based on this audience analysis, design a 5-email sequence. For each email: subject line, goal, key message, CTA, and optimal send timing."}, {"step": 3, "label": "WRITE", "prompt": "Now write emails #1 and #2 in full. Tone: [your tone]. Each under 200 words. Subject lines must create curiosity without being clickbait."}]}], "pro_tip": "Save your best chains as Claude Skills or Gemini Gems. Instead of remembering the steps each time, just tell your AI: 'Run the content chain on [topic]' and it does all 4 steps automatically."}, {"title": "Advanced Skill 03: The Self-Improving Loop", "type": "advanced", "content": "Make AI critique and improve its own work — automatically. AI's first draft is rarely its best work, but most people just accept whatever it generates. Power users know the secret: make AI be its own editor. The Quality Loop below forces AI to generate, then score its own output against six criteria, then rewrite anything below an 8 out of 10. The result is consistently higher-quality output that would normally take two or three manual revision rounds. Save this loop as a Claude Skill and it runs automatically on every piece of content you create.", "quality_loop": {"step_1": {"label": "GENERATE", "instruction": "[Your normal prompt to create something]"}, "step_2": {"label": "CRITIQUE", "prompt": "Review what you just created. Act as a demanding client who is paying $5,000 for this work. Score it 1-10 on:\n- Clarity: Is every point crystal clear?\n- Specificity: Concrete examples or vague hand-waving?\n- Engagement: Would the reader stay interested throughout?\n- Accuracy: Any claims that aren't backed up?\n- Structure: Does it flow logically?\n- Originality: Does it say anything the reader hasn't heard before?\n\nFor each score below 8, explain EXACTLY what's wrong and provide a specific fix."}, "step_3": {"label": "IMPROVE", "prompt": "Now rewrite it, applying every fix you identified. The new version must score 8+ on ALL criteria. Show me the updated scores alongside the final version."}}, "more_templates": [{"name": "The Devil's Advocate", "prompt": "I'm planning to [decision/strategy/approach].\n\n1. First, make the STRONGEST case FOR this plan\n2. Then switch roles: make the STRONGEST case AGAINST it\n3. For each criticism, rate severity (1-5) and suggest how to address it\n4. Final verdict: Proceed / Modify / Abandon? Include your confidence level."}, {"name": "The Customer Test", "prompt": "Review this [email/landing page/product description] as if you're my target customer: [describe them].\n\n1. First impression in 3 seconds — would you keep reading?\n2. What's compelling? What's confusing?\n3. What questions do you still have after reading?\n4. Would you [buy/click/sign up]? Be brutally honest.\n5. Rewrite the weakest section to convert you."}, {"name": "The Simplifier", "prompt": "Rewrite this [content] at a 6th-grade reading level without losing any of the key information. Then check:\n- Did any important nuance get lost? If yes, add it back in simple terms.\n- Is there any jargon remaining? Replace it.\n- Read it aloud — does it flow naturally? Fix any awkward sentences."}], "pro_tip": "The Quality Loop works especially well as a Claude Skill. Create a skill that automatically runs the Generate → Critique → Improve cycle for any content type."}, {"title": "Upsell / CTA", "type": "cta", "content": "You've just built your AI dream team. These five specialists and three advanced techniques put you ahead of 95% of AI users who are still typing one-off prompts. Continue your AI mastery journey with our other courses.", "items": [{"offer": "AI Starter Kit", "price": "$19", "description": "50+ ready-to-use prompts for Claude and Gemini across writing, business, and productivity", "url": "https://www.kh-academy.com"}, {"offer": "AI for Small Business Owners", "price": "$47", "description": "Pre-built AI skills for operations, HR, finance, and customer management", "url": "https://www.kh-academy.com"}, {"offer": "AI Automation Cookbook", "price": "$67", "description": "Advanced multi-step automation workflows you can install and run immediately", "url": "https://www.kh-academy.com"}, {"offer": "Ultimate AI Bundle", "price": "$147", "description": "Every KH Academy product — all skills, all templates, all future updates included", "url": "https://www.kh-academy.com"}]}]};

export const SMALL_BUSINESS_DATA: CourseData = {"product_id": "small-business", "title": "AI for Small Business", "subtitle": "Ready-to-Deploy AI Systems That Run Your Business While You Sleep", "tagline": "6 Complete Business Systems + Templates Inside", "source": "ai-small-business.pdf", "version": "1.0 — March 2026", "pages": 44, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini"], "sections": [{"title": "Welcome", "type": "intro", "content": "YOUR BUSINESS DOESN'T NEED MORE AI ADVICE. IT NEEDS AI SYSTEMS. You've read the articles. You've tried the prompts. But here's what nobody tells you: using AI for one task at a time is like hiring an employee and only letting them answer one question per day. This playbook is different. Instead of scattered prompts, you get complete business systems — tested workflows where AI handles entire processes from start to finish. Each system comes with ready-to-use templates you customize once, then run forever.", "comparison": {"what_most_people_do": ["Ask AI one question at a time", "Start over every session", "Get generic answers", "Waste 2+ hours daily on repetitive tasks"], "what_this_playbook_gives_you": ["Complete systems that chain tasks", "Pre-loaded business context", "Output tailored to YOUR business", "Systems that run in under 15 minutes"]}, "items": []}, {"title": "How to Use This Playbook", "type": "instructions", "content": "Three-step guide to deploying AI systems in your business.", "items": [{"step": 1, "title": "Pick a System", "instruction": "Start with your biggest time-waster. Each system stands alone."}, {"step": 2, "title": "Fill in Your Details", "instruction": "Every template has [BRACKETS] for your business info. Fill once, use forever."}, {"step": 3, "title": "Deploy & Repeat", "instruction": "Use the system daily — AI remembers your context and gets better over time."}]}, {"title": "Table of Contents", "type": "toc", "content": "3 parts. 6 systems. All templates included.", "items": [{"part": "I — FOUNDATION", "chapter": "01", "title": "The AI Business Profile", "pages": "4-5"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "02", "title": "Customer Inquiry & Response", "pages": "6-13"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "03", "title": "Content & Social Media", "pages": "14-18"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "04", "title": "Financial Analysis & Reporting", "pages": "19-22"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "05", "title": "Sales & Lead Follow-Up", "pages": "23-28"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "06", "title": "Operations & SOP", "pages": "29-32"}, {"part": "II — 6 BUSINESS SYSTEMS", "chapter": "07", "title": "Hiring & Team Management", "pages": "33-36"}, {"part": "III — CUSTOMIZATION", "chapter": "08", "title": "Industry Quick-Start Guides", "pages": "37-39"}, {"part": "III — CUSTOMIZATION", "chapter": "09", "title": "Your AI Operations Manual", "pages": "40-41"}, {"part": "III — CUSTOMIZATION", "chapter": "10", "title": "What's Next: Systems to Automation", "pages": "42-43"}]}, {"title": "Chapter 01: The AI Business Profile", "type": "templates", "content": "Fill this in ONCE. Every system in this playbook uses it.", "master_template": {"label": "BUSINESS PROFILE — [Your Business Name]", "fields": {"industry": "[e.g., Restaurant / Retail / Consulting / Freelance]", "business_type": "[B2B / B2C / Both]", "years_operating": "[___]", "team_size": "[Solo / 2-5 / 6-20 / 20+]", "customers": {"primary_customer": "[Who buys from you? Age, role, situation]", "pain_points": "[Top 3 problems you solve]", "average_transaction_value": "$[___]", "how_customers_find_you": "[Social / Referral / Walk-in / Search]"}, "voice_and_brand": {"brand_tone": "[Professional / Friendly / Casual / Luxury / Fun]", "words_we_always_use": "[3-5 brand words]", "words_we_never_use": "[3-5 words to avoid]", "competitor_difference": "[What makes you different in 1 sentence]"}, "operations": {"biggest_time_waster": "[The task that eats most of your week]", "software_you_use": "[List your tools — POS, CRM, email, etc.]", "business_hours": "[___]", "peak_season": "[___]"}}}, "how_to_use_profile": [{"step": 1, "platform": "Claude", "instruction": "Copy your completed Business Profile into a Claude Project as the project instruction. Every conversation in that project will automatically know your business."}, {"step": 2, "platform": "Gemini", "instruction": "Paste your profile at the start of any Gemini Gem instruction. The Gem becomes a specialist that already knows who you are."}, {"step": 3, "platform": "Everywhere", "instruction": "Every system in this playbook references [YOUR PROFILE] — that means this template. Fill it once and all 6 systems auto-customize to your business."}], "pro_tip": "Update your Business Profile quarterly as your business evolves. Your prices change, your customers shift, your tools upgrade — keep this document alive and every AI system stays current."}, {"title": "System 01: Customer Response System", "type": "system", "problem": "You spend 1-2 hours daily writing similar emails and messages", "solution": "A system that drafts responses in your brand voice in under 60 seconds", "time_saved": "8-10 hours per week", "whats_inside": ["8 ready-to-use response templates (all fully written out)", "Escalation decision tree (AI vs. human)", "Claude Skill + Gemini Gem setup instructions", "AI prompts to customize any response"], "response_templates": [{"template_number": 1, "name": "New Inquiry / First Contact", "scenario": "Someone contacts you for the first time", "trigger": "New email, DM, or form submission", "tone": "[BRAND TONE] — warm, welcoming", "template": "Hi [Customer Name],\n\nThanks so much for reaching out to [YOUR BUSINESS]!\n\nI'd love to help you with [restate their question/need].\n\nHere's a quick overview of what we offer:\n[YOUR TOP 2-3 SERVICES/PRODUCTS with 1-line descriptions]\n\nWould you like to [get a quote]? I'm happy to help you find the right fit.\n\nLooking forward to connecting,\n[YOUR NAME]\n[YOUR PREFERRED CONTACT METHOD]"}, {"template_number": 2, "name": "Pricing Question", "scenario": "Customer asks about pricing", "trigger": "Customer asks 'how much' or 'what do you charge'", "tone": "[BRAND TONE] — confident, transparent", "template": "Hi [Customer Name],\n\nThanks for your interest in [YOUR BUSINESS]!\n\nHere's our pricing for [what they asked about]:\n[Price details from YOUR product/service list]\n\nWhat makes us different: [YOUR COMPETITOR DIFFERENCE]\n\nHappy to answer any other questions —\n[YOUR PREFERRED CONTACT METHOD]\n\n[YOUR NAME]"}, {"template_number": 3, "name": "Complaint / Negative Feedback", "scenario": "Customer is unhappy or reports a problem", "trigger": "Complaint email, negative review, angry message", "tone": "[BRAND TONE] — empathetic, solution-focused", "template": "Hi [Customer Name],\n\nThank you for letting us know about this. I'm really sorry you had this experience — that's not the standard we hold ourselves to at [YOUR BUSINESS].\n\nHere's what I'd like to do to make this right:\n[Specific remedy: refund / redo / discount / replacement]\n\nI've also [updated our process / personally reviewed what happened] so this doesn't happen again.\n\nCan I [call you / schedule a time to chat] to make sure you're fully taken care of?\n\n[YOUR NAME]"}, {"template_number": 4, "name": "Follow-Up (No Response)", "scenario": "You reached out but haven't heard back", "trigger": "3-5 days since last contact with no reply", "tone": "[BRAND TONE] — helpful, not pushy", "template": "Hi [Customer Name],\n\nJust checking in — I wanted to make sure my last message didn't get buried in your inbox!\n\nTo recap, you asked about [their original question], and I'd shared [brief summary of your response].\n\nIf you have any other questions or if your needs have changed, I'm here to help. No pressure at all.\n\nHave a great [day of week]!\n[YOUR NAME]"}, {"template_number": 5, "name": "Booking / Appointment Confirmation", "scenario": "Customer books an appointment or reservation", "trigger": "New booking received", "tone": "[BRAND TONE] — organized, reassuring", "template": "Hi [Customer Name],\n\nYou're all set! Here are your booking details:\n\nDate: [DATE]\nTime: [TIME]\nLocation: [ADDRESS / virtual link]\nService: [WHAT THEY BOOKED]\n\nA few things to know before your visit:\n- [Preparation info: what to bring, parking, etc.]\n- [Cancellation/reschedule policy]\n\nIf anything changes, just reply to this message or call us at [PHONE]. We look forward to seeing you!\n\n[YOUR NAME] at [YOUR BUSINESS]"}, {"template_number": 6, "name": "Thank You / Post-Purchase", "scenario": "Customer just made a purchase or completed service", "trigger": "Transaction complete", "tone": "[BRAND TONE] — grateful, personal", "template": "Hi [Customer Name],\n\nThank you for choosing [YOUR BUSINESS]! We truly appreciate your [purchase / visit / business].\n\nJust a quick summary:\n[Order details / service summary / receipt reference]\n\nA few things that might be helpful:\n- [Care instructions / next steps / how to get support]\n- [Warranty / return policy reminder]\n\nIf you enjoyed your experience, we'd love a quick review on [Google / Yelp / your platform]: [REVIEW LINK]\n\nThanks again — hope to see you back soon!\n[YOUR NAME]"}, {"template_number": 7, "name": "Refund / Cancellation Request", "scenario": "Customer wants a refund or to cancel", "trigger": "Refund/cancellation request received", "tone": "[BRAND TONE] — understanding, professional", "template": "Hi [Customer Name],\n\nI understand, and I appreciate you letting us know.\n\nI've started processing your [refund / cancellation]. Here's what to expect:\n- [Timeline: refund in 5-7 business days / etc.]\n- [Any conditions or next steps they need to take]\n\nIf you don't mind me asking — was there anything we could have done differently? Your feedback helps us improve for everyone.\n\nYou're always welcome back at [YOUR BUSINESS].\n\n[YOUR NAME]"}, {"template_number": 8, "name": "Review Request", "scenario": "You want to ask a happy customer for a review", "trigger": "1-3 days after positive interaction or purchase", "tone": "[BRAND TONE] — warm, appreciative, brief", "template": "Hi [Customer Name],\n\nIt was great [helping you with ___] recently!\n\nIf you have 30 seconds, a quick review would mean the world to us. It helps other people like you find us:\n\n[REVIEW LINK — Google / Yelp / Facebook / your platform]\n\nNo pressure at all — and thank you again for choosing [YOUR BUSINESS]. We're here whenever you need us!\n\n[YOUR NAME]"}], "escalation_decision_tree": [{"situation": "Simple question", "action": "AI handles it (use response template)"}, {"situation": "Pricing inquiry", "action": "AI drafts, quick review, then send"}, {"situation": "Complaint", "action": "AI drafts, YOU review before sending"}, {"situation": "Legal / safety issue", "action": "YOU handle directly — no AI"}, {"situation": "VIP / high-value", "action": "AI drafts, YOU personalize & send"}], "pro_tip": "Set a rule: if the customer's issue involves money, emotions, or legal risk — always have a human review before sending. AI is great at drafting, but judgment calls need you.", "time_savings": {"before": "1-2 hours/day writing repetitive responses", "after": "Under 10 minutes — AI drafts, you approve"}, "ai_skill_instructions": {"claude": {"skill_name": "Customer Response Agent", "role": "You are a customer response specialist for [YOUR BUSINESS NAME].", "context": "Use the Business Profile attached to this project to understand our brand, customers, and tone.", "rules": ["Always match our brand tone: [BRAND TONE]", "Include our differentiator when relevant", "Keep responses under 150 words", "Flag complaints for human review", "Never make promises about pricing or timelines without checking the product/service list"], "workflow": ["Read the customer message", "Identify the scenario type (pricing, complaint, etc.)", "Use the matching template from the library", "Customize with business details", "Output: ready-to-send response"]}, "gemini": {"gem_name": "Customer Response Agent", "instructions": "You are a customer response specialist for [YOUR BUSINESS NAME]. Use the Business Profile in my instructions to understand our brand. When I paste a customer message, identify the type (pricing, complaint, review request, etc.) and draft a response using our brand tone: [BRAND TONE]. Keep it under 150 words. Flag complaints for review."}}, "quick_use_prompts": [{"label": "AI Prompt (Claude / Gemini)", "prompt": "Using my Business Profile, draft a response to this customer message: [paste message]. Identify which scenario it is (new inquiry, pricing, complaint, follow-up, booking, thank you, refund, or review request) and use the matching template. Match my brand tone. Keep it under 100 words."}, {"label": "Review Response Prompt (Claude / Gemini)", "prompt": "A customer left this negative review: [paste review]. Draft a public response that (1) acknowledges their concern, (2) apologizes sincerely, (3) offers a specific remedy, and (4) invites them to continue the conversation privately. Match my brand tone: [BRAND TONE]."}, {"label": "Batch Follow-Up Prompt (Claude / Gemini)", "prompt": "I need to follow up with [X] customers who haven't responded. Here are their names and original inquiries: [paste list]. For each, draft a brief, friendly follow-up using Template 4. Personalize each one based on their original question."}], "content": "Most business owners spend 1-2 hours every day writing the same types of emails and messages — greetings, pricing replies, complaint responses, follow-ups. This system eliminates that repetitive work by giving you 8 pre-built response templates that AI customizes to your brand voice in under 60 seconds. You load your Business Profile once into a Claude Project or Gemini Gem, paste any incoming customer message, and the AI identifies the scenario type, selects the right template, and drafts a polished response you can send immediately. The escalation decision tree tells you exactly when AI handles it alone versus when you should review first — so complaints and VIP customers always get your personal touch. Tested across service businesses, retail, and restaurants: owners report cutting response time from 42 minutes average down to under 2 minutes per message."}, {"title": "System 02: Content & Social Media", "type": "system", "problem": "Content creation takes 5+ hours/week and still feels inconsistent", "solution": "A batch system that produces a full week of branded content in one sitting", "time_saved": "4-6 hours per week", "whats_inside": ["4-pillar content framework (customized to your business)", "30-minute batch workflow (a full week of content)", "Platform-specific templates (Instagram, Facebook, LinkedIn, Email)", "AI prompts for both Claude and Gemini"], "content_pillar_framework": {"description": "Stop guessing what to post. These 4 pillars give you a rotation system that keeps content varied, on-brand, and engaging.", "pillars": [{"number": 1, "name": "Behind the Scenes", "description": "How we do it, workspace tours, process reveals, day-in-the-life"}, {"number": 2, "name": "Customer Results", "description": "Testimonials, before-after, case studies, success stories"}, {"number": 3, "name": "Education & Tips", "description": "How-to's, tips your audience needs, myth-busting, FAQs"}, {"number": 4, "name": "Personality & Culture", "description": "Team introductions, values, humor, what makes you human"}], "weekly_rotation": {"Monday": "Pillar 1 — Behind the Scenes", "Tuesday": "Pillar 2 — Customer Results", "Wednesday": "Pillar 3 — Education & Tips", "Thursday": "Pillar 4 — Personality & Culture", "Friday": "Pillar 2 or 3 — Repurpose best performer"}}, "batch_workflow": {"title": "The 30-Minute Batch Workflow", "description": "One sitting. One week of content.", "steps": [{"step": 1, "action": "Feed AI Your Context", "detail": "Paste Business Profile + this week's theme. (2 min)"}, {"step": 2, "action": "Generate 5 Post Concepts", "detail": "Ask AI for 5 ideas using Pillar rotation. (3 min)"}, {"step": 3, "action": "Expand to Drafts", "detail": "AI writes platform-specific drafts. (10 min)"}, {"step": 4, "action": "Add Captions & Hashtags", "detail": "Generate captions and hashtags. (5 min)"}, {"step": 5, "action": "Create Newsletter", "detail": "Convert best post into email newsletter. (5 min)"}, {"step": 6, "action": "Review & Schedule", "detail": "Quick review, adjust, schedule. (5 min)"}], "ai_prompt": "Using my Business Profile, create 5 social media post concepts for this week. Use the 4-pillar rotation. Theme: [YOUR THEME]. For each: headline, 2-sentence description, suggested visual, and best platform."}, "platform_templates": [{"platform": "Instagram", "format": "Carousel / Single Post / Story Sequence", "structure": {"hook": "[Attention-grabbing question or stat]", "body": "[2-3 short paragraphs, one idea per paragraph]", "cta": "[What you want them to do — save, share, comment]", "hashtags": "[5-10 relevant, mix of niche + broad]"}, "ai_prompt": "Write an Instagram [carousel/post/story] about [TOPIC] for my [INDUSTRY] business. Use my brand tone: [BRAND TONE]. Hook them with the first line."}, {"platform": "Facebook", "format": "Engagement Post / Event Promo / Review Share", "structure": {"opening": "[Personal story or question to spark comments]", "body": "[Conversational, 3-5 sentences max]", "cta": "[Ask a question to drive comments]"}, "ai_prompt": "Write a Facebook [engagement post/event promo] about [TOPIC]. Make it conversational. Ask a question to drive comments. Match my brand tone: [BRAND TONE]."}, {"platform": "LinkedIn", "format": "Thought Leadership / Case Study / Hiring", "structure": {"hook": "[Bold statement or contrarian take]", "story": "[3-4 short paragraphs with line breaks]", "insight": "[What you learned or what others should know]", "cta": "[Agree? Disagree? Share your experience.]"}, "ai_prompt": "Write a LinkedIn post about [TOPIC] from my perspective as a [YOUR ROLE] in [INDUSTRY]. Professional but authentic tone."}, {"platform": "Email Newsletter", "format": "Weekly digest / single-topic deep-dive", "structure": {"subject_line": "[Curiosity-driven, under 50 characters]", "preview_text": "[Complement the subject, don't repeat it]", "body": "[One main story/tip from this week's best post]", "cta": "[One clear action — reply, click, shop]"}, "ai_prompt": "Turn this social media post into a weekly email newsletter: [paste post]. Add a personal intro, expand the content, and end with one clear CTA."}], "content": "Creating consistent social media content is one of the biggest time drains for small business owners — most spend 5+ hours per week and still feel like their posts are scattered and off-brand. This system solves that with a structured 4-pillar content rotation (Behind the Scenes, Customer Results, Education, Personality) combined with a 30-minute batch workflow that produces an entire week of platform-specific content in one sitting. You fill in your weekly theme, feed it to Claude or Gemini alongside your Business Profile, and the AI generates 5 post concepts, expands them into platform-ready drafts for Instagram, Facebook, LinkedIn, and email, then adds captions and hashtags. The included templates are formatted for each platform so character limits, hashtag counts, and CTA styles are already optimized. One batch session replaces what used to take all week."}, {"title": "System 03: Financial Analysis & Reporting", "type": "system", "problem": "You know your revenue but not your real profitability drivers", "solution": "Monthly financial health checks that take 15 minutes", "time_saved": "3-5 hours per month", "whats_inside": ["Monthly business health check template", "Pricing & profitability analyzer", "3-month cash flow forecaster", "AI prompts to turn your numbers into insights"], "monthly_health_check_template": {"fields": {"month": "[___]", "year": "[___]", "revenue": {"total": "$[___]", "product_service_a": "$[___]", "product_service_b": "$[___]", "product_service_c": "$[___]"}, "costs": {"total": "$[___]", "cost_of_goods": "$[___]", "rent_utilities": "$[___]", "staff": "$[___]", "marketing": "$[___]", "software_tools": "$[___]", "other": "$[___]"}, "customers": {"total": "[___]", "new": "[___]", "returning": "[___]", "lost": "[___]"}}, "ai_prompt": "Analyze this month's data against last month. Identify: (1) top revenue driver, (2) biggest cost increase, (3) customer retention rate, (4) three specific actions to improve next month. Be direct — I'm a busy owner."}, "pricing_analysis_template": {"description": "Most small businesses underprice. This template helps you evaluate whether your pricing is right.", "fields": {"product_service": "[Name]", "your_price": "$[___]", "your_cost_to_deliver": "$[___]", "your_margin": "[___]%", "competitor_pricing": [{"competitor": "Competitor 1: [Name]", "price": "$[___]"}, {"competitor": "Competitor 2: [Name]", "price": "$[___]"}, {"competitor": "Competitor 3: [Name]", "price": "$[___]"}], "positioning": "[Budget / Mid-range / Premium]", "last_price_increase": "[Date or 'Never']"}, "ai_prompt": "Review my pricing data above. Compare my margins to industry averages for [INDUSTRY]. Analyze my competitor positioning. Recommend: should I raise prices, by how much, and how to communicate the increase. Give me a specific plan.", "pro_tip": "Run this analysis quarterly. Most small businesses haven't raised prices in 2+ years while costs have increased 15-20%. A 10% price increase with zero customer loss goes straight to your bottom line."}, "cash_flow_forecast_template": {"description": "See the future before it arrives. This 3-month template helps you spot cash crunches before they hit.", "fields": {"current_cash_balance": "$[___]", "month_1": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "month_2": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "month_3": {"name": "[Month Name]", "expected_revenue": "$[___]", "expected_costs": "$[___]", "seasonal_factor": "[Peak / Normal / Slow]", "projected_balance": "$[___]"}, "upcoming_big_expenses": "[List any known large costs]"}, "ai_prompt": "Using my cash flow data and my Business Profile (peak season: [PEAK SEASON]), identify: (1) months where cash might run low, (2) seasonal adjustment recommendations, (3) how much reserve I should keep. Be specific with dollar amounts."}, "content": "Most small business owners know their top-line revenue but have no idea which products actually make money, whether their pricing is right, or when cash flow will get tight. This system gives you three plug-and-play financial templates that turn raw numbers into clear action items in 15 minutes flat. The Monthly Health Check compares this month to last month across revenue, costs, and customer metrics — then AI identifies your top driver, biggest cost spike, and three specific things to fix. The Pricing Analyzer compares your margins against competitors and tells you exactly how much to raise prices and how to communicate the increase. The 3-Month Cash Flow Forecaster spots cash crunches before they hit by factoring in your seasonal patterns. No accounting degree needed — just paste your numbers and AI does the analysis."}, {"title": "System 04: Sales & Lead Follow-Up", "type": "system", "problem": "80% of sales need 5+ follow-ups, but most businesses stop at 1-2", "solution": "A 5-touch follow-up sequence with templates for each stage", "time_saved": "5-8 hours per week", "whats_inside": ["5-touch follow-up sequence with full email templates", "Lead scoring cheat sheet (hot / warm / cool)", "Proposal & quote generator template", "AI prompts for personalized outreach"], "follow_up_sequence": [{"touch": 1, "name": "Initial Response", "timing": "Day 0 — within 1 hour of inquiry", "goal": "Acknowledge, answer, invite next step", "template": "Hi [Customer Name],\n\nThanks for reaching out to [YOUR BUSINESS]! I saw your question about [their specific inquiry].\n\n[Direct answer to their question — be specific]\n\nI'd love to learn more about what you're looking for. Would you be open to [sharing a few more details]?\n\nLooking forward to hearing from you,\n[YOUR NAME]\n[YOUR PHONE / BOOKING LINK]"}, {"touch": 2, "name": "Value-Add Follow-Up", "timing": "Day 2", "goal": "Build trust by giving, not asking", "template": "Hi [Customer Name],\n\nI was thinking about [their situation/question] and wanted to share something that might help:\n\n[helpful resource related to their need — NOT a sales pitch]\n\nA lot of our customers in [similar situation] have found this really helpful. No strings attached — just thought of you.\n\nLet me know if you have any questions!\n[YOUR NAME]"}, {"touch": 3, "name": "Social Proof", "timing": "Day 5", "goal": "Show results others have gotten", "template": "Hi [Customer Name],\n\nQuick thought — I wanted to share how we helped [similar customer/business] with [similar need]:\n\n\"[2-3 sentences about the result they achieved]\"\n— [Customer name/business], [their role]\n\nTheir situation was similar to yours, and I think we could get you similar results.\n\nWorth a conversation? I'm free [times]. Happy to keep it to 15 minutes.\n\n[YOUR NAME]"}, {"touch": 4, "name": "Direct Ask", "timing": "Day 10", "goal": "Make a clear, specific offer", "template": "Hi [Customer Name],\n\nI wanted to check in one more time about [their need].\n\nBased on what you shared, here's what I'd recommend:\n[Specific product/service recommendation with price]\n\n[Urgency element: 'We have 2 spots left this month' or 'Our seasonal offer runs through [date]']\n\nIf you'd like to move forward, here's the easiest way: [specific next step — book a call, reply, visit]\n\nAnd if now isn't the right time, no worries at all — I'll be here when you're ready.\n\n[YOUR NAME]"}, {"touch": 5, "name": "Long-Term Nurture", "timing": "Day 21", "goal": "Stay top of mind without being pushy", "template": "Hi [Customer Name],\n\nHope you're doing well! No sales pitch today — just wanted to share something I thought you'd find useful:\n\n[helpful resource, tip, or community event related to their interest]\n\nIf your needs around [their original question] ever come back up, I'm always happy to help.\n\nHave a great [day/week]!\n[YOUR NAME]"}], "follow_up_ai_prompt": "Using my Business Profile, write a [Touch 1/2/3/4/5] follow-up email for this lead: [paste lead details]. Match my brand tone. Keep it under 80 words. The goal is [proof / close / nurture].", "lead_scoring": {"hot": {"label": "HOT — Follow Up Today", "signals": ["Asked about pricing", "Mentioned a timeline or deadline", "Referred by existing customer", "Visited or contacted you twice or more"]}, "warm": {"label": "WARM — Follow Up This Week", "signals": ["Downloaded your content or signed up", "Asked general questions about your services", "Engaged with your social media content", "Attended an event or webinar"]}, "cool": {"label": "COOL — Monthly Nurture", "signals": ["Early-stage research only", "No budget or timeline mentioned", "Competitor comparison shopping", "Connected but no conversation yet"]}, "pro_tip": "Create three saved AI prompts — one for each lead temperature. When a new lead comes in, classify them, then use the matching prompt to generate a personalized response in seconds."}, "proposal_template": {"description": "Stop spending hours on proposals. Paste your discovery call notes and let AI draft a professional proposal in minutes.", "template": {"for": "[Client Name / Company]", "date": "[___]", "prepared_by": "[YOUR NAME] at [YOUR BUSINESS]", "understanding_your_needs": "[AI generates from your call notes]", "recommended_solution": "[AI recommends from your services/products]", "pricing": {"service_1": "$[___]", "service_2": "$[___]", "total_investment": "$[___]"}, "timeline": "[___]", "whats_included": "[Scope of work]", "next_steps": "[How to proceed]", "valid_until": "[Date — 14 days recommended]"}, "ai_prompt": "Using my Business Profile and this template, draft a proposal for: [describe the client request]. Match our brand tone. Recommend the right service/product combo. Include a 14-day validity period."}, "content": "Research shows 80% of sales require 5 or more follow-up touches, but most small businesses stop at 1 or 2 and wonder why leads go cold. This system gives you a complete 5-touch follow-up sequence with full email templates for each stage — from initial response (within 1 hour) through value-add, social proof, direct ask, and long-term nurture over 21 days. Each template is designed so AI fills in lead-specific details using your Business Profile: their name, their inquiry, a relevant case study, and your specific offer. The lead scoring cheat sheet helps you instantly classify leads as Hot, Warm, or Cool so you know which ones need attention today. The proposal generator turns your discovery call notes into a professional quote in minutes instead of hours. Set up one Claude Project or Gemini Gem and paste any lead — AI handles the personalization, you handle the relationship."}, {"title": "System 05: Operations & SOP System", "type": "system", "problem": "Everything lives in your head — if you're sick, the business stops", "solution": "AI-generated SOPs from your verbal descriptions", "time_saved": "Major — building a business that runs without you", "whats_inside": ["SOP generator workflow (voice to procedure)", "SOP template with fill-in structure", "Top 10 SOPs every small business needs", "Delegation & handoff templates"], "sop_generator_workflow": [{"step": 1, "action": "Voice-Describe Your Process", "detail": "Talk like you're training a new employee. Record yourself explaining the task from start to finish."}, {"step": 2, "action": "Paste the Transcript", "detail": "Use speech-to-text or a free transcription tool. Paste the raw text into AI along with the SOP template."}, {"step": 3, "action": "AI Outputs Formatted SOP", "detail": "AI organizes your rambling into a clean, step-by-step procedure anyone can follow."}], "sop_template": {"name": "[Process Name]", "owner": "[Who's responsible]", "last_updated": "[Date]", "purpose": "[Why this process exists]", "trigger": "[What starts this process]", "steps": [{"step": 1, "action": "[Step]", "expected_output": "[___]"}, {"step": 2, "action": "[Step]", "expected_output": "[___]"}, {"step": 3, "action": "[Step]", "expected_output": "[___]"}, {"step": 4, "action": "[Step]", "expected_output": "[___]"}], "exceptions": "[What to do when things go wrong]", "tools_needed": "[Software, equipment]", "time_estimate": "[How long it should take]"}, "top_10_sops": [{"rank": 1, "name": "Opening / closing procedures", "complexity": "Easy"}, {"rank": 2, "name": "New customer onboarding", "complexity": "Medium"}, {"rank": 3, "name": "Order fulfillment / service delivery", "complexity": "Medium"}, {"rank": 4, "name": "Complaint handling", "complexity": "Easy"}, {"rank": 5, "name": "Social media posting", "complexity": "Easy"}, {"rank": 6, "name": "Invoicing & payment collection", "complexity": "Easy"}, {"rank": 7, "name": "Inventory / supply reordering", "complexity": "Medium"}, {"rank": 8, "name": "Staff training for new hires", "complexity": "Complex"}, {"rank": 9, "name": "Monthly financial review", "complexity": "Medium"}, {"rank": 10, "name": "Emergency / crisis response", "complexity": "Complex"}], "sop_ai_prompt": "I'm going to describe my [PROCESS NAME] process. Here's my raw description: [paste transcript]. Using the SOP template, organize this into a clean, step-by-step procedure. Include expected outputs, exceptions, and a time estimate.", "task_handoff_template": {"task": "[Name]", "delegated_to": "[Person / Role]", "sop_reference": "[Which SOP to follow]", "due": "[Date / Recurring schedule]", "what_success_looks_like": "[Describe the expected output clearly]", "common_mistakes_to_avoid": ["[___]", "[___]", "[___]"], "questions_contact": "[Your name / contact]", "check_in_schedule": "[Daily / Weekly / As needed]"}, "training_checklist": ["Shared the SOP document with team member", "Walked through the process together once", "Team member completed process with supervision", "Team member completed process independently", "Reviewed quality of first 3 independent outputs", "Scheduled recurring check-ins"], "pro_tip": "Use AI to generate a quiz from any SOP. Paste the SOP and ask: 'Create a 5-question quiz to test understanding of this procedure.' Great for training verification.", "content": "If everything about how your business operates lives inside your head, you do not have a business — you have a job you cannot take a day off from. This system fixes that by converting your verbal knowledge into documented, repeatable standard operating procedures that anyone on your team can follow. The workflow is simple: talk through any process like you are training a new employee, paste the transcript into Claude or Gemini with the included SOP template, and AI organizes your explanation into a clean step-by-step procedure with expected outputs, exception handling, tools needed, and time estimates. The Top 10 SOPs checklist tells you exactly which procedures to document first (opening/closing, onboarding, order fulfillment, complaint handling). The task handoff template ensures clean delegation with clear success criteria and check-in schedules. Build your operations manual one SOP at a time — the goal is a business that runs even when you are not there."}, {"title": "System 06: Hiring & Team Management", "type": "system", "problem": "Hiring takes weeks and you still pick the wrong person", "solution": "AI-assisted hiring pipeline — from posting to onboarding in half the time", "time_saved": "10-15 hours per hire", "whats_inside": ["Job description generator template", "Interview question bank (role + culture fit)", "Scoring rubric for objective evaluation", "30-day onboarding checklist"], "job_description_input_template": {"role": "[___]", "reports_to": "[___]", "type": "[Full-time / Part-time / Contract]", "must_have_skills": ["[___]", "[___]", "[___]"], "nice_to_have": ["[___]", "[___]"], "personality_fit": "[From your Business Profile brand tone]", "deal_breakers": "[What disqualifies a candidate]", "compensation": "[Range or 'competitive']", "location": "[On-site / Remote / Hybrid]"}, "job_description_ai_prompt": "Using my Business Profile and this role template, write a job description for [ROLE]. Match our brand tone [BRAND TONE]. Include what makes working here different. Under 300 words. Make skills specific and measurable.", "interview_questions": {"role_specific": ["Describe a time you [KEY SKILL] — what was the result?", "How would you handle [COMMON SCENARIO]?", "What tools/methods do you use for [CORE RESPONSIBILITY]?", "Walk me through how you'd approach [REAL TASK].", "What's the biggest [SKILL] challenge you've solved?"], "culture_fit": ["What kind of work environment brings out your best?", "How do you handle [BRAND TONE-RELATED SCENARIO]?", "Describe a team you loved — what made it great?", "How do you handle feedback you disagree with?", "What would your last manager say is your biggest strength?"]}, "scoring_rubric": {"scale": "1=Poor 2=Below Avg 3=Meets 4=Above 5=Exceptional", "total_possible": 50, "fields": {"candidate": "[Name]", "role": "[Position]", "role_scores": "Role Q1: [/5] Role Q2: [/5] Role Q3: [/5] Role Q4: [/5] Role Q5: [/5]", "culture_scores": "Culture Q1: [/5] Culture Q2: [/5] Culture Q3: [/5] Culture Q4: [/5] Culture Q5: [/5]", "total": "[/50]", "red_flags": "[___]", "decision": "[ ] Advance [ ] Maybe [ ] Pass"}}, "onboarding_checklist": {"week_1": {"title": "Orientation", "tasks": ["Complete all paperwork and system access", "Tour of workspace / intro to team", "Review Business Profile and brand values", "Shadow existing team member for 2 days", "Read SOPs for their role (from Chapter 06)"]}, "week_2": {"title": "Supervised Work", "tasks": ["Complete first tasks with supervision", "Daily 15-min check-in with manager", "Review and practice all relevant SOPs", "Start handling routine tasks independently", "Document questions and feedback"]}, "week_3": {"title": "Independent Work", "tasks": ["Handle routine tasks independently", "Check-in reduced to every other day", "Introduce customer-facing responsibilities", "Begin cross-training on secondary tasks", "Manager observes and takes notes"]}, "week_4": {"title": "First Review", "tasks": ["Complete first performance review template", "Discuss wins, challenges, and next goals", "Adjust training plan based on performance", "Set 60-day and 90-day milestones", "Transition to regular check-in schedule"]}}, "content": "Hiring is one of the most expensive and time-consuming activities for a small business — a bad hire can cost 30% of that person's annual salary in lost productivity and rehiring costs. This system cuts your hiring time in half while improving candidate quality using an AI-assisted pipeline from job posting to 30-day onboarding. You fill in the role template (skills, personality fit, deal-breakers, compensation range), and Claude or Gemini generates a compelling job description that matches your brand tone and highlights what makes your workplace different. The interview question bank gives you 10 structured questions split between role-specific skills and culture fit. The scoring rubric eliminates gut-feel hiring by giving you a 50-point objective evaluation framework. After you hire, the 4-week onboarding checklist takes your new team member from orientation through supervised work to independent performance review — with AI generating quizzes from your SOPs to verify they actually learned the procedures."}, {"title": "Chapter 08: Industry Quick-Start Guides", "type": "educational", "content": "Every business is different, but you do not need to figure out where to start from scratch. These four industry-specific guides tell you exactly which systems to deploy first based on what moves the needle fastest in your industry, plus bonus templates designed for your specific use cases. Each guide includes the recommended system priority order, industry-specific template additions you will not find in generic AI courses, a recommended Claude Skill or Gemini Gem name, and a ready-to-paste quick-start prompt that configures your first system in minutes. Pick your industry, follow the priority order, and you will see measurable time savings within your first week.", "industries": [{"industry": "Restaurant / Food Service", "content": "Restaurants live and die by two things: reviews and repeat customers. Start with the Customer Response System because a single unanswered Google or Yelp complaint can cost you thousands in lost foot traffic — Claude generates polished, brand-voice responses in under 30 seconds that turn critics into return visitors. Next, deploy Content to keep your social feeds active with daily specials, seasonal menus, and behind-the-kitchen posts without spending your evenings writing captions. Finally, Operations locks down your prep lists, staff scheduling, and food safety checklists so nothing falls through the cracks during a Friday rush. The four bonus templates below are restaurant-specific additions you will not find in any generic AI course — they handle the exact scenarios that eat up a restaurant owner's time every single week.", "priority_systems": ["#1 Customer Response", "#2 Content", "#3 Operations"], "industry_specific_additions": ["Menu update and seasonal special templates", "Review response templates (Google, Yelp)", "Staff scheduling SOP with peak-hour coverage", "Daily prep checklist generator"], "recommended_skill": "Restaurant Manager", "quick_start_prompt": "I run a [TYPE] restaurant with [X] staff. Busiest days: [DAYS]. Brand voice: [TONE]. Customize the Customer Response System for: reservation inquiries, dietary restriction questions, complaint about food quality, and catering requests."}, {"industry": "Retail / E-Commerce", "content": "Retail margins are thin, so every lost lead and every slow-moving product costs real money. Start with Sales & Lead Follow-Up because the data is clear: stores that send a follow-up within 24 hours of an abandoned cart recover 10-15% of those sales — and Claude writes those sequences in seconds, personalized to the exact product left behind. Next, Content keeps your product pages and social channels fresh with SEO-optimized descriptions and seasonal campaigns that drive organic traffic instead of paid ads. Then Financial Analysis shows you which products actually make money after shipping, returns, and ad spend — most retail owners are shocked to find their best-seller is their worst margin item. The four bonus templates below cover the exact retail workflows that separate stores doing $10K/month from those doing $100K.", "priority_systems": ["#1 Sales & Leads", "#2 Content", "#3 Financial"], "industry_specific_additions": ["Product description generator (SEO-optimized)", "Seasonal promotion calendar template", "Inventory alert and reorder SOP", "Customer review collection sequence"], "recommended_skill": "Retail Operations Manager", "quick_start_prompt": "I run a [TYPE] retail store (online/physical/both) selling [PRODUCTS]. Average order: $[X]. Customize the Sales & Lead Follow-Up System for: abandoned cart follow-up, post-purchase thank you, seasonal promotion, and restock notification."}, {"industry": "Service Business / Consulting", "content": "Service businesses have one fundamental problem: your revenue stops when you stop working, and most of your non-billable time goes into proposals, follow-ups, and client management. Start with Sales & Lead Follow-Up because the average consultant loses 60% of qualified leads simply by not following up fast enough — this system generates personalized follow-up sequences that keep prospects warm without you spending evenings writing emails. Next, Customer Response handles the client communication that eats 5-10 hours per week: project updates, scope clarification, and the delicate art of saying 'that is outside the current agreement' without damaging the relationship. Then Hiring becomes critical when you are ready to scale — the proposal generator alone pays for this entire playbook by turning a 2-hour proposal process into 15 minutes while producing documents that close at higher rates because they are structured, specific, and professionally formatted.", "priority_systems": ["#1 Sales & Leads", "#2 Customer Response", "#3 Hiring"], "industry_specific_additions": ["Proposal generator with scope-of-work", "Scope creep prevention template", "Testimonial collection and case study builder", "Client offboarding and referral request"], "recommended_skill": "Service Business Assistant", "quick_start_prompt": "I run a [TYPE] service business. Average project: $[X] over [TIMELINE]. Customize the Operations & SOP System for: client intake, project kickoff, milestone check-in, and project completion/handoff."}, {"industry": "Freelancer / Solopreneur", "content": "As a solopreneur, you are the business — which means every hour spent on admin is an hour not spent earning. Start with Content because visibility is your lifeline: freelancers who post consistently get 3-5x more inbound leads than those who rely on referrals alone, and Claude generates a full week of thought-leadership posts, case studies, and industry commentary in under 20 minutes. Next, Sales & Lead Follow-Up automates the feast-or-famine cycle by keeping your pipeline warm even when you are buried in client work — the system sends personalized check-ins to past clients and nurtures new leads so you never finish a project and face an empty calendar. Then Financial Analysis shows you your real hourly rate after accounting for unpaid admin time, scope creep, and revision rounds — most freelancers discover they are earning 30-40% less than they think. The bonus templates below tackle the specific pain points every freelancer knows: pricing conversations, late-paying clients, and building a personal brand that attracts premium work.", "priority_systems": ["#1 Content", "#2 Sales & Leads", "#3 Financial"], "industry_specific_additions": ["Personal brand content calendar", "Rate calculator and pricing confidence builder", "Contract and scope-of-work template", "Late payment follow-up email sequence"], "recommended_skill": "Freelance Business Manager", "quick_start_prompt": "I'm a freelance [SPECIALTY] charging $[RATE] per [hour/project]. My clients are [TARGET CLIENTS]. Brand voice: [TONE]. Customize the Content & Social Media System for: personal brand thought leadership, client case studies, industry tips that position me as an expert, and behind-the-scenes of my workflow."}]}, {"title": "Chapter 09: Your AI Operations Manual", "type": "templates", "content": "This is your master control panel for every AI system you deploy. Think of it as the cockpit dashboard for your AI-powered business — one page that shows you which systems are active, how much time they are saving, which tools are running, and when your next review is scheduled. Print it or pin it as a digital document you check weekly. The monthly review checklist walks you through four critical areas: reviewing system performance, updating your Business Profile foundation, optimizing and expanding to new systems, and measuring actual results in hours saved and revenue attributed. The businesses that get the most value from AI are not the ones with the best tools — they are the ones who review their systems monthly and iterate. Update this dashboard every time you activate a new system or retire an old one.", "ai_ops_dashboard": {"systems_active": ["[ ] System 1: Customer Response", "[ ] System 2: Content & Social Media", "[ ] System 3: Financial Analysis", "[ ] System 4: Sales & Follow-Up", "[ ] System 5: Operations & SOP", "[ ] System 6: Hiring & Team"], "weekly_ai_time_budget": "[___] hours", "estimated_time_saved": "[___] hours", "ai_tools_in_use": {"claude_project": "[Project name]", "gemini_gems": "[List active Gems]"}, "monthly_review_date": "[First Monday / Last Friday / etc.]", "next_review": "[Date]"}, "pro_tip": "Print this page or keep it as a pinned document. Update it monthly. The businesses that succeed with AI aren't the ones with the best tools — they're the ones who review and iterate.", "monthly_review_checklist": {"review_your_systems": ["Check each active system — still saving time?", "Review AI outputs — quality still good?", "Identify systems needing template updates", "Check if any system should be activated or paused"], "update_your_foundation": ["Review and update your Business Profile", "Update pricing, products, or services if changed", "Refresh brand tone and messaging if evolved", "Update competitor information"], "optimize_and_expand": ["Refresh templates with new products/services", "Archive SOPs no longer relevant", "Train new team members on AI systems", "Consider adding the next system"], "measure_your_results": ["Calculate total hours saved this month", "Note revenue attributed to AI systems", "Record customer feedback improvements", "Update your AI Ops Dashboard"]}}, {"title": "Chapter 10: What's Next", "type": "educational", "content": "The Automation Ladder — You've been climbing. Here's where you are and what's next.", "automation_ladder": [{"level": 1, "name": "Manual AI", "description": "You type prompts one at a time", "product": "AI Starter Kit ($19)", "status": "COMPLETED"}, {"level": 2, "name": "Specialist AI", "description": "You built Skills & Gems", "product": "AI Skills Builder ($29)", "status": "COMPLETED"}, {"level": 3, "name": "System AI", "description": "You deployed business systems", "product": "AI for Small Business ($47)", "status": "YOU ARE HERE"}, {"level": 4, "name": "Automated AI", "description": "Systems run on autopilot with triggers", "product": "AI Automation Cookbook ($67)", "status": "NEXT"}], "pro_tip": "You don't need Level 4 to see massive results. Most businesses save 15-20 hours/week with Level 3 systems. Automation is the cherry on top."}, {"title": "Upsell / CTA", "type": "cta", "content": "Coming Next: AI Automation Cookbook — You've built the systems. Now let them run without you. The AI Automation Cookbook connects your systems to triggers, schedules, and multi-tool workflows.", "upcoming_product": {"name": "AI Automation Cookbook", "features": ["Multi-tool workflows (connect AI to your existing tools)", "Zapier + Make integration templates", "Auto-triggers: new customer → welcome sequence → follow-up", "Scheduled reports that run while you sleep", "Advanced prompt chains for complex business decisions"]}, "items": [{"offer": "Ultimate AI Bundle", "price": "$147 (Save 40%)", "description": "All 4 products + future updates. vs. $162 buying separately.", "url": "https://www.kh-academy.com"}]}]};

export const AUTOMATION_MASTERY_DATA: CourseData = {"product_id": "automation-mastery", "title": "AI Automation Mastery", "subtitle": "Hands-Free AI Workflows That Market, Sell & Serve Your Customers on Autopilot", "tagline": "9 Ready-to-Use Workflows | Claude + Gemini + Zapier + n8n", "source": "ai-automation-mastery.pdf", "version": "1.0 — March 2026", "pages": 32, "publisher": "KH Academy", "website": "kh-academy.com", "compatible_tools": ["Claude", "Gemini", "Zapier", "n8n"], "sections": [{"title": "Welcome", "type": "intro", "content": "YOUR AI SHOULD WORK WHILE YOU DON'T. You've learned the prompts (Product 1). You've built the Skills and Gems (Product 2). You've deployed complete business systems (Product 3). Now it's time for the final level: automation that runs without you. This guide gives you ready-to-use, step-by-step workflows that connect Claude and Gemini to tools like Zapier and n8n. The result? Your AI writes, responds, follows up, and reports — automatically. You just review the output.", "automation_ladder": [{"level": "01", "name": "Manual AI", "description": "You type prompts one at a time", "status": "DONE"}, {"level": "02", "name": "Specialist AI", "description": "You built Skills & Gems", "status": "DONE"}, {"level": "03", "name": "System AI", "description": "You deployed business systems", "status": "DONE"}, {"level": "04", "name": "Automated AI", "description": "Systems run on autopilot", "status": "YOU ARE HERE"}], "items": []}, {"title": "How to Use This Guide", "type": "instructions", "content": "Three-step guide to setting up and launching automations.", "items": [{"step": 1, "title": "Pick a Workflow", "instruction": "Browse by category: Marketing or Customer Service."}, {"step": 2, "title": "Set Up the Workflow", "instruction": "Follow the step-by-step setup for Zapier OR n8n."}, {"step": 3, "title": "Customize & Launch", "instruction": "Fill in your [BRACKETS], test once, let it run."}]}, {"title": "Table of Contents", "type": "toc", "content": "4 parts. 9 workflows. All templates included.", "items": [{"part": "I — AUTOMATION FOUNDATION", "chapter": "01", "title": "Understanding Automation Platforms", "pages": "4-5"}, {"part": "I — AUTOMATION FOUNDATION", "chapter": "02", "title": "Your Automation Toolkit Setup", "pages": "6-7"}, {"part": "II — MARKETING AUTOMATION", "chapter": "03", "title": "Auto-Generate Social Media Posts", "pages": "8-9"}, {"part": "II — MARKETING AUTOMATION", "chapter": "04", "title": "Email Sequence Generator", "pages": "10-11"}, {"part": "II — MARKETING AUTOMATION", "chapter": "05", "title": "Content Repurposing Engine", "pages": "12-13"}, {"part": "II — MARKETING AUTOMATION", "chapter": "06", "title": "Lead Magnet Follow-Up", "pages": "14-15"}, {"part": "II — MARKETING AUTOMATION", "chapter": "07", "title": "Competitor Watch & Alert", "pages": "16-17"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "08", "title": "Smart Inquiry Auto-Responder", "pages": "18-19"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "09", "title": "Client Onboarding Automation", "pages": "20-21"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "10", "title": "Review & Testimonial Collector", "pages": "22-23"}, {"part": "III — CUSTOMER SERVICE AUTOMATION", "chapter": "11", "title": "Customer Follow-Up & Re-Engagement", "pages": "24-25"}, {"part": "IV — OPTIMIZATION", "chapter": "12", "title": "Automation Dashboard", "pages": "26-27"}, {"part": "IV — OPTIMIZATION", "chapter": "13", "title": "Troubleshooting & Optimization", "pages": "28-29"}, {"part": "IV — OPTIMIZATION", "chapter": "14", "title": "What's Next: Ultimate AI Bundle", "pages": "30-31"}]}, {"title": "Chapter 01: Understanding Automation Platforms", "type": "educational", "content": "Before you build a single workflow, you need to understand the two platforms that make hands-free AI possible: Zapier and n8n. Both connect your AI tools (Claude and Gemini) to the apps you already use — email, CRM, social media, spreadsheets, payment processors — so tasks fire automatically without you lifting a finger. Every automation follows the same 4-part anatomy: a Trigger starts it, an AI Action processes it, an Output is generated, and a Destination receives it. Zapier is the no-code easy button with 7,000+ app integrations and built-in Claude and Gemini connectors — ideal if you want to be live in under 10 minutes. n8n is the open-source power tool with visual workflow building, complex branching logic, and self-hosting for cost savings — ideal if you want full control. This chapter breaks down both platforms with real pricing, key terminology, and a decision guide so you pick the right tool for your situation. Every workflow in this guide includes step-by-step setup for BOTH platforms.", "automation_anatomy": {"description": "The 4 Parts of Every Automation", "parts": [{"number": 1, "label": "TRIGGER", "description": "When this happens..."}, {"number": 2, "label": "AI ACTION", "description": "Ask AI to..."}, {"number": 3, "label": "OUTPUT", "description": "Take the result..."}, {"number": 4, "label": "DESTINATION", "description": "Send it to..."}]}, "platforms": [{"name": "Zapier", "tagline": "The Easy Button", "what_it_is": "Cloud-based, no-code, 7,000+ app integrations", "best_for": "Non-technical users, quick setup, massive app library", "ai_integrations": "Built-in Claude AI and Google Gemini integrations", "pricing": "Free = 100 tasks/month; Starter = $19.99/mo for 750 tasks", "key_terms": {"Zap": "one workflow", "Task": "one execution of a step"}}, {"name": "n8n", "tagline": "The Power Tool", "what_it_is": "Open-source, self-hostable or cloud, visual workflow builder", "best_for": "Users who want more control, complex logic, cost savings", "ai_integrations": "Native Claude + Gemini nodes via API keys", "pricing": "Free self-hosted; Cloud starts at EUR 20/month", "key_terms": {"Workflow": "automation", "Execution": "one run"}}], "decision_guide": {"choose_zapier_if": ["You want the fastest setup (under 10 min)", "You're not technical — no-code everything", "You need to connect to many different apps", "You're okay paying per task as you scale"], "choose_n8n_if": ["You want more control over workflows", "You're comfortable with slightly more tech", "You want to self-host for cost savings", "You need complex logic (loops, branching)"]}, "pro_tip": "Every workflow in this guide includes setup steps for BOTH platforms. You can start with Zapier for speed, then migrate to n8n later if you want more control."}, {"title": "Chapter 02: Your Automation Toolkit Setup", "type": "educational", "content": "This chapter walks you through connecting all your tools in 30 minutes or less so you are ready to deploy any workflow in this guide. You will set up your Claude API key from console.anthropic.com, your Gemini API key from Google AI Studio, and connect them to your chosen automation platform. For Zapier: four steps from signup through the Anthropic connection to a test Zap that confirms everything works. For n8n: four steps from cloud signup (or self-hosting) through credential setup to a verified test workflow. The pre-flight checklist covers every account you need, the optional-but-recommended integrations (Gmail, Google Sheets, your CRM, Slack) that unlock the most powerful workflows, and a credentials tracker template so you never lose track of your API keys, plan tiers, or setup dates. Complete this chapter once and every workflow after it is plug-and-play.", "pre_flight_checklist": ["Claude account (free or Pro) — claude.ai", "Gemini account (free or Advanced) — gemini.google.com", "Anthropic API key — console.anthropic.com", "Google AI Studio API key — aistudio.google.com", "Zapier account — zapier.com", "n8n account — n8n.io (cloud) or self-hosted"], "optional_but_recommended": ["Gmail / Google Workspace", "Google Sheets (for tracking outputs)", "Your CRM (HubSpot, Salesforce, etc.)", "Social media accounts", "Slack or Teams (for notifications)"], "zapier_setup": [{"step": 1, "action": "Sign up at zapier.com", "detail": "Choose Starter plan or higher for AI actions"}, {"step": 2, "action": "Connect Anthropic", "detail": "Settings > Connections > Search 'Anthropic' > Paste API key"}, {"step": 3, "action": "Connect Gemini", "detail": "Settings > Connections > Search 'Google AI Studio' > Paste API key"}, {"step": 4, "action": "Test connection", "detail": "Create test Zap > Add Claude step > Send 'Hello, test!'"}], "n8n_setup": [{"step": 1, "action": "Sign up at app.n8n.cloud", "detail": "Choose Starter plan, or self-host for free"}, {"step": 2, "action": "Add Anthropic credential", "detail": "Settings > Credentials > New > Anthropic > Paste API key"}, {"step": 3, "action": "Add Gemini credential", "detail": "Settings > Credentials > New > Google Gemini > Paste API key"}, {"step": 4, "action": "Test workflow", "detail": "Create new workflow > Add Anthropic node > Execute > Verify"}], "credentials_tracker": {"platform": "[Zapier / n8n / Both]", "plan": "[tier]", "budget": "$[___]", "anthropic_api_key_location": "[location]", "gemini_api_key_location": "[location]", "setup_date": "[___/___/2026]"}}, {"title": "Workflow 03: Auto-Generate Social Posts", "type": "workflow", "tagline": "FRESH CONTENT EVERY DAY — WITHOUT TOUCHING A KEYBOARD", "metrics": {"time_saved": "5-7 hrs", "difficulty": "Beginner", "tools_needed": 3, "frequency": "Daily"}, "flow": [{"step": "S", "label": "SCHEDULE", "description": "Daily 7AM"}, {"step": "G", "label": "SHEETS", "description": "Read topics from Google Sheet"}, {"step": "AI", "label": "CLAUDE", "description": "Generate post"}, {"step": "B", "label": "BUFFER", "description": "Publish to social media"}], "content_calendar_template": {"columns": ["Date", "Topic", "Platform", "Tone", "Key Message"], "example_rows": [["[Monday]", "[Industry tip]", "LinkedIn", "Expert", "[Your main point]"], ["[Tuesday]", "[Behind scenes]", "Instagram", "Casual", "[What to share]"], ["[Wednesday]", "[Client story]", "X/Twitter", "Bold", "[Success metric]"], ["[Thursday]", "[How-to]", "LinkedIn", "Helpful", "[Problem > Solution]"], ["[Friday]", "[Weekend take]", "X/Twitter", "Casual", "[Your perspective]"]]}, "ai_prompt": {"platform": "Claude / Gemini", "prompt": "SYSTEM: You are a social media content creator for [YOUR BUSINESS NAME]. Your brand voice is [PROFESSIONAL/CASUAL/BOLD]. You write for [YOUR INDUSTRY]. RULES: Keep posts under [280 chars for X / 1300 for LinkedIn]. Use 3-5 relevant hashtags. Include a hook in the first line. End with a question or call-to-action. Never use 'In today's fast-paced world'. Reference real audience problems: [PAIN POINTS]. TODAY'S POST — Topic: {{topic}} | Platform: {{platform}} | Tone: {{tone}} | Key message: {{key_message}}. Write the post now."}, "zapier_setup": [{"step": "T", "node": "Schedule by Zapier", "detail": "Every day at 7:00 AM"}, {"step": "S", "node": "Google Sheets", "detail": "Get row from Content Calendar (Status=Pending)"}, {"step": "AI", "node": "Claude AI", "detail": "Generate post using topic, platform, tone"}, {"step": "A", "node": "Buffer", "detail": "Publish post to social media"}], "n8n_setup": [{"step": "T", "node": "Schedule Trigger", "detail": "Daily at your chosen time"}, {"step": "S", "node": "Google Sheets", "detail": "Read row: Status=Pending, 1 Limit"}, {"step": "AI", "node": "Claude AI", "detail": "claude-sonnet model with prompt template"}, {"step": "A", "node": "HTTP Request", "detail": "POST to Buffer/LinkedIn API"}], "customization": {"business_name": "[___]", "platform": "[LinkedIn / X / Instagram]", "brand_voice": "[Professional / Casual / Bold / Friendly]", "post_frequency": "[Daily / 3x per week / Weekly]", "content_themes": ["[___]", "[___]", "[___]"]}, "content": "This workflow eliminates the daily scramble for social media content by automatically generating and publishing branded posts every morning while you sleep. Here is how it works: you fill a Google Sheet content calendar with topics, platforms, and tone for each day of the week. Every morning at 7AM, your automation reads the next pending row, sends the topic details to Claude via the Anthropic API, and Claude generates a platform-optimized post using your brand voice, audience pain points, and content rules. The finished post routes to Buffer or your social scheduling tool and publishes automatically. In Zapier, this is a 4-step Zap: Schedule trigger, Google Sheets read, Claude AI generate, Buffer publish. In n8n, the same flow uses Schedule Trigger, Google Sheets node, Anthropic Claude node (claude-sonnet model), and an HTTP Request to your publishing API. The included content calendar template and AI prompt are ready to customize — just fill in your business name, brand voice, and content themes. Saves 5-7 hours per week of content creation time."}, {"title": "Workflow 04: Email Sequence Generator", "type": "workflow", "tagline": "AUTOMATED NURTURE SEQUENCES THAT SOUND LIKE YOU WROTE EACH ONE", "metrics": {"time_saved": "3-5 hrs", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Per lead"}, "flow": [{"step": "L", "label": "NEW LEAD", "description": "CRM trigger"}, {"step": "E", "label": "ENRICH", "description": "Pull details"}, {"step": "AI", "label": "CLAUDE", "description": "Write 5 emails"}, {"step": "R", "label": "REVIEW", "description": "Your approval"}, {"step": "S", "label": "SEND", "description": "Auto-queue"}], "why_this_beats_generic_templates": "Every email tool has templates. But they're the same for everyone. This workflow generates sequences personalized to each lead — their industry, their pain points, their entry point — using YOUR brand voice.", "ai_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are an email marketing specialist for [YOUR BUSINESS NAME]. BRAND VOICE: [YOUR EMAIL TONE]. PRODUCT: [WHAT YOU SELL] at [PRICE]. UNIQUE VALUE: [WHY CHOOSE YOU]. LEAD: Name: {{lead_name}} | Company: {{company}} | Source: {{lead_source}} | Industry: {{industry}}. Generate a 5-email nurture sequence: EMAIL 1 (Immediate): Welcome + value. EMAIL 2 (Day 3): Educational, no selling. EMAIL 3 (Day 7): Case study for their industry. EMAIL 4 (Day 10): Soft offer with specific benefit. EMAIL 5 (Day 14): Direct offer with urgency. For each: Subject line (<50 chars), Preview text (<90 chars), Body (<200 words), CTA, Send timing."}, "zapier_setup": [{"step": "T", "node": "HubSpot / Mailchimp", "detail": "New Contact or New detected Subscriber"}, {"step": "AI", "node": "Claude AI", "detail": "Generate 5-email nurture sequence"}, {"step": "S", "node": "Google Sheets", "detail": "Create row per email with send dates"}, {"step": "@", "node": "Gmail / Mailchimp", "detail": "Send approved emails on schedule"}], "n8n_setup": [{"step": "T", "node": "Webhook / CRM", "detail": "Fires when new lead enters system"}, {"step": "AI", "node": "Claude AI", "detail": "Paste prompt template, map lead data"}, {"step": "S", "node": "Google Sheets", "detail": "Write all 5 emails as separate rows"}, {"step": "@", "node": "Gmail", "detail": "Send on scheduled dates"}], "pro_tip": "Start with manual approval for the first 10 sequences. Once you trust the output, let it run fully automated.", "customization": {"email_tool": "[Mailchimp / HubSpot / Gmail]", "crm": "[HubSpot / Sheets]", "approval_mode": "[Manual / Auto]"}, "content": "Every email marketing tool has templates, but they are the same generic sequences for everyone. This workflow generates fully personalized 5-email nurture sequences for each individual lead based on their industry, pain points, and how they found you — all in your brand voice. When a new contact enters your CRM or email tool, the automation fires: it pulls the lead details, sends them to Claude with your product info and brand guidelines, and Claude writes 5 timed emails (welcome, educational, case study, soft offer, direct offer with urgency). The emails land in a Google Sheet for review, then queue automatically in Gmail or Mailchimp on the scheduled send dates. In Zapier: HubSpot/Mailchimp trigger, Claude AI step, Sheets storage, Gmail/Mailchimp send. In n8n: Webhook or CRM trigger, Claude AI node with mapped lead data, Sheets write, Gmail scheduled send. Start with manual approval for your first 10 sequences to build confidence in the output quality, then switch to fully automated mode."}, {"title": "Workflow 05: Content Repurposing Engine", "type": "workflow", "tagline": "ONE PIECE OF CONTENT → 10+ PIECES ACROSS EVERY PLATFORM", "metrics": {"time_saved": "8-10 hrs", "difficulty": "Intermediate", "tools_needed": 4, "frequency": "Per post"}, "flow": [{"step": "P", "label": "PUBLISH", "description": "Blog/Video"}, {"step": "E", "label": "EXTRACT", "description": "Get full text"}, {"step": "AI", "label": "CLAUDE", "description": "Repurpose"}, {"step": "G", "label": "SHEETS", "description": "Store all pieces"}, {"step": "Q", "label": "QUEUE", "description": "Schedule"}], "repurposing_matrix": [{"output": "5 LinkedIn posts", "description": "Different angles from the original"}, {"output": "5 X/Twitter posts", "description": "Punchy, under 280 characters"}, {"output": "1 Email newsletter", "description": "Hook + key insight + link"}, {"output": "3 Instagram captions", "description": "Visual-friendly with CTAs"}, {"output": "5 Quote graphics", "description": "Quotable lines for Canva"}], "stats": {"original_pieces": 1, "output_pieces": "19+", "weeks_covered": "4+"}, "ai_prompt": {"platform": "Gemini", "prompt": "SYSTEM: You are a content repurposing specialist. You take one piece of long-form content and create multiple shorter pieces. BRAND VOICE: [YOUR VOICE]. BUSINESS: [YOUR NAME]. ORIGINAL CONTENT: {{full_text}}. Create: 1) 5 LinkedIn posts (100-200 words, end with question, 3-5 hashtags). 2) 5 X/Twitter posts (under 280 chars, punchy). 3) 1 Email newsletter intro (100 words, hook + insight). 4) 5 Quote graphics (most quotable lines). Format each with platform headers."}, "zapier_setup": [{"step": 1, "action": "Trigger: RSS / Webhook", "detail": "New blog post published or Google Doc updated"}, {"step": 2, "action": "Extract content", "detail": "Formatter by Zapier > Extract text from URL or doc"}, {"step": 3, "action": "Claude: Send Message", "detail": "Paste repurposing prompt > Map full text"}, {"step": 4, "action": "Google Sheets: Create Rows", "detail": "One row per piece with platform + date columns"}], "customization": {"source_content_type": "[Blog / Video / Podcast / Newsletter]", "publishing_frequency": "[Weekly / Bi-weekly / Monthly]", "target_platforms": "[LinkedIn / X / Instagram / Email / YouTube]", "repurposing_schedule": "Spread over [___] weeks", "content_themes": "[___]"}, "content": "One blog post or video can fuel four weeks of content across every platform — if you have the right system. This workflow takes any long-form content you publish and automatically transforms it into 19+ pieces: 5 LinkedIn posts (different angles, 100-200 words each), 5 X/Twitter posts (punchy, under 280 characters), 1 email newsletter intro, 3 Instagram captions with CTAs, and 5 quotable lines ready for Canva graphics. The automation triggers when you publish a new blog post or update a Google Doc. It extracts the full text, sends it to Gemini with your brand voice and repurposing matrix, and Gemini creates all variations in one API call. Every piece lands in a Google Sheet organized by platform and scheduled date. In Zapier: RSS or Webhook trigger, Formatter to extract text, Claude Send Message with repurposing prompt, Sheets row creation. In n8n: the same flow with native nodes. You publish once, the engine distributes for weeks."}, {"title": "Workflow 06: Lead Magnet Follow-Up", "type": "workflow", "tagline": "TURN EVERY FREE DOWNLOAD INTO A SALES CONVERSATION", "metrics": {"time_saved": "2-4 hrs", "difficulty": "Beginner", "tools_needed": 3, "frequency": "Per download"}, "flow": [{"step": "D", "label": "DOWNLOAD", "description": "Visitor downloads guide"}, {"step": "T", "label": "DETECT", "description": "New subscriber triggered"}, {"step": "C", "label": "CLASSIFY", "description": "AI reads which lead magnet"}, {"step": "AI", "label": "GENERATE", "description": "4-email sequence created"}, {"step": "S", "label": "SEND", "description": "Emails sent automatically"}], "performance_stats": {"generic_open_rate": "15%", "personalized_open_rate": "35-45%", "more_replies": "3x"}, "ai_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are a follow-up email specialist for [YOUR BUSINESS NAME]. LEAD MAGNET: {{lead_magnet_name}}. KEY TOPICS: {{key_topics}}. NEXT PAID PRODUCT: {{product_name}} at {{price}}. LEAD: {{name}}. Write 4 emails: EMAIL 1 (Immediate): Deliver download + bonus tip not in the guide. EMAIL 2 (Day 2): Ask if they tried [specific technique]. Quick-win example. No selling. EMAIL 3 (Day 5): Success story. Bridge to paid product. Soft mention only. EMAIL 4 (Day 7): Direct offer for paid product. Specific benefit. Time-limited bonus. Clear CTA."}, "zapier_setup": [{"step": 1, "action": "Trigger: ConvertKit/Mailchimp", "detail": "New Subscriber with tag = lead magnet name"}, {"step": 2, "action": "Claude: Send Message", "detail": "Follow-up prompt > Map subscriber + lead magnet details"}, {"step": 3, "action": "Google Sheets: Create Rows", "detail": "Store all 4 emails with send dates"}, {"step": 4, "action": "Email tool: Create Sequence", "detail": "Queue emails on the generated schedule"}], "customization": {"lead_magnet_name": "[___]", "key_topics_in_guide": ["[___]", "[___]", "[___]"], "next_paid_product": "[___] at $[___]", "email_tool": "[ConvertKit / Mailchimp / HubSpot]", "from_name": "[___]", "reply_to_email": "[___]"}, "content": "Generic follow-up emails after a free download get a 15% open rate. Personalized sequences tailored to the specific lead magnet someone downloaded get 35-45% opens and 3x more replies. This workflow bridges that gap automatically. When someone downloads your free guide or resource, the automation detects which lead magnet they grabbed, sends that context to Claude along with your business profile and next paid product details, and Claude generates a 4-email sequence: immediate delivery with a bonus tip not in the guide, a day-2 check-in asking if they tried a specific technique, a day-5 success story that bridges to your paid offer, and a day-7 direct offer with time-limited urgency. In Zapier: ConvertKit or Mailchimp new subscriber trigger with lead magnet tag, Claude AI generation, Sheets storage, email tool queue. Each sequence is unique to the lead magnet topic and the subscriber, not a copy-paste template everyone receives."}, {"title": "Workflow 07: Competitor Watch & Alert", "type": "workflow", "tagline": "KNOW WHAT YOUR COMPETITORS DO — BEFORE YOUR CUSTOMERS TELL YOU", "metrics": {"time_saved": "3-4 hrs", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Daily"}, "flow": [{"step": "S", "label": "SCHEDULE", "description": "Daily 8AM"}, {"step": "W", "label": "SCAN", "description": "Check competitor sources"}, {"step": "AI", "label": "CLAUDE", "description": "Analyze changes"}, {"step": "F", "label": "FILTER", "description": "Significant only?"}, {"step": "A", "label": "ALERT", "description": "Notify you"}], "what_ai_monitors": [{"category": "New announcements", "detail": "Blog posts, press releases, product launches"}, {"category": "Pricing changes", "detail": "Plan updates, discounts, new tiers"}, {"category": "Marketing campaigns", "detail": "Social media pushes, ad campaigns, promotions"}, {"category": "Customer reviews", "detail": "Google, Trustpilot, G2 — opportunities for you"}, {"category": "Content strategy", "detail": "Topics they're publishing — topics to respond to"}], "ai_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are a competitive intelligence analyst for [YOUR BUSINESS] in [YOUR INDUSTRY]. MY COMPETITORS: 1. [COMPETITOR 1 — name + website] 2. [COMPETITOR 2] 3. [COMPETITOR 3]. WHAT I CARE ABOUT: Pricing changes, new launches, marketing campaigns, negative reviews (opportunities for me), content topics. TODAY'S DATA: {{scraped_content}}. Analyze: 1) ALERT LEVEL: Red Urgent / Yellow Notable / Green Routine. 2) WHAT CHANGED. 3) WHY IT MATTERS. 4) RECOMMENDED ACTION. 5) OPPORTUNITY to exploit. If nothing significant: respond 'NO SIGNIFICANT CHANGES TODAY.'"}, "setup_steps": [{"step": 1, "action": "Trigger: Daily schedule", "detail": "RSS for competitor blogs + Google Alerts for brand mentions"}, {"step": 2, "action": "HTTP Request: Fetch data", "detail": "Pull latest from competitor websites and review sites"}, {"step": 3, "action": "Claude: Analyze", "detail": "Send competitor data through analysis prompt"}, {"step": 4, "action": "Filter: Significant only", "detail": "IF response != 'NO SIGNIFICANT CHANGES' then continue"}, {"step": 5, "action": "Slack/Email: Alert", "detail": "Send summary to your preferred notification channel"}], "customization": {"competitor_1": {"name": "[Name]", "website": "[URL]", "social": "[LinkedIn / X / Instagram URLs]"}, "competitor_2": {"name": "[Name]", "website": "[URL]", "social": "[LinkedIn / X / Instagram URLs]"}, "competitor_3": {"name": "[Name]", "website": "[URL]", "social": "[LinkedIn / X / Instagram URLs]"}, "alert_delivery": "[Slack / Email / Both]"}, "content": "By the time your customers tell you a competitor dropped their prices or launched a new product, you have already lost the first-mover advantage. This workflow monitors your top 3 competitors daily and alerts you only when something significant changes. Every morning at 8AM, the automation pulls data from competitor blog RSS feeds, Google Alerts for brand mentions, and review sites. Claude analyzes the aggregated data as a competitive intelligence analyst, rating each finding as Red (urgent), Yellow (notable), or Green (routine). It identifies what changed, explains why it matters to your business, recommends a specific action, and flags opportunities you can exploit. If nothing significant happened, it responds with a simple all-clear and you are not bothered. In Zapier or n8n: Schedule trigger, HTTP requests to data sources, Claude analysis with your competitor prompt, Filter node that only continues on significant changes, then Slack or email alert delivery. You stay informed without spending 3-4 hours per week manually checking competitor websites."}, {"title": "Workflow 08: Smart Inquiry Auto-Responder", "type": "workflow", "tagline": "RESPOND TO EVERY CUSTOMER INQUIRY IN UNDER 60 SECONDS — 24/7", "metrics": {"time_saved": "5-8 hrs", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Instant"}, "stats": {"avg_response_time_before": "42 hrs", "with_workflow": "<60 sec", "customers_who_leave_if_slow": "78%"}, "flow": [{"step": "I", "label": "INQUIRY", "description": "New email/form"}, {"step": "C", "label": "CLASSIFY", "description": "Sales/Support/General/Spam"}, {"step": "AI", "label": "GENERATE", "description": "Write response"}, {"step": "R", "label": "ROUTE", "description": "CRM + queue"}, {"step": "S", "label": "SEND", "description": "Auto-reply"}], "classifier_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are a customer inquiry classifier for [YOUR BUSINESS]. Read the incoming message and classify: SALES (pricing, demos, quotes), SUPPORT (existing customer issues), GENERAL (partnerships, media, jobs), SPAM (irrelevant). Also extract: URGENCY (High/Medium/Low), CUSTOMER_NAME, KEY_QUESTION, SUMMARY. INCOMING: {{message_body}} FROM: {{sender_email}} SUBJECT: {{subject}}. Respond in JSON format only."}, "response_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are a customer service rep for [YOUR BUSINESS]. WHAT WE SELL: [PRODUCTS/SERVICES]. PRICING: [STRUCTURE]. HOURS: [BUSINESS HOURS]. BOOKING: [LINK]. INQUIRY: Category: {{category}} | Name: {{customer_name}} | Question: {{key_question}} | Original: {{original_message}}. Write a professional, warm response that: 1) Addresses by name. 2) Acknowledges their question. 3) Provides a helpful answer. 4) Includes a clear next step. 5) Feels personal, NOT like a bot. Under 150 words. Sign off as [YOUR NAME]."}, "zapier_setup": [{"step": "T", "node": "Gmail", "detail": "New inquiry arrives"}, {"step": "AI", "node": "Claude AI", "detail": "Classify: Sales / Support / General / Spam"}, {"step": "F", "node": "Filter", "detail": "Only continue if NOT Spam"}, {"step": "AI", "node": "Claude AI", "detail": "Generate personalized response"}, {"step": "@", "node": "Gmail", "detail": "Send reply to customer"}, {"step": "A", "node": "HubSpot", "detail": "Create/update contact record"}], "customization": {"business_name": "[___]", "inquiry_sources": "[Email / Website form / Social DMs]", "response_mode": "[Auto-send / Approve first]", "booking_link": "[___]", "response_sign_off": "[Your name / Team name]"}, "content": "78% of customers go with the business that responds first. Yet the average small business takes 42 hours to reply to an inquiry. This workflow gets your response time under 60 seconds, 24 hours a day, 7 days a week. When a new email or form submission arrives, the automation sends it through a two-stage AI pipeline. Stage one: Claude classifies the inquiry as Sales, Support, General, or Spam, extracts the customer name, key question, and urgency level, and returns structured JSON. Stage two: if it is not spam, Claude generates a personalized response using your products, pricing, business hours, and booking link — addressing them by name, acknowledging their specific question, providing a helpful answer, and including a clear next step. The response sends automatically while the contact is created or updated in your CRM. In Zapier: Gmail trigger, Claude classify step, Filter (not spam), Claude response step, Gmail send, HubSpot update. In n8n: the same flow with Webhook trigger and native nodes. Every inquiry gets a human-quality response before your competitor even opens their inbox."}, {"title": "Workflow 09: Client Onboarding Automation", "type": "workflow", "tagline": "PROFESSIONAL ONBOARDING IN MINUTES — NOT DAYS", "metrics": {"time_saved": "2-3 hrs", "difficulty": "Intermediate", "tools_needed": 4, "frequency": "Per client"}, "stats": {"manual_onboarding": "2-3 hrs", "automated": "<5 min", "consistency": "100%"}, "flow": [{"step": "P", "label": "PAYMENT", "description": "Stripe/PayPal"}, {"step": "AI", "label": "CLAUDE", "description": "Generate welcome package"}, {"step": "D", "label": "DOCS", "description": "Create onboarding guide"}, {"step": "E", "label": "EMAIL", "description": "Send welcome email"}, {"step": "C", "label": "CRM", "description": "Update status"}], "ai_prompt": {"platform": "Claude", "prompt": "SYSTEM: You are an onboarding specialist for [YOUR BUSINESS]. Create personalized onboarding docs. SERVICE: {{service_name}}. CLIENT: {{client_name}} at {{company_name}} in {{industry}}. START: {{start_date}}. Generate: 1) WELCOME: Personalized message + what to expect in first 7 days + key contacts. 2) CHECKLIST: Step-by-step for them + what we need from them + deadlines. 3) TIMELINE: Week 1-4 milestones. 4) FAQ: 5 common questions with answers. 5) NEXT STEPS: Book kickoff [LINK], complete intake [LINK], join channel [LINK]."}, "zapier_setup": [{"step": "T", "node": "Stripe: New Payment OR CRM Deal Won / PayPal New Sale"}, {"step": "AI", "node": "Claude AI", "detail": "Generate onboarding doc from template"}, {"step": "A", "node": "Google Docs + Gmail", "detail": "Create doc + send welcome email with links"}, {"step": "A", "node": "HubSpot", "detail": "Update client status to Onboarding"}], "n8n_setup": [{"step": "T", "node": "Webhook Trigger", "detail": "Connected to Stripe or CRM"}, {"step": "AI", "node": "Claude AI", "detail": "Generate onboarding document"}, {"step": "A", "node": "Google Docs + Gmail", "detail": "Create doc + send welcome email"}, {"step": "A", "node": "HTTP Request", "detail": "Update CRM status via API"}], "customization": {"service_product_name": "[___]", "payment_processor": "[Stripe / PayPal]", "intake_form_link": "[___]", "booking_calendar_link": "[___]", "communication_channel": "[Slack / Email / WhatsApp]"}, "content": "Manual client onboarding takes 2-3 hours per new client and the quality varies every time depending on how busy you are that day. This workflow delivers a consistent, professional onboarding experience in under 5 minutes, triggered automatically when payment is received. When Stripe or PayPal processes a new payment, the automation sends the client details and service information to Claude, which generates a complete personalized welcome package: a welcome message with what to expect in the first 7 days, a step-by-step checklist for both sides, a week-by-week milestone timeline, 5 pre-answered FAQs specific to their service, and clear next steps with links to book a kickoff call, complete an intake form, and join your communication channel. The package is created as a Google Doc, the welcome email sends automatically with all links, and your CRM status updates to Onboarding. In Zapier: Stripe new payment trigger, Claude AI generation, Google Docs create, Gmail send, HubSpot update. In n8n: Webhook connected to Stripe, Claude node, Google Docs and Gmail nodes, HTTP request to CRM API. Every client gets the same premium first impression."}, {"title": "Workflow 10: Review & Testimonial Collector", "type": "workflow", "tagline": "AUTOMATICALLY COLLECT AND SHOWCASE YOUR BEST CLIENT FEEDBACK", "metrics": {"time_saved": "2-3 hrs", "difficulty": "Beginner", "tools_needed": 3, "frequency": "Per project"}, "flow": [{"step": "C", "label": "COMPLETE", "description": "Project done"}, {"step": "R", "label": "REQUEST", "description": "AI-crafted review ask"}, {"step": "F", "label": "COLLECT", "description": "Response arrives"}, {"step": "AI", "label": "FORMAT", "description": "3 versions created"}, {"step": "S", "label": "STORE", "description": "Added to library"}], "request_email_prompt": {"platform": "Claude", "prompt": "SYSTEM: You write review request emails for [YOUR BUSINESS] that feel personal and genuine — never pushy. CLIENT: {{client_name}}. SERVICE: {{service_name}}. DURATION: {{duration}}. RESULTS: {{results_delivered}}. Write a short, warm email (under 100 words) asking for a review. Reference specific results you delivered. Make it easy — offer 3 questions: 1) What was your situation before working with us? 2) What specific results did you see? 3) Would you recommend us? Why?"}, "testimonial_formatter_prompt": {"platform": "Gemini", "prompt": "Take this raw customer feedback and create 3 versions: RAW: {{raw_feedback}}. VERSION 1 — WEBSITE (2-3 sentences, impactful, with attribution). VERSION 2 — SOCIAL MEDIA (1 sentence, punchy, shareable). VERSION 3 — CASE STUDY INTRO (3-4 sentences, story format: problem > solution > result)."}, "setup_steps": [{"step": 1, "action": "Trigger: CRM status change", "detail": "Project marked 'Complete' or X days after purchase"}, {"step": 2, "action": "Claude: Generate request email", "detail": "Personalized to their project and results"}, {"step": 3, "action": "Email: Send request", "detail": "Gmail or email tool sends the review request"}, {"step": 4, "action": "Trigger 2: Form response", "detail": "When they reply or submit the review form"}, {"step": 5, "action": "Gemini: Format testimonial", "detail": "Create 3 versions (website, social, case study)"}, {"step": 6, "action": "Google Sheets: Store", "detail": "Add to your Testimonial Library with all versions"}], "customization": {"ask_for_review_days_after_completion": "[___ days]", "review_platform": "[Google / Trustpilot / G2 / Website]", "request_sender": "[Your name / Team name]", "testimonial_storage": "[Google Sheet URL]", "follow_up_if_no_response": "[Yes/No — after ___ days]"}, "content": "Social proof sells, but most businesses collect testimonials randomly and inconsistently. This workflow automates the entire cycle: requesting reviews at the perfect moment, collecting responses, and formatting them into ready-to-use marketing assets. When a project is marked complete in your CRM (or a set number of days after purchase), Claude generates a personalized review request email that references specific results you delivered for that client — making it feel genuine, not like a mass blast. When the client responds, Gemini takes their raw feedback and creates three formatted versions: a 2-3 sentence website testimonial with attribution, a punchy one-sentence social media quote, and a 3-4 sentence case study introduction in problem-solution-result format. All three versions land in your Testimonial Library spreadsheet, organized and ready to use. In Zapier or n8n: CRM status change trigger, Claude review request, email send, then a second trigger on form response, Gemini formatting, Sheets storage. You build a growing library of proof without ever manually asking for a review."}, {"title": "Workflow 11: Follow-Up & Re-Engagement", "type": "workflow", "tagline": "NEVER LOSE A CUSTOMER TO SILENCE AGAIN", "metrics": {"time_saved": "3-5 hrs", "difficulty": "Intermediate", "tools_needed": 3, "frequency": "Weekly"}, "stats": {"follow_ups_needed_for_sale": "5+", "give_up_after_1": "44%", "sales_close_after_5th_follow_up": "80%"}, "three_workflows": [{"label": "A: LEAD FOLLOW-UP", "description": "Scan CRM weekly > Find leads inactive 7+ days > AI check-in > Send"}, {"label": "B: POST-PURCHASE", "description": "30/60/90 days after purchase > AI value-check email > Send"}, {"label": "C: WIN-BACK", "description": "Customers inactive 90+ days > AI re-engagement offer > Send"}], "lead_follow_up_prompt": {"platform": "Claude", "prompt": "SYSTEM: You write follow-up emails for [YOUR BUSINESS]. LEAD: {{lead_name}} at {{company}}. LAST CONTACT: {{last_date}} — {{last_type}}. DAYS INACTIVE: {{days}}. Write a brief follow-up (under 100 words): 1) Reference last interaction. 2) Offer something valuable. 3) Ask one simple question. 4) Soft CTA. DO NOT use 'just checking in' or 'touching base'."}, "win_back_prompt": {"platform": "Gemini", "prompt": "SYSTEM: You write win-back emails for [YOUR BUSINESS]. CUSTOMER: {{name}}. LAST PURCHASE: {{date}} — {{product}}. DAYS SINCE: {{days}}. Write a re-engagement email (under 120 words): 1) Acknowledge the gap without guilt. 2) Share something new. 3) Offer exclusive 'welcome back' incentive. 4) Gentle urgency. Tone: Warm, not desperate."}, "zapier_setup": [{"step": "T", "node": "Weekly Schedule", "detail": "Scan CRM for inactive leads/customers"}, {"step": "A", "node": "CRM: Search Contacts", "detail": "Filter by last activity date > threshold"}, {"step": "AI", "node": "Claude / Gemini", "detail": "Generate personalized email follow-up"}, {"step": "@", "node": "Gmail / Mailchimp", "detail": "Send the follow-up automatically"}, {"step": "A", "node": "CRM: Log Activity", "detail": "Record that follow-up was sent"}], "customization": {"lead_follow_up_every_days": "[___] days", "win_back_days": "[___] days", "incentive": "[Discount / Free resource / Exclusive]", "crm": "[HubSpot / Salesforce / Google Sheets]", "email_tool": "[Gmail / Mailchimp / ConvertKit]"}, "content": "44% of salespeople give up after one follow-up, yet 80% of sales close after the 5th touch. This workflow runs three parallel re-engagement engines that ensure no lead or customer falls through the cracks. Engine A (Lead Follow-Up) scans your CRM weekly for leads inactive 7+ days and has Claude write a personalized check-in that references their last interaction and offers something valuable — never a generic just checking in. Engine B (Post-Purchase) sends value-check emails at 30, 60, and 90 days after purchase to keep customers engaged and reduce churn. Engine C (Win-Back) targets customers inactive 90+ days with a Gemini-crafted re-engagement email that acknowledges the gap without guilt, shares something new, and offers a welcome-back incentive with gentle urgency. In Zapier: Weekly schedule trigger, CRM search for inactive contacts filtered by threshold, Claude or Gemini generation based on segment, Gmail or Mailchimp auto-send, CRM activity log. In n8n: the same flow with Cron trigger and native CRM, AI, and email nodes. Your pipeline stays warm automatically while you focus on delivering great work."}, {"title": "Chapter 12: Automation Dashboard", "type": "templates", "content": "Once you have multiple workflows running, you need a single view to track what is working, what is breaking, and where to optimize. This dashboard template gives you that view in a Google Sheet you update weekly. Each row tracks one workflow: name, platform (Zapier or n8n), status, runs per week, and estimated time saved. The weekly summary prompt feeds your dashboard data to Gemini, which generates a report covering total time saved, your most active workflow, any errors needing attention, optimization suggestions, and an ROI estimate calculated as time saved multiplied by your hourly rate. The monthly optimization checklist walks through each active workflow: is AI output quality still accurate, are there recurring errors in the logs, are API costs within budget, does the prompt need updating for changed business info? The cost tracker tallies your Anthropic API, Google AI Studio, Zapier, and n8n spend against the hours saved — so you always know your automation ROI in real dollars. This is how you run automations like a business operation, not a set-and-forget experiment.", "dashboard_template": {"columns": ["Workflow", "Platform", "Status", "Runs/Wk", "Time Saved"], "example_rows": [["Social Post Gen", "Zapier", "Active", "7", "5 hrs"], ["Email Sequences", "n8n", "Active", "12", "4 hrs"], ["Content Repurpose", "Zapier", "Active", "3", "8 hrs"], ["Lead Magnet Follow", "Zapier", "Active", "15", "3 hrs"], ["Competitor Watch", "n8n", "Active", "7", "3 hrs"], ["Inquiry Responder", "Zapier", "Active", "28", "7 hrs"], ["Client Onboarding", "n8n", "Active", "4", "8 hrs"], ["Review Collector", "Zapier", "Active", "3", "2 hrs"], ["Customer Follow-Up", "n8n", "Active", "8", "4 hrs"]]}, "weekly_summary_prompt": {"platform": "Gemini", "prompt": "Here is my automation dashboard data for this week: {{dashboard_data}}. Generate a weekly report: 1) TOTAL TIME SAVED. 2) MOST ACTIVE workflow. 3) ANY ERRORS needing attention. 4) OPTIMIZATION SUGGESTIONS. 5) ROI ESTIMATE: Time saved x $[YOUR_HOURLY_RATE] = value generated."}, "monthly_optimization_checklist": {"for_each_active_workflow": ["Review AI output quality — still accurate?", "Check error logs — any recurring failures?", "Review API costs — within budget?", "Test with edge cases — handling unusual inputs?", "Update prompts — business info changed?"], "scaling_questions": ["Which workflow saves the most time? Can I expand it?", "Which has the most errors? Fix or replace?", "What manual task am I still doing? New workflow needed?", "Am I under API budget? Add more automations", "Am I over API budget? Switch models or reduce frequency"]}, "cost_tracker": {"anthropic_api": "$[___] / month ([___] runs)", "google_ai_studio": "$[___] / month ([___] runs)", "zapier_plan": "$[___] / month", "n8n_plan": "$[___] / month", "total": "$[___] / month", "time_saved": "[___] hours / month", "value_at_hourly_rate": "$[___] / month"}}, {"title": "Chapter 13: Troubleshooting & Optimization", "type": "educational", "content": "Automations break. AI outputs drift. API keys expire. This chapter is your field manual for diagnosing and fixing the seven most common automation issues — from generic AI output (fix: add your Business Profile to every prompt) to rate limit errors (fix: add 30-60 second delays between steps in your Zapier Zap or n8n workflow). Beyond troubleshooting, five optimization strategies help you cut costs and improve quality: use cheaper models like claude-haiku or gemini-flash for simple classification tasks while reserving expensive models for complex generation, batch multiple items into single API calls, cache repeated responses, pre-filter data so AI only processes what matters, and write more specific prompts that produce better output with fewer retries. The emergency checklist gives you step-by-step protocols for three crisis scenarios: automation sending wrong output (pause, check last 5 outputs, fix prompt, test, resume), automation stopped completely (check API key, billing, platform status, re-authenticate), and output quality declining (grade last 10 outputs, add context and examples, upgrade model if needed).", "common_issues": [{"problem": "AI output too generic", "fix": "Add your Business Profile to every prompt"}, {"problem": "Automation stopped", "fix": "Check API key + billing on provider dashboard"}, {"problem": "Wrong tone in emails", "fix": "Add 3 example emails in YOUR voice to the prompt"}, {"problem": "Too many errors", "fix": "Add a 'clean data' step before AI processes"}, {"problem": "API rate limits hit", "fix": "Add 30-60 second delays between steps"}, {"problem": "AI hallucinating facts", "fix": "Always feed real data, never ask AI to guess"}, {"problem": "Task limit reached", "fix": "Consolidate workflows or upgrade plan"}], "optimization_strategies": [{"number": 1, "name": "Model Selection", "description": "Use cheaper models (claude-haiku, gemini-flash) for simple tasks; expensive for complex."}, {"number": 2, "name": "Batching", "description": "Process multiple items in one AI call instead of one at a time."}, {"number": 3, "name": "Caching", "description": "Store repeated AI responses to avoid redundant API calls."}, {"number": 4, "name": "Pre-Filtering", "description": "Add conditional logic to only send relevant data to AI."}, {"number": 5, "name": "Prompt Engineering", "description": "More specific prompts = better output = fewer retries = lower cost."}], "emergency_checklist": {"sending_wrong_output": ["PAUSE immediately", "Check last 5 outputs", "Fix prompt", "Test > Resume"], "stopped_working": ["Check API key/billing", "Check platform status", "Re-auth connections", "Fix > Resume"], "results_are_meh": ["Grade last 10 outputs", "Add more context", "Add example outputs", "Upgrade model"]}}, {"title": "Chapter 14: What's Next", "type": "educational", "content": "You have completed the full AI journey: from typing single prompts (Starter Kit) to building AI specialists (Skills Builder) to deploying complete business systems (Small Business) to putting it all on autopilot (Automation Mastery). Each level built on the previous one, and together they form an integrated AI operation that handles marketing, sales, customer service, operations, and reporting with minimal daily input from you. The Ultimate AI Bundle packages all four products at $147 (saving $15 versus buying separately) and includes all future updates as we add new workflows and refine existing ones. Whether you went through the products one at a time or jumped straight to automation, you now have the skills and systems to run a business where AI does the heavy lifting and you make the strategic decisions.", "complete_journey": [{"step": "01", "product": "AI Starter Kit", "price": "$19", "description": "Learned to talk to AI", "status": "DONE"}, {"step": "02", "product": "AI Skills Builder", "price": "$29", "description": "Built AI specialists", "status": "DONE"}, {"step": "03", "product": "AI for Small Business", "price": "$47", "description": "Deployed business systems", "status": "DONE"}, {"step": "04", "product": "AI Automation Mastery", "price": "$67", "description": "Put it all on autopilot", "status": "DONE"}]}, {"title": "Upsell / CTA", "type": "cta", "content": "You built the automations. Your AI writes, responds, follows up, onboards, monitors competitors, collects reviews, and re-engages customers — all without you touching a keyboard. The Ultimate AI Bundle at $147 gives you every product in the KH Academy lineup (Starter Kit, Skills Builder, Small Business Systems, and Automation Mastery) plus all future updates and new workflow additions. That is $15 less than buying each product separately, and it means every new workflow or system we release lands in your account automatically. If you started with just this guide, the bundle fills in the foundation layers. If you already own everything, you are set — keep optimizing, keep reviewing your dashboard, and keep climbing.", "items": [{"offer": "Ultimate AI Bundle", "price": "$147", "description": "All 4 products | Separately: $162 | Save $15. AI Starter Kit + AI Skills Builder + AI for Small Business + AI Automation Mastery.", "url": "https://www.kh-academy.com"}], "contact": "info@kh-academy.com"}]};

